function sketch(p) {
  let time = 0;
  let wings = [];
  let seaWaves = [];
  let architecturePoints = [];
  let netParticles = [];

  p.setup = function() {
    p.createCanvas(400, 600);

    // Initialize wing particles
    for(let i = 0; i < 20; i++) {
      wings.push({
        x: p.random(200, 380),
        y: p.random(50, 150),
        alpha: p.random(20, 60),
        drift: p.random(-0.5, 0.5)
      });
    }

    // Initialize sea waves
    for(let i = 0; i < 15; i++) {
      seaWaves.push({
        x: p.random(0, 400),
        y: p.random(350, 450),
        size: p.random(30, 80),
        angle: p.random(0, p.TWO_PI)
      });
    }

    // Initialize architecture points
    for(let i = 0; i < 100; i++) {
      architecturePoints.push({
        x: p.random(0, 200),
        y: p.random(200, 400),
        alpha: p.random(100, 255)
      });
    }

    // Initialize net particles
    for(let i = 0; i < 50; i++) {
      netParticles.push({
        x: p.random(0, 200),
        y: p.random(100, 500),
        connections: []
      });
    }
  };

  p.draw = function() {
    time += 0.01;

    // Background - Irish grey-green sky
    p.background(140, 150, 145);

    // Sea - geometric modernist waves
    p.fill(90, 110, 100, 180);
    p.noStroke();
    for(let wave of seaWaves) {
      p.push();
      p.translate(wave.x, wave.y + p.sin(time * 2 + wave.angle) * 5);
      p.rotate(wave.angle + time * 0.3);
      p.beginShape();
      p.vertex(0, 0);
      p.vertex(wave.size, -10);
      p.vertex(wave.size + 20, 0);
      p.vertex(wave.size, 10);
      p.endShape(p.CLOSE);
      p.pop();
    }

    // Architecture behind - church spire, university dome
    p.stroke(80, 85, 82);
    p.strokeWeight(3);
    p.noFill();

    // Church spire
    let spireHeight = 300 + p.sin(time) * 10;
    p.line(50, 500, 50, 500 - spireHeight);
    p.line(30, 500 - spireHeight + 50, 70, 500 - spireHeight + 50);
    p.triangle(50, 500 - spireHeight, 40, 500 - spireHeight + 30, 60, 500 - spireHeight + 30);

    // University dome
    p.arc(120, 400, 60, 60, p.PI, p.TWO_PI);
    p.rect(90, 400, 60, 80);

    // Abstract architecture points
    p.stroke(100, 105, 102, 150);
    p.strokeWeight(1);
    for(let point of architecturePoints) {
      let fade = p.map(point.x, 0, 200, 255, 50);
      p.stroke(100, 105, 102, fade);
      p.point(point.x, point.y + p.sin(time + point.x * 0.01) * 2);
    }

    // Nets in architecture - barely visible
    p.stroke(70, 75, 72, 80);
    p.strokeWeight(0.5);
    for(let i = 0; i < netParticles.length - 1; i++) {
      let particle = netParticles[i];
      let nextParticle = netParticles[i + 1];
      if(p.dist(particle.x, particle.y, nextParticle.x, nextParticle.y) < 50) {
        p.line(particle.x, particle.y, nextParticle.x, nextParticle.y);
      }
    }

    // Stephen Dedalus figure - angular, sharp
    p.push();
    p.translate(280, 400);

    // Body - black coat
    p.fill(30, 30, 35);
    p.noStroke();
    p.rect(-15, -50, 30, 80);

    // Head - profile
    p.fill(180, 160, 140);
    p.ellipse(-5, -70, 20, 25);

    // Hair
    p.fill(60, 40, 30);
    p.ellipse(-8, -80, 18, 15);

    // Book under arm
    p.fill(100, 80, 70);
    p.rect(8, -20, 15, 20);

    // Legs
    p.fill(20, 20, 25);
    p.rect(-8, 30, 8, 40);
    p.rect(0, 30, 8, 40);

    p.pop();

    // Wing suggestions in sky - faint, potential
    for(let wing of wings) {
      wing.x += wing.drift;
      wing.y += p.sin(time + wing.x * 0.01) * 0.5;

      if(wing.x > 400) wing.x = 200;
      if(wing.x < 200) wing.x = 380;

      p.stroke(200, 200, 210, wing.alpha + p.sin(time * 2) * 20);
      p.strokeWeight(2);
      p.noFill();

      // Wing shape suggestion
      p.beginShape();
      p.curveVertex(wing.x, wing.y);
      p.curveVertex(wing.x, wing.y);
      p.curveVertex(wing.x + 20, wing.y - 10);
      p.curveVertex(wing.x + 30, wing.y);
      p.curveVertex(wing.x + 20, wing.y + 10);
      p.curveVertex(wing.x, wing.y);
      p.curveVertex(wing.x, wing.y);
      p.endShape();
    }

    // Interactive element - mouse proximity affects wing visibility
    let mouseInfluence = p.map(p.dist(p.mouseX, p.mouseY, 300, 100), 0, 200, 100, 0);
    mouseInfluence = p.constrain(mouseInfluence, 0, 100);

    for(let wing of wings) {
      wing.alpha = p.lerp(wing.alpha, 30 + mouseInfluence, 0.05);
    }

    // Pier edge
    p.stroke(80, 85, 82);
    p.strokeWeight(4);
    p.line(250, 480, 350, 480);
    p.line(350, 480, 350, 500);
  };
}

