function sketch(p) {
  let towerAngle = 0;
  let keyFloat = 0;
  let seaOffset = 0;
  let mulligan, stephen;
  let crackedMirror = [];
  let milkWoman;
  let shavingFoam = [];

  p.setup = function() {
    p.createCanvas(400, 600);

    // Initialize cracked mirror segments
    for(let i = 0; i < 8; i++) {
      crackedMirror.push({
        x: 200 + p.random(-30, 30),
        y: 200 + p.random(-20, 20),
        rotation: p.random(p.TWO_PI),
        drift: p.random(-0.005, 0.005)
      });
    }

    // Initialize shaving foam particles
    for(let i = 0; i < 15; i++) {
      shavingFoam.push({
        x: 200 + p.random(-20, 20),
        y: 120 + p.random(-10, 10),
        size: p.random(3, 8),
        drift: p.random(-0.2, 0.2),
        bob: p.random(p.TWO_PI)
      });
    }
  };

  p.draw = function() {
    // Background - morning sky
    for(let i = 0; i < p.height; i++) {
      let inter = p.map(i, 0, p.height, 0, 1);
      let c = p.lerpColor(p.color(200, 210, 220), p.color(150, 160, 170), inter);
      p.stroke(c);
      p.line(0, i, p.width, i);
    }

    // Animate variables
    towerAngle += 0.003;
    keyFloat += 0.02;
    seaOffset += 0.01;

    // Irish Sea background
    p.noFill();
    for(let y = 400; y < 600; y += 8) {
      p.stroke(80 + p.sin(seaOffset + y * 0.01) * 20, 120 + p.sin(seaOffset + y * 0.02) * 15, 100);
      p.strokeWeight(2);
      p.line(0, y, p.width, y + p.sin(seaOffset * 2 + y * 0.1) * 3);
    }

    // Martello Tower - dominant stone structure
    p.fill(140, 140, 130);
    p.stroke(100, 100, 90);
    p.strokeWeight(3);

    // Tower body - cylindrical, fortress-like
    p.ellipse(200, 280, 180, 200);
    p.rect(110, 200, 180, 180);

    // Tower top platform
    p.fill(120, 120, 110);
    p.rect(100, 180, 200, 30);
    p.ellipse(200, 180, 200, 40);

    // Spiral stairs suggestion - angular lines
    p.stroke(80, 80, 70);
    p.strokeWeight(2);
    for(let i = 0; i < 6; i++) {
      let stairY = 220 + i * 25;
      let stairX = 160 + p.sin(i * 0.5 + towerAngle * 2) * 30;
      p.line(stairX, stairY, stairX + 40, stairY);
      p.line(stairX + 40, stairY, stairX + 45, stairY + 5);
    }

    // Buck Mulligan - theatrical figure at tower top
    p.fill(200, 180, 50); // Yellow dressing gown
    p.stroke(150, 130, 20);
    p.strokeWeight(2);

    // Mulligan's body - theatrical pose
    let mulliganX = 200 + p.sin(towerAngle) * 5;
    let mulliganY = 140;

    p.ellipse(mulliganX, mulliganY + 30, 25, 40); // body
    p.fill(220, 180, 140); // skin tone
    p.ellipse(mulliganX, mulliganY, 20, 25); // head

    // Shaving bowl held aloft - mock chalice
    p.fill(240, 240, 240);
    p.stroke(200, 200, 200);
    p.strokeWeight(2);
    let bowlY = mulliganY - 20 + p.sin(towerAngle * 3) * 3;
    p.ellipse(mulliganX - 5, bowlY, 18, 12);
    p.arc(mulliganX - 5, bowlY, 18, 12, 0, p.PI);

    // Shaving foam particles
    for(let foam of shavingFoam) {
      p.fill(255, 255, 255, 180);
      p.noStroke();
      foam.x += foam.drift;
      foam.y += p.sin(foam.bob + p.frameCount * 0.1) * 0.1;
      foam.bob += 0.05;

      if(foam.x < 180 || foam.x > 220) foam.drift *= -0.8;

      p.ellipse(foam.x, foam.y, foam.size, foam.size);
    }

    // Stephen Dedalus - haunted figure descending
    p.fill(20, 20, 20); // black clothing
    p.stroke(50, 50, 50);
    p.strokeWeight(2);

    let stephenX = 180 + p.sin(towerAngle * 0.7) * 2;
    let stephenY = 260;

    p.ellipse(stephenX, stephenY + 25, 20, 35); // body
    p.fill(180, 160, 120); // pale skin
    p.ellipse(stephenX, stephenY, 15, 20); // head - gaunt

    // Stephen's haunted expression
    p.fill(0);
    p.noStroke();
    p.ellipse(stephenX - 3, stephenY - 2, 2, 3); // eyes
    p.ellipse(stephenX + 3, stephenY - 2, 2, 3);

    // Cracked mirror segments - reflecting guilt/mother
    for(let mirror of crackedMirror) {
      p.push();
      p.translate(mirror.x, mirror.y);
      p.rotate(mirror.rotation);
      mirror.rotation += mirror.drift;

      p.fill(200, 200, 220, 150);
      p.stroke(180, 180, 200);
      p.strokeWeight(1);

      // Jagged mirror piece
      p.beginShape();
      p.vertex(-8, -5);
      p.vertex(12, -8);
      p.vertex(15, 10);
      p.vertex(-5, 12);
      p.vertex(-10, 3);
      p.endShape(p.CLOSE);

      // Ghostly mother's face suggestion in mirror
      if(p.sin(p.frameCount * 0.05 + mirror.x) > 0.5) {
        p.fill(255, 255, 255, 100);
        p.noStroke();
        p.ellipse(0, 0, 8, 10);
        p.fill(0, 0, 0, 80);
        p.ellipse(-2, -1, 1, 1);
        p.ellipse(2, -1, 1, 1);
      }

      p.pop();
    }

    // The key - prominent symbol of surrender
    p.push();
    p.translate(320, 350 + p.sin(keyFloat) * 5);
    p.rotate(p.sin(keyFloat * 0.5) * 0.1);

    p.fill(100, 80, 60); // iron key
    p.stroke(60, 40, 20);
    p.strokeWeight(2);

    // Key shaft
    p.rect(-20, -3, 40, 6, 3);
    // Key head
    p.ellipse(-18, 0, 12, 12);
    // Key teeth
    p.rect(18, -6, 8, 6);
    p.rect(18, 3, 6, 3);

    p.pop();

    // Milk woman at base - Ireland not recognizing herself
    p.fill(150, 130, 110); // weathered clothing
    p.stroke(100, 80, 60);
    p.strokeWeight(2);

    let womanX = 120;
    let womanY = 380 + p.sin(seaOffset * 2) * 2;

    p.ellipse(womanX, womanY + 15, 18, 25); // body
    p.fill(160, 140, 120); // aged skin
    p.ellipse(womanX, womanY, 12, 15); // head

    // Milk pail
    p.fill(180, 180, 180);
    p.rect(womanX + 8, womanY + 10, 8, 12);

    // Tower's psychological weight - subtle shadow effects
    p.fill(0, 0, 0, 30);
    p.noStroke();
    p.ellipse(200, 480, 200, 60);

    // Mouse interaction - increased agitation near figures
    let mouseDistance = p.dist(p.mouseX, p.mouseY, 200, 200);
    if(mouseDistance < 100) {
      towerAngle += 0.005;
      keyFloat += 0.01;

      // Intensify mirror reflections
      for(let mirror of crackedMirror) {
        mirror.drift += p.random(-0.002, 0.002);
      }
    }
  };
}

