function sketch(p) {
  let classroom = {};
  let dustParticles = [];
  let clockTime = 0;
  let catPos = 0;
  let streetNoise = [];

  p.setup = function() {
    p.createCanvas(400, 600);

    // Initialize dust particles
    for(let i = 0; i < 15; i++) {
      dustParticles.push({
        x: p.random(p.width),
        y: p.random(p.height),
        size: p.random(1, 3),
        speed: p.random(0.2, 0.8),
        opacity: p.random(30, 80)
      });
    }

    // Initialize street sounds visualization
    for(let i = 0; i < 8; i++) {
      streetNoise.push({
        x: 320 + p.random(-20, 20),
        y: 150 + p.random(-30, 30),
        life: p.random(60),
        maxLife: 60
      });
    }
  };

  p.draw = function() {
    clockTime += 0.02;
    catPos = p.sin(clockTime * 2) * 5;

    // Dark institutional background
    p.background(45, 35, 25);

    // Wood paneled walls
    p.fill(60, 45, 30);
    p.noStroke();
    for(let i = 0; i < 8; i++) {
      p.rect(0, i * 75, p.width, 70);
      p.fill(50, 38, 25);
      p.rect(0, i * 75 + 65, p.width, 5);
      p.fill(60, 45, 30);
    }

    // Window with bright outside light
    p.fill(200, 195, 180);
    p.rect(270, 80, 100, 120);
    p.fill(240, 235, 220);
    p.rect(275, 85, 90, 110);

    // Window frame
    p.stroke(80, 60, 40);
    p.strokeWeight(4);
    p.noFill();
    p.rect(270, 80, 100, 120);
    p.line(320, 80, 320, 200);
    p.line(270, 140, 370, 140);

    // Cat in window (truth in the street)
    p.noStroke();
    p.fill(40, 40, 45);
    p.ellipse(315 + catPos, 160, 25, 15);
    p.ellipse(312 + catPos, 155, 8, 8);
    p.ellipse(318 + catPos, 155, 8, 8);

    // Street noise/sound waves from window
    p.noFill();
    p.strokeWeight(1);
    for(let sound of streetNoise) {
      let alpha = p.map(sound.life, 0, sound.maxLife, 0, 150);
      p.stroke(255, 240, 200, alpha);
      p.circle(sound.x, sound.y, (sound.maxLife - sound.life) * 0.8);
      sound.life--;
      if(sound.life < 0) {
        sound.life = sound.maxLife;
        sound.x = 320 + p.random(-20, 20);
        sound.y = 150 + p.random(-30, 30);
      }
    }

    // Blackboard
    p.noStroke();
    p.fill(25, 35, 25);
    p.rect(30, 220, 180, 100);

    // Blackboard frame
    p.fill(70, 50, 35);
    p.rect(25, 215, 190, 110);
    p.fill(25, 35, 25);
    p.rect(30, 220, 180, 100);

    // Chalk writing (fading)
    let chalkOpacity = 150 + p.sin(clockTime * 3) * 30;
    p.fill(200, 195, 180, chalkOpacity);
    p.textSize(12);
    p.text("Pyrrhus:", 40, 240);
    p.text("Victory of", 40, 255);
    p.text("defeats...", 40, 270);
    p.textSize(8);
    p.text("What is history but a", 40, 290);
    p.text("nightmare from which", 40, 300);

    // Stephen teaching (disconnected)
    p.fill(85, 70, 55);
    p.ellipse(120, 180, 30, 40); // head
    p.fill(120, 100, 80);
    p.rect(105, 195, 30, 60); // body
    p.rect(100, 175, 8, 25); // left arm
    p.rect(132, 175, 8, 25); // right arm pointing at board
    p.rect(110, 250, 8, 30); // left leg
    p.rect(122, 250, 8, 30); // right leg

    // Stephen's disconnected expression
    p.fill(200, 180, 160);
    p.ellipse(120, 180, 25, 35);
    p.fill(60, 50, 40);
    p.ellipse(115, 175, 2, 2); // eyes looking away
    p.ellipse(125, 175, 2, 2);

    // Bored students at desks
    p.fill(70, 55, 40);
    // Desk 1
    p.rect(50, 350, 60, 40);
    p.fill(150, 130, 110);
    p.ellipse(80, 340, 20, 25); // student head
    p.fill(100, 85, 70);
    p.rect(70, 355, 20, 25); // body slouching

    // Desk 2
    p.fill(70, 55, 40);
    p.rect(130, 360, 60, 40);
    p.fill(160, 140, 120);
    p.ellipse(160, 350, 20, 25); // student head turned away
    p.fill(100, 85, 70);
    p.rect(150, 365, 20, 25);

    // Mr. Deasy counting coins (foreground, dominant)
    p.fill(80, 65, 50);
    p.rect(220, 420, 120, 80); // desk
    p.fill(180, 160, 140);
    p.ellipse(280, 380, 40, 50); // large head
    p.fill(90, 75, 60);
    p.rect(260, 400, 40, 70); // body

    // Deasy's satisfied/prejudiced expression
    p.fill(60, 50, 40);
    p.ellipse(275, 375, 3, 3); // eyes
    p.ellipse(285, 375, 3, 3);
    p.arc(280, 385, 8, 6, 0, p.PI); // smug smile

    // Coins on desk (animated)
    for(let i = 0; i < 6; i++) {
      let coinY = 430 + p.sin(clockTime + i) * 2;
      p.fill(200, 180, 100);
      p.ellipse(240 + i * 15, coinY, 12, 8);
      p.fill(220, 200, 120);
      p.ellipse(240 + i * 15, coinY - 1, 10, 6);
    }

    // Historical maps and charts on walls (oppressive past)
    p.stroke(80, 60, 40);
    p.strokeWeight(2);
    p.fill(160, 140, 120);
    p.rect(20, 50, 80, 60);
    p.rect(120, 40, 60, 50);

    // Map details
    p.strokeWeight(1);
    p.stroke(100, 80, 60);
    for(let i = 0; i < 5; i++) {
      p.line(25, 60 + i * 8, 95, 60 + i * 8);
      p.line(125, 50 + i * 6, 175, 50 + i * 6);
    }

    // Books stacked (weight of history)
    for(let i = 0; i < 4; i++) {
      p.fill(80 - i * 5, 60 - i * 5, 40 - i * 5);
      p.rect(15, 520 - i * 15, 100, 12);
    }

    // Dust particles floating (staleness)
    for(let dust of dustParticles) {
      p.fill(120, 110, 90, dust.opacity);
      p.noStroke();
      p.ellipse(dust.x, dust.y, dust.size);

      dust.y += dust.speed;
      dust.x += p.sin(clockTime + dust.y * 0.01) * 0.3;

      if(dust.y > p.height) {
        dust.y = -10;
        dust.x = p.random(p.width);
      }
    }

    // Oppressive shadow gradient from top
    for(let i = 0; i < 100; i++) {
      let alpha = p.map(i, 0, 100, 80, 0);
      p.stroke(20, 15, 10, alpha);
      p.line(0, i, p.width, i);
    }
  };
}

