function sketch(p) {
  let waves = [];
  let signatures = [];
  let stephenX, stephenY;
  let eyesClosed = false;
  let handWriting = false;
  let timeOffset = 0;
  let particles = [];

  p.setup = function() {
    p.createCanvas(400, 600);

    // Initialize wave points
    for (let i = 0; i <= 50; i++) {
      waves.push({
        x: i * 8,
        baseY: 350 + p.sin(i * 0.3) * 20,
        offset: p.random(100)
      });
    }

    // Initialize beach signatures
    signatures.push({x: 80, y: 480, type: 'shell', alpha: 100});
    signatures.push({x: 150, y: 520, type: 'seaweed', alpha: 120});
    signatures.push({x: 280, y: 490, type: 'text', alpha: 80, word: 'ineluctable'});
    signatures.push({x: 320, y: 530, type: 'dog', alpha: 90});
    signatures.push({x: 200, y: 460, type: 'pool', alpha: 110});
    signatures.push({x: 250, y: 510, type: 'text', alpha: 70, word: 'modality'});

    // Stephen's position
    stephenX = 120;
    stephenY = 440;

    // Initialize particles for mutable reality
    for (let i = 0; i < 30; i++) {
      particles.push({
        x: p.random(400),
        y: p.random(300, 600),
        vx: p.random(-0.5, 0.5),
        vy: p.random(-0.3, 0.3),
        alpha: p.random(20, 60),
        size: p.random(2, 5)
      });
    }
  };

  p.draw = function() {
    // Shifting sky colors
    let skyR = 180 + p.sin(p.millis() * 0.001) * 30;
    let skyG = 185 + p.cos(p.millis() * 0.0007) * 25;
    let skyB = 170 + p.sin(p.millis() * 0.0012) * 40;

    // Gradient sky
    for (let y = 0; y <= 300; y++) {
      let inter = p.map(y, 0, 300, 0, 1);
      let c = p.lerpColor(p.color(skyR, skyG, skyB), p.color(120, 140, 130), inter);
      p.stroke(c);
      p.line(0, y, 400, y);
    }

    // Protean sea - colors shift
    let seaR = 90 + p.sin(p.millis() * 0.0015) * 40;
    let seaG = 130 + p.cos(p.millis() * 0.0008) * 35;
    let seaB = 110 + p.sin(p.millis() * 0.002) * 45;

    p.fill(seaR, seaG, seaB, 180);
    p.noStroke();

    // Animated waves with blurred boundaries
    p.beginShape();
    p.vertex(0, 600);
    for (let wave of waves) {
      let waveY = wave.baseY + p.sin(p.millis() * 0.002 + wave.offset) * 15;
      p.vertex(wave.x, waveY);
    }
    p.vertex(400, 600);
    p.endShape(p.CLOSE);

    // Sand with shifting color
    let sandR = 180 + p.sin(p.millis() * 0.0005) * 20;
    let sandG = 165 + p.cos(p.millis() * 0.0008) * 15;
    let sandB = 120 + p.sin(p.millis() * 0.0006) * 25;
    p.fill(sandR, sandG, sandB);
    p.rect(0, 400, 400, 200);

    // Blurred horizon effect
    for (let i = 0; i < 10; i++) {
      let alpha = p.map(i, 0, 9, 30, 0);
      p.stroke(seaR, seaG, seaB, alpha);
      p.line(0, 340 + i, 400, 340 + i);
    }

    // Mutable particles representing protean reality
    for (let particle of particles) {
      particle.x += particle.vx;
      particle.y += particle.vy;

      if (particle.x < 0 || particle.x > 400) particle.vx *= -1;
      if (particle.y < 300 || particle.y > 600) particle.vy *= -1;

      p.fill(255, 255, 255, particle.alpha);
      p.noStroke();
      p.ellipse(particle.x, particle.y, particle.size);
    }

    // Beach signatures - fade in and out
    for (let sig of signatures) {
      let visibility = 100 + p.sin(p.millis() * 0.003 + sig.alpha) * 80;
      p.fill(60, 50, 40, visibility);

      if (sig.type === 'shell') {
        p.ellipse(sig.x, sig.y, 8, 6);
        p.ellipse(sig.x + 2, sig.y - 1, 4, 3);
      } else if (sig.type === 'seaweed') {
        p.stroke(40, 80, 50, visibility);
        p.strokeWeight(2);
