    p.fill(60, 80, 90, drownedAlpha);
    p.ellipse(300, 320 + p.sin(p.millis() * 0.003) * 10, 20, 8);
    p.ellipse(290, 325 + p.sin(p.millis() * 0.003) * 10, 8, 15);
  };

