function sketch(p) {
  let bloomFigures = [];
  let steamParticles = [];
  let letterFloat = 0;
  let soapGlow = 0;
  let churchLight = 0;
  let bottles = [];
  let time = 0;

  p.setup = function() {
    p.createCanvas(400, 600);

    // Initialize Bloom figures in different poses
    bloomFigures = [
      { x: 80, y: 150, alpha: 0.4, pose: 'letter' },
      { x: 320, y: 200, alpha: 0.3, pose: 'church' },
      { x: 200, y: 300, alpha: 0.35, pose: 'soap' },
      { x: 150, y: 400, alpha: 0.25, pose: 'walking' }
    ];

    // Initialize chemistry bottles
    for (let i = 0; i < 5; i++) {
      bottles.push({
        x: 50 + i * 60,
        y: 450 + Math.sin(i) * 20,
        height: 40 + Math.random() * 30,
        hue: 120 + Math.random() * 60,
        bob: Math.random() * p.TWO_PI
      });
    }

    // Initialize steam particles
    for (let i = 0; i < 30; i++) {
      steamParticles.push({
        x: 300 + Math.random() * 80,
        y: 500,
        vy: -1 - Math.random() * 2,
        alpha: Math.random() * 100 + 50,
        size: Math.random() * 8 + 3
      });
    }
  };

  p.draw = function() {
    time += 0.02;

    // Soft, hazy background with warm tones
    for (let i = 0; i <= p.height; i += 2) {
      let inter = p.map(i, 0, p.height, 0, 1);
      let c = p.lerpColor(
        p.color(255, 248, 220, 80),
        p.color(200, 180, 255, 120),
        inter
      );
      p.stroke(c);
      p.line(0, i, p.width, i);
    }

    // Draw layered, transparent scenes
    drawBathtub();
    drawBloomFigures();
    drawLetter();
    drawChurchDoorway();
    drawChemistryBottles();
    drawSteam();

    // Gentle mouse interaction - affects transparency and movement
    let mouseInfluence = p.map(p.mouseX, 0, p.width, 0.5, 1.2);
    letterFloat = p.sin(time * 2) * 10 * mouseInfluence;
    soapGlow = (p.sin(time * 1.5) + 1) * 30;
    churchLight = (p.cos(time * 0.8) + 1) * 20;
  };

  function drawBathtub() {
    // Large bathtub in background, suggesting promised comfort
    p.push();
    p.fill(200, 220, 255, 40);
    p.noStroke();
    p.ellipse(320, 520, 140, 60);

    // Bathtub rim
    p.stroke(180, 200, 220, 60);
    p.strokeWeight(3);
    p.noFill();
    p.ellipse(320, 515, 140, 60);
    p.pop();
  }

  function drawBloomFigures() {
    bloomFigures.forEach((bloom, index) => {
      p.push();
      let drift = p.sin(time + index) * 3;
      let alpha = bloom.alpha * 255 * (0.8 + 0.4 * p.sin(time + index * 2));

      p.translate(bloom.x + drift, bloom.y);
      p.fill(80, 60, 40, alpha);
      p.noStroke();

      // Simple figure silhouette
      p.ellipse(0, -15, 12, 16); // head
      p.rect(-6, -8, 12, 25, 3); // body
      p.rect(-8, 15, 6, 15, 2); // left leg
      p.rect(2, 15, 6, 15, 2); // right leg

      // Arms in different poses
      if (bloom.pose === 'letter') {
        p.rect(6, -5, 12, 4, 2); // reaching arm
      } else if (bloom.pose === 'church') {
        p.rect(-15, -2, 8, 4, 2); // observing arm
      } else if (bloom.pose === 'soap') {
        p.ellipse(8, -2, 4, 4); // holding soap
      }

      p.pop();
    });
  }

  function drawLetter() {
    // Martha's letter with purple prose
    p.push();
    p.translate(80, 100 + letterFloat);
    p.rotate(p.sin(time) * 0.1);

    // Letter background
    p.fill(255, 250, 240, 150);
    p.stroke(200, 150, 200, 100);
    p.rect(0, 0, 60, 40, 3);

    // Purple prose suggestion
    p.stroke(150, 80, 150, 120);
    p.strokeWeight(1);
    for (let i = 0; i < 5; i++) {
      let y = 8 + i * 6;
      let wobble = p.sin(time * 3 + i) * 2;
      p.line(5, y + wobble, 50, y + wobble);
    }
    p.pop();
  }

  function drawChurchDoorway() {
    // Church doorway with light spilling out
    p.push();
    p.translate(320, 180);

    // Doorway
    p.fill(40, 30, 20, 100);
    p.rect(0, 0, 30, 50, 15, 15, 0, 0);

    // Light from inside
    p.fill(255, 245, 200, churchLight + 30);
    p.noStroke();
    p.triangle(0, 50, 30, 50, 15, 30);

    // Stained glass suggestion
    p.fill(100, 150, 200, 80);
    p.ellipse(15, 20, 8, 12);
    p.pop();
  }

  function drawChemistryBottles() {
    bottles.forEach((bottle, index) => {
      p.push();
      let bob = p.sin(time + bottle.bob) * 3;

      p.translate(bottle.x, bottle.y + bob);

      // Bottle body
      p.fill(bottle.hue, 100, 80, 100);
      p.stroke(bottle.hue, 150, 120, 150);
      p.strokeWeight(1);
      p.rect(-8, -bottle.height, 16, bottle.height, 3, 3, 1, 1);

      // Bottle neck
      p.rect(-3, -bottle.height - 8, 6, 8);

      // Contents
      p.fill(bottle.hue + 20, 80, 60, 60);
      p.noStroke();
      p.rect(-6, -bottle.height + 5, 12, bottle.height - 8, 2, 2, 1, 1);

      // Flower name labels (suggested)
      p.fill(255, 255, 255, 80);
      p.rect(-6, -bottle.height + 2, 12, 8, 1);

      p.pop();
    });
  }

  function drawSteam() {
    // Update and draw steam particles
    steamParticles.forEach((particle, index) => {
      particle.y += particle.vy;
      particle.x += p.sin(particle.y * 0.02) * 0.5;
      particle.alpha *= 0.998;

      if (particle.y < 300 || particle.alpha < 10) {
        particle.x = 300 + Math.random() * 80;
        particle.y = 500;
        particle.alpha = Math.random() * 100 + 50;
      }

      p.push();
      p.fill(220, 240, 255, particle.alpha);
      p.noStroke();
      p.ellipse(particle.x, particle.y, particle.size);
      p.pop();
    });

    // Soap with gentle glow
    p.push();
    p.translate(200, 300);
    p.fill(255, 255, 150, soapGlow + 80);
    p.noStroke();
    p.ellipse(0, 0, 15 + soapGlow * 0.1, 8);

    // Lemon soap color
    p.fill(255, 240, 100, 120);
    p.ellipse(0, 0, 12, 6);
    p.pop();
  }
}

