  p.setup = function() {
    p.createCanvas(400, 600);

    // Initialize cemetery elements
    for (let i = 0; i < 15; i++) {
      crosses.push({
        x: p.random(50, 350),
        y: p.random(200, 450),
        height: p.random(30, 60),
        sway: p.random(0.001, 0.003)
      });
    }

    for (let i = 0; i < 8; i++) {
      angels.push({
