      let sway = p.sin(time * mourner.sway + i) * 1;

      p.push();
      p.translate(mourner.x + sway, mourner.y);

      // Simple mourner figures
      p.rect(-8, -40, 16, 40); // body
      p.circle(0, -50, 16); // head
