    bloom.contemplation = p.sin(time * 0.002) * 5;
    p.fill(45, 50, 45);
    p.push();
    p.translate(bloom.x, bloom.y);

    // Bloom's figure - more detailed, thoughtful posture
    p.rect(-10, -45, 20, 45); // body
    p.circle(0, -55, 18); // head

    // Thoughtful gesture - hand to chin
    p.fill(60, 70, 60);
    p.circle(8, -50, 4); // hand

    // His gaze direction - looking at grave but also beyond
    p.stroke(70, 80, 70);
    p.strokeWeight(1);
    let gazeX = 50 + bloom.contemplation;
    let gazeY = -30;
    p.line(3, -50, gazeX, gazeY);
