    // Ghost images fade in based on mouse proximity to Bloom
    let bloomDistance = p.dist(p.mouseX, p.mouseY, bloom.x, bloom.y);
    let ghostOpacity = p.map(bloomDistance, 0, 100, 120, 0);
    ghostOpacity = p.constrain(ghostOpacity, 0, 120);

    for (let ghost of ghostImages) {
      p.fill(110, 120, 110, ghostOpacity);
      p.noStroke();

      if (ghost.type === 'father') {
        // Older figure
        p.push();
        p.translate(ghost.x, ghost.y);
        p.rect(-8, -35, 16, 35);
        p.circle(0, -45, 15);
        p.pop();
      } else if (ghost.type === 'rudy') {
        // Small coffin suggestion
        p.push();
        p.translate(ghost.x, ghost.y);
        p.rect(-15, -8, 30, 16);
        p.pop();
      }
    }

    // Rain effect
    p.stroke(120, 130, 120, 80);
    p.strokeWeight(1);
    for (let drop of raindrops) {
      p.line(drop.x, drop.y, drop.x - 2, drop.y + drop.length);
      drop.y += drop.speed;
      drop.x -= 0.5;

      if (drop.y > 600) {
        drop.y = p.random(-50, 0);
        drop.x = p.random(450);
      }
    }

    // Atmospheric overlay - sense of weight and presence
    p.fill(85, 95, 85, 30);
    p.noStroke();
    p.rect(0, 0, 400, 600);

    // Subtle highlight on Bloom when mouse approaches
    if (bloomDistance < 50) {
      p.fill(130, 140, 130, 50);
      p.noStroke();
      p.circle(bloom.x, bloom.y - 25, 60);
    }
  };
}

