function sketch(p) {
  let papers = [];
  let headlines = [];
  let speechBubbles = [];
  let figures = [];
  let windOffset = 0;
  let rejectionAnimation = 0;

  p.setup = function() {
    p.createCanvas(400, 600);

    // Initialize flying papers
    for (let i = 0; i < 15; i++) {
      papers.push({
        x: p.random(400),
        y: p.random(600),
        size: p.random(20, 40),
        rotation: p.random(p.TWO_PI),
        speed: p.random(0.5, 2),
        drift: p.random(-0.02, 0.02)
      });
    }

    // Headlines that fragment the image
    headlines = [
      {text: "SOPHIST WALLOPS", x: 50, y: 120, active: false},
      {text: "HAUGHTY HELEN", x: 250, y: 180, active: false},
      {text: "SAD", x: 100, y: 350, active: false},
      {text: "RHETORIC RULES", x: 200, y: 450, active: false}
    ];

    // Speech bubbles/fragments
    for (let i = 0; i < 8; i++) {
      speechBubbles.push({
        x: p.random(50, 350),
        y: p.random(200, 500),
        size: p.random(15, 30),
        alpha: p.random(100, 200),
        pulse: p.random(0, p.TWO_PI)
      });
    }

    // Key figures
    figures = [
      {name: "Crawford", x: 120, y: 280, pointing: true, dominant: true},
      {name: "Bloom", x: 280, y: 320, rejected: true},
      {name: "Stephen", x: 80, y: 400, observing: true},
      {name: "Journalist1", x: 200, y: 250, gesturing: true},
      {name: "Journalist2", x: 300, y: 280, gesturing: true}
    ];
  };

  p.draw = function() {
    // Dynamic background - newspaper texture
    p.background(245, 240, 225);

    // Draw printing press machinery in background
    p.fill(60, 60, 70, 150);
    p.noStroke();
    for (let i = 0; i < 3; i++) {
      p.rect(20 + i * 120, 50, 80, 150, 5);
      // Moving parts
      p.fill(40, 40, 50, 200);
      p.rect(30 + i * 120, 70 + p.sin(p.millis() * 0.01 + i) * 5, 60, 20);
    }

    windOffset += 0.02;
    rejectionAnimation = p.abs(p.sin(p.millis() * 0.003)) * 0.3 + 0.7;

    // Flying papers with wind effect
    for (let paper of papers) {
      p.push();
      p.translate(paper.x, paper.y);
      p.rotate(paper.rotation + p.sin(windOffset + paper.x * 0.01) * 0.3);

      p.fill(255, 255, 255, 180);
      p.stroke(0, 50);
      p.rect(0, 0, paper.size, paper.size * 1.4);

      // Fake text lines on papers
      p.stroke(0, 100);
      for (let j = 0; j < 4; j++) {
        p.line(2, 4 + j * 6, paper.size - 2, 4 + j * 6);
      }

      p.pop();

      // Update paper positions
      paper.x += paper.speed + p.sin(windOffset + paper.y * 0.01) * 2;
      paper.y += paper.drift;
      paper.rotation += 0.02;

      if (paper.x > 450) {
        paper.x = -50;
        paper.y = p.random(600);
      }
    }

    // Draw figures
    for (let fig of figures) {
      p.push();
      p.translate(fig.x, fig.y);

      if (fig.name === "Crawford" && fig.dominant) {
        // Dominant editor pointing dismissively
        p.fill(80, 60, 40);
        p.ellipse(0, -20, 25, 30); // head
        p.fill(40, 40, 60);
        p.rect(-15, -10, 30, 40); // body

        // Pointing gesture (animated)
        p.stroke(80, 60, 40);
        p.strokeWeight(4);
        let pointAngle = -0.5 + p.sin(p.millis() * 0.005) * 0.2;
        p.line(10, 0, 10 + p.cos(pointAngle) * 25, p.sin(pointAngle) * 25);

      } else if (fig.name === "Bloom" && fig.rejected) {
        // Bloom being dismissed, holding papers
        p.fill(120, 100, 80);
        p.ellipse(0, -20, 20, 25); // head
        p.fill(60, 60, 90);
        p.rect(-12, -10, 24, 35); // body

        // Holding advertisement (shrinks during rejection)
        p.fill(255, 255, 255, 200 * rejectionAnimation);
        p.rect(-8, 5, 16 * rejectionAnimation, 20 * rejectionAnimation);

      } else if (fig.name === "Stephen" && fig.observing) {
        // Young Stephen, contemplative
        p.fill(100, 85, 70);
        p.ellipse(0, -18, 18, 22); // head
        p.fill(30, 50, 30);
        p.rect(-10, -8, 20, 32); // body

      } else if (fig.gesturing) {
        // Generic journalists gesturing
        p.fill(90, 75, 60);
        p.ellipse(0, -18, 16, 20); // head
        p.fill(50, 50, 70);
        p.rect(-8, -8, 16, 28); // body

        // Animated gestures
        p.stroke(90, 75, 60);
        p.strokeWeight(3);
        let gestureAngle = p.sin(p.millis() * 0.01 + fig.x * 0.01) * 0.8;
        p.line(5, -5, 5 + p.cos(gestureAngle) * 15, -5 + p.sin(gestureAngle) * 15);
      }
      p.pop();
    }

    // Speech bubbles representing cacophony
    p.noStroke();
    for (let bubble of speechBubbles) {
      let pulsation = p.sin(bubble.pulse + p.millis() * 0.01) * 0.3 + 0.7;
      p.fill(255, 255, 255, bubble.alpha * pulsation);
      p.ellipse(bubble.x, bubble.y, bubble.size * pulsation, bubble.size * pulsation * 0.7);

      // Tiny dots suggesting text/noise
      p.fill(0, 0, 0, bubble.alpha * pulsation * 0.5);
      for (let i = 0; i < 3; i++) {
        p.ellipse(bubble.x - 5 + i * 5, bubble.y, 2, 2);
      }
    }

    // Fragment the image with headlines
    p.textSize(24);
    p.textStyle(p.BOLD);
    p.fill(0, 0, 0, 200);

    for (let headline of headlines) {
      // Make headlines appear/disappear based on mouse proximity
      let distance = p.dist(p.mouseX, p.mouseY, headline.x, headline.y);
      headline.active = distance < 100;

      if (headline.active || p.sin(p.millis() * 0.002 + headline.x * 0.01) > 0) {
        p.push();
        p.translate(headline.x, headline.y);
        p.rotate(p.sin(p.millis() * 0.001 + headline.x * 0.01) * 0.1);

        // Newspaper-style background bar
        p.fill(0, 0, 0, 150);
        p.rect(-headline.text.length * 6, -15, headline.text.length * 12, 25);

        p.fill(255, 255, 255);
        p.text(headline.text, -headline.text.length * 6, 0);
        p.pop();
      }
    }

    // Suggestion of Moses on Pisgah in background
    p.fill(100, 100, 120, 80);
    p.triangle(320, 100, 340, 60, 360, 100);
    p.ellipse(340, 55, 8, 8); // tiny figure on mountain

    // Interactive wind effect on mouse movement
    if (p.mouseX > 0 && p.mouseX < 400) {
      let mouseWind = (p.mouseX - p.pmouseX) * 0.1;
      for (let paper of papers) {
        paper.x += mouseWind;
        paper.rotation += mouseWind * 0.05;
      }
    }
  };
}

