function sketch(p) {
  let bloomX, bloomY;
  let crowds = [];
  let foodParticles = [];
  let time = 0;
  let blindBoy = {};
  let thoughtClouds = [];
  let mouths = [];

  p.setup = function() {
    p.createCanvas(400, 600);

    // Initialize Bloom's position
    bloomX = 120;
    bloomY = 300;

    // Initialize blind boy
    blindBoy = {
      x: 280,
      y: 350,
      guided: false
    };

    // Create crowd members
    for (let i = 0; i < 12; i++) {
      crowds.push({
        x: p.random(50, 350),
        y: p.random(200, 500),
        eating: p.random() > 0.5,
        mouthOpen: 0,
        violence: p.random(0.3, 1.0),
        size: p.random(15, 25)
      });
    }

    // Create floating mouths
    for (let i = 0; i < 8; i++) {
      mouths.push({
        x: p.random(400),
        y: p.random(600),
        openness: p.random(),
        speed: p.random(0.5, 2)
      });
    }

    // Create thought clouds
    for (let i = 0; i < 5; i++) {
      thoughtClouds.push({
        x: p.random(300, 400),
        y: p.random(50, 150),
        alpha: p.random(50, 150),
        type: p.floor(p.random(3)) // 0: Molly, 1: food, 2: Boylan
      });
    }
  };

  p.draw = function() {
    time += 0.02;

    // Background - warm Dublin street
    p.background(85, 70, 50);

    // Street atmosphere
    for (let i = 0; i < 20; i++) {
      p.fill(120, 85, 60, 30);
      p.noStroke();
      p.ellipse(p.random(400), p.random(600), p.random(50, 200));
    }

    // Burton's restaurant (violent eating) - left side
    p.fill(140, 40, 30, 180);
    p.rect(20, 150, 80, 120, 5);

    // Draw violent eaters in Burton's
    for (let i = 0; i < 3; i++) {
      let x = 30 + i * 20;
      let y = 180 + p.sin(time * 3 + i) * 5;
      p.fill(180, 60, 40);
      p.ellipse(x, y, 12);
      // Violent mouth
      p.fill(20, 10, 10);
      p.arc(x, y + 2, 8, 6, 0, p.PI);
    }

    // Davy Byrne's pub (gentle, moderate) - right side
    p.fill(80, 120, 60, 180);
    p.rect(300, 180, 80, 100, 5);

    // Gorgonzola sandwich and burgundy
    p.fill(220, 200, 140);
    p.rect(320, 220, 25, 15, 3);
    p.fill(100, 30, 60);
    p.ellipse(350, 230, 12, 15);

    // Draw crowd with eating emphasis
    for (let person of crowds) {
      p.push();
      p.translate(person.x, person.y);

      // Body
      p.fill(120 + p.sin(time) * 20, 80, 60);
      p.ellipse(0, 0, person.size);

      // Mouth emphasis
      if (person.eating) {
        person.mouthOpen = p.sin(time * 2 + person.x * 0.01) * 0.5 + 0.5;
        p.fill(40, 20, 20);
        p.arc(0, 2, person.size * 0.4, person.size * 0.3 * person.mouthOpen, 0, p.PI);

        // Food particles
        if (p.random() < 0.1) {
          foodParticles.push({
            x: person.x + p.random(-5, 5),
            y: person.y + p.random(-5, 5),
            life: 60,
            color: [p.random(100, 200), p.random(50, 150), p.random(30, 80)]
          });
        }
      }

      p.pop();
    }

    // Update and draw food particles
    for (let i = foodParticles.length - 1; i >= 0; i--) {
      let particle = foodParticles[i];
      p.fill(particle.color[0], particle.color[1], particle.color[2], particle.life * 2);
      p.noStroke();
      p.ellipse(particle.x, particle.y, 3);
      particle.life--;
      particle.y += 0.5;
      if (particle.life <= 0) {
        foodParticles.splice(i, 1);
      }
    }

    // Draw floating mouths (peristaltic imagery)
    for (let mouth of mouths) {
      mouth.y += mouth.speed;
      if (mouth.y > 650) mouth.y = -50;

      mouth.openness = p.sin(time * 2 + mouth.x * 0.01) * 0.5 + 0.5;

      p.fill(160, 80, 60, 100);
      p.noStroke();
      p.ellipse(mouth.x, mouth.y, 20);

      p.fill(60, 30, 30, 150);
      p.arc(mouth.x, mouth.y + 2, 15, 10 * mouth.openness, 0, p.PI);
    }

    // Bloom walking and observing
    bloomX += p.sin(time * 0.5) * 0.3;
    bloomY += p.cos(time * 0.3) * 0.2;

    p.fill(90, 110, 140);
    p.ellipse(bloomX, bloomY, 30);
    p.fill(40, 30, 20);
    p.ellipse(bloomX - 3, bloomY - 5, 4);
    p.ellipse(bloomX + 3, bloomY - 5, 4);

    // Bloom helping blind boy
    let dist = p.dist(bloomX, bloomY, blindBoy.x, blindBoy.y);
    if (dist < 40 && !blindBoy.guided) {
      blindBoy.guided = true;
    }

    // Draw blind boy
    p.fill(70, 90, 110);
    p.ellipse(blindBoy.x, blindBoy.y, 25);

    if (blindBoy.guided) {
      // Show guiding gesture
      p.stroke(200, 180, 140);
      p.strokeWeight(2);
      p.line(bloomX + 10, bloomY, blindBoy.x - 10, blindBoy.y);
      blindBoy.x += 0.2;
    }

    // Thought clouds (Molly, food, Boylan intermingled)
    for (let cloud of thoughtClouds) {
      cloud.alpha = 80 + p.sin(time + cloud.x * 0.01) * 30;
      cloud.y += p.sin(time * 0.5 + cloud.x * 0.01) * 0.1;

      p.fill(cloud.alpha, cloud.alpha * 0.7, cloud.alpha * 0.5, cloud.alpha);
      p.noStroke();

      if (cloud.type === 0) { // Molly
        p.ellipse(cloud.x, cloud.y, 25, 15);
      } else if (cloud.type === 1) { // Food
        p.rect(cloud.x - 8, cloud.y - 4, 16, 8, 3);
      } else { // Boylan
        p.ellipse(cloud.x, cloud.y, 20);
        p.fill(cloud.alpha * 0.5, cloud.alpha * 0.3, cloud.alpha * 0.3, cloud.alpha);
        p.ellipse(cloud.x, cloud.y - 2, 8);
      }
    }

    // Digestive/peristaltic waves
    p.stroke(180, 100, 80, 100);
    p.strokeWeight(3);
    p.noFill();
    for (let i = 0; i < 5; i++) {
      let waveY = 100 + i * 100 + p.sin(time * 2 - i * 0.5) * 20;
      p.beginShape();
      for (let x = 0; x < 400; x += 10) {
        let y = waveY + p.sin(x * 0.02 + time * 2 - i * 0.5) * 10;
        p.curveVertex(x, y);
      }
      p.endShape();
    }

    // Interactive element - mouse affects hunger intensity
    let hungerIntensity = p.map(p.mouseY, 0, 600, 0.5, 2.0);
    for (let person of crowds) {
      if (person.eating) {
        person.mouthOpen *= hungerIntensity;
      }
    }
  };
}

