function sketch(p) {
  let books = [];
  let scylla, charybdis;
  let stephen, figures;
  let shakespeareGhost;
  let textFragments = [];
  let time = 0;

  p.setup = function() {
    p.createCanvas(400, 600);

    // Initialize book stacks
    for (let i = 0; i < 20; i++) {
      books.push({
        x: p.random(50, 350),
        y: p.random(450, 580),
        w: p.random(15, 25),
        h: p.random(3, 8),
        color: p.color(p.random(60, 120), p.random(40, 80), p.random(80, 140)),
        sway: p.random(-0.02, 0.02)
      });
    }

    // Initialize Scylla (rock formation)
    scylla = {
      x: 60,
      y: 200,
      points: []
    };
    for (let i = 0; i < 8; i++) {
      scylla.points.push({
        x: p.random(-20, 20),
        y: p.random(-30, 30),
        baseY: p.random(-30, 30)
      });
    }

    // Initialize Charybdis (whirlpool)
    charybdis = {
      x: 340,
      y: 200,
      rotation: 0,
      spirals: []
    };
    for (let i = 0; i < 5; i++) {
      let radius = 20 + i * 8;
      for (let j = 0; j < 12; j++) {
        charybdis.spirals.push({
          angle: j * p.PI / 6,
          radius: radius,
          layer: i
        });
      }
    }

    // Initialize Stephen
    stephen = {
      x: 200,
      y: 280,
      argumentIntensity: 0
    };

    // Initialize literary figures
    figures = [
      { x: 120, y: 320, name: "AE", listening: 0 },
      { x: 280, y: 340, name: "Eglinton", skepticism: 0 },
      { x: 160, y: 370, name: "Best", attention: 0 }
    ];

    // Shakespeare ghost
    shakespeareGhost = {
      x: 200,
      y: 120,
      opacity: 0,
      phase: 0
    };

    // Text fragments
    textFragments = [
      { text: "HAMLET", x: 150, y: 100, float: 0 },
      { text: "THEORY", x: 250, y: 180, float: 0 },
      { text: "FATHER", x: 300, y: 120, float: 0 },
      { text: "ART", x: 100, y: 160, float: 0 }
    ];
  };

  p.draw = function() {
    time += 0.02;

    // Library background - muted blues and grays
    p.background(45, 55, 75);

    // Dome ceiling suggestion
    p.fill(55, 65, 85, 150);
    p.noStroke();
    p.ellipse(200, -100, 500, 400);

    // Library shelves in background
    p.stroke(30, 40, 60);
    p.strokeWeight(2);
    for (let i = 0; i < 8; i++) {
      let y = 50 + i * 60;
      p.line(20, y, 380, y);
    }

    // Draw books with subtle movement
    for (let book of books) {
      p.push();
      p.translate(book.x, book.y + p.sin(time + book.x * 0.01) * book.sway);
      p.fill(book.color);
      p.noStroke();
      p.rect(0, 0, book.w, book.h);
      p.pop();
    }

    // Draw Scylla (jagged rock)
    p.push();
    p.translate(scylla.x, scylla.y);
    p.fill(80, 90, 110);
    p.stroke(60, 70, 90);
    p.strokeWeight(2);
    p.beginShape();
    for (let point of scylla.points) {
      let y = point.baseY + p.sin(time * 2 + point.x * 0.1) * 3;
      p.vertex(point.x, y);
    }
    p.endShape(p.CLOSE);
    p.pop();

    // Draw Charybdis (whirlpool)
    p.push();
    p.translate(charybdis.x, charybdis.y);
    charybdis.rotation += 0.03;
    p.rotate(charybdis.rotation);
    p.noFill();
    p.stroke(70, 120, 160, 180);
    p.strokeWeight(3);
    for (let spiral of charybdis.spirals) {
      let x = p.cos(spiral.angle + charybdis.rotation * spiral.layer) * spiral.radius;
      let y = p.sin(spiral.angle + charybdis.rotation * spiral.layer) * spiral.radius;
      p.strokeWeight(4 - spiral.layer * 0.5);
      p.point(x, y);
    }
    p.pop();

    // Draw literary figures
    for (let figure of figures) {
      p.fill(90, 80, 70);
      p.noStroke();
      p.ellipse(figure.x, figure.y, 25, 30); // head
      p.rect(figure.x - 15, figure.y + 15, 30, 40); // body

      // Listening/reaction indicators
      if (figure.name === "AE") {
        figure.listening = p.sin(time * 3) * 0.5 + 0.5;
        p.fill(120, 100, 80, figure.listening * 100);
        p.ellipse(figure.x, figure.y - 20, 15, 10);
      }
    }

    // Draw Stephen (central figure)
    stephen.argumentIntensity = p.abs(p.sin(time * 2));
    p.fill(70 + stephen.argumentIntensity * 30, 60, 50);
    p.noStroke();
    p.ellipse(stephen.x, stephen.y, 28, 35); // head
    p.rect(stephen.x - 18, stephen.y + 18, 36, 45); // body

    // Stephen's gesturing arms
    p.stroke(70, 60, 50);
    p.strokeWeight(4);
    let armAngle = p.sin(time * 4) * 0.3;
    p.line(stephen.x - 18, stephen.y + 25, stephen.x - 35 + p.cos(armAngle) * 15, stephen.y + 40 + p.sin(armAngle) * 10);
    p.line(stephen.x + 18, stephen.y + 25, stephen.x + 35 + p.cos(-armAngle) * 15, stephen.y + 40 + p.sin(-armAngle) * 10);

    // Shakespeare ghost
    shakespeareGhost.opacity = (p.sin(time * 1.5) + 1) * 0.3;
    shakespeareGhost.phase += 0.01;
    p.fill(200, 180, 160, shakespeareGhost.opacity * 100);
    p.noStroke();
    p.push();
    p.translate(shakespeareGhost.x + p.sin(shakespeareGhost.phase) * 10, shakespeareGhost.y);
    p.ellipse(0, 0, 40, 45); // ghostly head
    p.rect(-20, 20, 40, 50); // ghostly body
    p.pop();

    // Floating text fragments
    for (let fragment of textFragments) {
      fragment.float += 0.03;
      p.fill(160, 140, 120, 150 + p.sin(fragment.float) * 50);
      p.textAlign(p.CENTER);
      p.textSize(12);
      p.text(fragment.text, 
        fragment.x + p.cos(fragment.float) * 5, 
        fragment.y + p.sin(fragment.float * 0.7) * 3);
    }

    // Mulligan entering from side (brief appearance)
    if (p.sin(time * 0.5) > 0.8) {
      p.fill(100, 90, 80);
      p.noStroke();
      let mulliganX = 350 + p.sin(time * 10) * 20;
      p.ellipse(mulliganX, 300, 22, 28);
      p.rect(mulliganX - 12, 315, 24, 35);
    }

    // Passage between Scylla and Charybdis
    p.stroke(120, 140, 180, 100);
    p.strokeWeight(2);
    p.line(scylla.x + 30, scylla.y, charybdis.x - 30, charybdis.y);

    // Interactive element - mouse affects argument intensity
    let mouseInfluence = p.map(p.mouseY, 0, p.height, 0, 1);
    stephen.argumentIntensity += mouseInfluence * 0.1;

    // Intellectual combat atmosphere
    p.fill(100, 120, 140, 30);
    p.noStroke();
    for (let i = 0; i < 5; i++) {
      let x = stephen.x + p.sin(time * 3 + i) * (30 + i * 10);
      let y = stephen.y + p.cos(time * 3 + i) * (20 + i * 5);
      p.ellipse(x, y, 10 - i, 10 - i);
    }
  };
}

