function sketch(p) {
  let streets = [];
  let figures = [];
  let clocks = [];
  let liffey;
  let time = 0;

  p.setup = function() {
    p.createCanvas(400, 600);

    // Create street network as labyrinth
    for (let i = 0; i < 25; i++) {
      streets.push({
        x1: p.random(0, 400),
        y1: p.random(100, 500),
        x2: p.random(0, 400),
        y2: p.random(100, 500),
        weight: p.random(1, 3),
        opacity: p.random(150, 255)
      });
    }

    // The Liffey - main river
    liffey = {
      points: []
    };
    for (let i = 0; i <= 400; i += 20) {
      liffey.points.push({
        x: i,
        y: 300 + p.sin(i * 0.02) * 30
      });
    }

    // Create wandering figures
    figures.push({
      x: 50, y: 150, vx: 0.8, vy: 0.2, color: [120, 80, 140], 
      path: [], name: "Conmee", blessing: true
    });
    figures.push({
      x: 350, y: 200, vx: -1.2, vy: 0.5, color: [180, 120, 60], 
      path: [], name: "Cavalcade", pomp: true
    });
    figures.push({
      x: 200, y: 320, vx: 0.3, vy: -0.7, color: [100, 140, 100], 
      path: [], name: "Bloom", book: true
    });
    figures.push({
      x: 150, y: 450, vx: 0.9, vy: -0.3, color: [140, 100, 80], 
      path: [], name: "Stephen", browsing: true
    });
    figures.push({
      x: 300, y: 380, vx: -0.6, vy: 0.8, color: [160, 90, 90], 
      path: [], name: "Boylan", fruit: true
    });

    // Create clocks showing 3pm
    for (let i = 0; i < 4; i++) {
      clocks.push({
        x: p.random(50, 350),
        y: p.random(80, 520),
        size: p.random(15, 25)
      });
    }
  };

  p.draw = function() {
    // Sepia/old map background
    p.background(240, 235, 215);

    time += 0.02;

    // Draw street network
    p.stroke(120, 110, 90, 150);
    for (let street of streets) {
      p.strokeWeight(street.weight);
      p.stroke(120, 110, 90, street.opacity);
      let wobble1 = p.sin(time + street.x1 * 0.01) * 2;
      let wobble2 = p.sin(time + street.x2 * 0.01) * 2;
      p.line(street.x1 + wobble1, street.y1, street.x2 + wobble2, street.y2);
    }

    // Draw the Liffey
    p.stroke(80, 120, 160, 180);
    p.strokeWeight(4);
    p.noFill();
    p.beginShape();
    for (let point of liffey.points) {
      let flow = p.sin(time * 2 + point.x * 0.05) * 5;
      p.vertex(point.x, point.y + flow);
    }
    p.endShape();

    // Draw and update figures
    for (let i = 0; i < figures.length; i++) {
      let fig = figures[i];

      // Update position with slight wandering
      fig.x += fig.vx + p.sin(time + i) * 0.2;
      fig.y += fig.vy + p.cos(time + i * 1.5) * 0.15;

      // Wrap around edges
      if (fig.x < 0) fig.x = 400;
      if (fig.x > 400) fig.x = 0;
      if (fig.y < 100) fig.y = 500;
      if (fig.y > 500) fig.y = 100;

      // Add to path
      fig.path.push({x: fig.x, y: fig.y});
      if (fig.path.length > 50) fig.path.shift();

      // Draw path
      p.stroke(fig.color[0], fig.color[1], fig.color[2], 100);
      p.strokeWeight(2);
      p.noFill();
      p.beginShape();
      for (let pos of fig.path) {
        p.vertex(pos.x, pos.y);
      }
      p.endShape();

      // Draw figure
      p.fill(fig.color[0], fig.color[1], fig.color[2], 200);
      p.noStroke();
      p.circle(fig.x, fig.y, 8);

      // Special attributes
      if (fig.blessing) {
        p.stroke(255, 255, 200, 150);
        p.strokeWeight(1);
        p.noFill();
        p.circle(fig.x, fig.y, 20 + p.sin(time * 3) * 3);
      }
      if (fig.pomp) {
        p.stroke(200, 180, 60, 180);
        p.strokeWeight(3);
        p.line(fig.x - 15, fig.y, fig.x + 15, fig.y);
      }
      if (fig.book) {
        p.fill(160, 120, 80);
        p.noStroke();
        p.rect(fig.x - 3, fig.y - 6, 6, 8);
      }
      if (fig.browsing) {
        p.stroke(100, 100, 100, 150);
        p.strokeWeight(2);
        p.point(fig.x - 8, fig.y - 5);
        p.point(fig.x + 8, fig.y - 5);
      }
      if (fig.fruit) {
        p.fill(180, 100, 100);
        p.noStroke();
        p.circle(fig.x - 4, fig.y - 8, 4);
        p.fill(100, 150, 80);
        p.circle(fig.x + 4, fig.y - 8, 4);
      }
    }

    // Draw clocks showing 3pm
    for (let clock of clocks) {
      p.stroke(60, 50, 40);
      p.strokeWeight(2);
      p.fill(250, 245, 235);
      p.circle(clock.x, clock.y, clock.size);

      // Clock hands pointing to 3pm
      let centerX = clock.x;
      let centerY = clock.y;
      let radius = clock.size * 0.3;

      // Hour hand (pointing right for 3)
      p.stroke(40, 30, 20);
      p.strokeWeight(3);
      p.line(centerX, centerY, centerX + radius * 0.6, centerY);

      // Minute hand (pointing up for 00)
      p.strokeWeight(2);
      p.line(centerX, centerY, centerX, centerY - radius * 0.8);
    }

    // Draw intersection points where paths might cross
    for (let i = 0; i < figures.length; i++) {
      for (let j = i + 1; j < figures.length; j++) {
        let dist = p.dist(figures[i].x, figures[i].y, figures[j].x, figures[j].y);
        if (dist < 30) {
          p.fill(255, 200, 100, 100);
          p.noStroke();
          let midX = (figures[i].x + figures[j].x) / 2;
          let midY = (figures[i].y + figures[j].y) / 2;
          p.circle(midX, midY, 10);
        }
      }
    }

    // Overlay labyrinth pattern
    p.stroke(100, 90, 70, 50);
    p.strokeWeight(1);
    p.noFill();
    let centerX = 200;
    let centerY = 300;
    for (let r = 20; r < 150; r += 25) {
      let sides = p.floor(r / 10) + 4;
      p.beginShape();
      for (let a = 0; a <= p.TWO_PI; a += p.TWO_PI / sides) {
        let x = centerX + p.cos(a + time * 0.5) * r;
        let y = centerY + p.sin(a + time * 0.5) * r * 0.7;
        p.vertex(x, y);
      }
      p.endShape(p.CLOSE);
    }

    // Interactive element - mouse creates temporary connection lines
    if (p.mouseX > 0 && p.mouseX < 400 && p.mouseY > 0 && p.mouseY < 600) {
      p.stroke(200, 150, 100, 100);
      p.strokeWeight(1);
      for (let fig of figures) {
        p.line(p.mouseX, p.mouseY, fig.x, fig.y);
      }
    }
  };
}

