function sketch(p) {
  let barmaids = [];
  let musicNotes = [];
  let soundWaves = [];
  let tuningFork;
  let bloom;
  let simon;
  let hoofbeats = [];
  let time = 0;

  p.setup = function() {
    p.createCanvas(400, 600);

    // Initialize barmaids
    barmaids.push({
      x: 120,
      y: 180,
      color: [184, 115, 51], // bronze
      mouth: 0,
      sway: 0
    });
    barmaids.push({
      x: 280,
      y: 170,
      color: [255, 215, 0], // gold
      mouth: 0,
      sway: 0
    });

    // Initialize Bloom
    bloom = {
      x: 80,
      y: 320,
      writing: 0
    };

    // Initialize Simon
    simon = {
      x: 320,
      y: 300,
      singing: 0
    };

    // Initialize tuning fork
    tuningFork = {
      x: 200,
      y: 250,
      vibration: 0
    };

    // Initialize music notes
    for(let i = 0; i < 15; i++) {
      musicNotes.push({
        x: p.random(400),
        y: p.random(600),
        size: p.random(8, 20),
        drift: p.random(-1, 1),
        alpha: p.random(100, 255)
      });
    }

    // Initialize hoofbeats
    for(let i = 0; i < 3; i++) {
      hoofbeats.push({
        x: 350 + i * 30,
        y: 80,
        phase: i * 0.5
      });
    }
  };

  p.draw = function() {
    time += 0.02;

    // Background - warm hotel interior
    p.background(40, 25, 15);

    // Window showing outside
    p.fill(20, 30, 50, 150);
    p.rect(280, 40, 100, 80);

    // Hoofbeats outside window
    p.fill(255, 100);
    for(let hoof of hoofbeats) {
      let bounce = p.sin(time * 4 + hoof.phase) * 3;
      p.ellipse(hoof.x, hoof.y + bounce, 8, 4);
    }

    // Bar counter
    p.fill(101, 67, 33);
    p.rect(0, 140, 400, 40);

    // Draw barmaids
    for(let barmaid of barmaids) {
      barmaid.sway = p.sin(time + barmaid.x * 0.01) * 5;
      barmaid.mouth = (p.sin(time * 3 + barmaid.x * 0.02) + 1) * 10;

      // Body
      p.fill(barmaid.color[0], barmaid.color[1], barmaid.color[2]);
      p.ellipse(barmaid.x + barmaid.sway, barmaid.y, 40, 60);

      // Head
      p.fill(250, 220, 190);
      p.ellipse(barmaid.x + barmaid.sway, barmaid.y - 40, 30, 35);

      // Hair
      p.fill(barmaid.color[0], barmaid.color[1], barmaid.color[2]);
      p.ellipse(barmaid.x + barmaid.sway, barmaid.y - 50, 35, 25);

      // Singing mouth
      p.fill(200, 100, 100);
      p.ellipse(barmaid.x + barmaid.sway, barmaid.y - 35, 8, barmaid.mouth);
    }

    // Draw Bloom writing
    bloom.writing = p.sin(time * 2) * 2;
    p.fill(60, 60, 80);
    p.ellipse(bloom.x, bloom.y, 35, 50);
    p.fill(220, 190, 160);
    p.ellipse(bloom.x, bloom.y - 25, 25, 30);

    // Bloom's letter
    p.fill(255, 255, 200, 180);
    p.rect(bloom.x + 15, bloom.y - 10, 20, 25);

    // Bloom's hand writing
    p.stroke(50);
    p.strokeWeight(1);
    p.line(bloom.x + 20, bloom.y + bloom.writing, bloom.x + 30, bloom.y + 5 + bloom.writing);
    p.noStroke();

    // Draw Simon singing
    simon.singing = p.sin(time * 2.5) * 3;
    p.fill(80, 60, 40);
    p.ellipse(simon.x, simon.y, 40, 55);
    p.fill(220, 190, 160);
    p.ellipse(simon.x, simon.y - 30, 28, 32);

    // Simon's open mouth
    p.fill(150, 80, 80);
    p.ellipse(simon.x, simon.y - 25, 10, 12 + simon.singing);

    // Tuning fork
    tuningFork.vibration = p.sin(time * 8) * 2;
    p.fill(200, 200, 220);
    p.rect(tuningFork.x - 2, tuningFork.y, 4, 30);
    p.rect(tuningFork.x - 8 + tuningFork.vibration, tuningFork.y - 20, 3, 20);
    p.rect(tuningFork.x + 5 - tuningFork.vibration, tuningFork.y - 20, 3, 20);

    // Sound waves from tuning fork
    p.stroke(200, 200, 255, 100);
    p.strokeWeight(2);
    p.noFill();
    for(let i = 1; i < 6; i++) {
      let radius = i * 15 + p.sin(time * 4) * 5;
      p.ellipse(tuningFork.x, tuningFork.y - 10, radius, radius);
    }
    p.noStroke();

    // Floating music notes
    for(let note of musicNotes) {
      note.y += note.drift;
      note.x += p.sin(time + note.y * 0.01) * 0.5;

      if(note.y < -20) note.y = 620;
      if(note.y > 620) note.y = -20;

      p.fill(255, 215, 0, note.alpha);

      // Musical note shape
      p.ellipse(note.x, note.y, note.size * 0.7, note.size * 0.5);
      if(note.size > 12) {
        p.rect(note.x + note.size * 0.3, note.y - note.size * 0.8, 2, note.size * 0.8);
      }
    }

    // Sound visualization - radiating from singers
    p.stroke(255, 215, 0, 60);
    p.strokeWeight(1);
    p.noFill();
    for(let i = 0; i < 3; i++) {
      let radius = (time * 30 + i * 20) % 150;
      p.ellipse(barmaids[0].x, barmaids[0].y - 40, radius, radius * 0.7);
      p.ellipse(barmaids[1].x, barmaids[1].y - 40, radius * 0.8, radius);
    }

    // Musical notation floating
    p.fill(255, 255, 200, 120);
    p.textSize(20);
    let musicalSymbols = ['♪', '♫', '♬', '♩', '♭', '♯'];
    for(let i = 0; i < 8; i++) {
      let x = 50 + (i * 45) + p.sin(time + i) * 10;
      let y = 400 + p.sin(time * 0.8 + i * 0.5) * 20;
      p.text(musicalSymbols[i % musicalSymbols.length], x, y);
    }

    // Piano keys at bottom
    p.fill(255);
    for(let i = 0; i < 7; i++) {
      p.rect(i * 57, 550, 55, 50);
    }
    p.fill(0);
    for(let i = 0; i < 6; i++) {
      if(i !== 2) {
        p.rect(i * 57 + 35, 550, 22, 30);
      }
    }

    // Interactive sound waves on mouse movement
    if(p.mouseX > 0 && p.mouseX < 400 && p.mouseY > 0 && p.mouseY < 600) {
      p.stroke(184, 115, 51, 80);
      p.strokeWeight(3);
      p.noFill();
      for(let i = 1; i < 4; i++) {
        let radius = i * 25 + p.sin(time * 6) * 8;
        p.ellipse(p.mouseX, p.mouseY, radius, radius);
      }
    }

    p.noStroke();
  };
}

