function sketch(p) {
  let citizen;
  let bloom;
  let biscuitTin;
  let pubPatrons = [];
  let heroicSymbols = [];
  let particles = [];
  let dog;

  p.setup = function() {
    p.createCanvas(400, 600);

    // Initialize characters
    citizen = {
      x: 200,
      y: 220,
      eyeSize: 80,
      rage: 0,
      armAngle: 0
    };

    bloom = {
      x: 320,
      y: 350,
      fear: 0,
      backing: false
    };

    biscuitTin = {
      x: 180,
      y: 280,
      vx: 3,
      vy: 2,
      rotation: 0,
      thrown: false
    };

    dog = {
      x: 100,
      y: 450,
      bark: 0
    };

    // Create pub patrons
    for (let i = 0; i < 6; i++) {
      pubPatrons.push({
        x: p.random(50, 150),
        y: p.random(380, 480),
        sway: p.random(0, p.TWO_PI),
        drunkness: p.random(0.5, 2)
      });
    }

    // Create heroic symbols (floating, fading)
    for (let i = 0; i < 8; i++) {
      heroicSymbols.push({
        x: p.random(400),
        y: p.random(200),
        type: p.floor(p.random(3)),
        alpha: p.random(30, 80),
        drift: p.random(-0.5, 0.5)
      });
    }
  };

  p.draw = function() {
    // Pub atmosphere background
    p.background(62, 39, 35);

    // Sawdust floor
    p.fill(139, 117, 82, 80);
    p.rect(0, 400, 400, 200);
    for (let i = 0; i < 50; i++) {
      p.fill(160, 140, 100, 60);
      p.circle(p.random(400), p.random(400, 600), p.random(2, 4));
    }

    // Floating heroic symbols (mock-epic overlay)
    p.push();
    for (let symbol of heroicSymbols) {
      p.push();
      p.translate(symbol.x, symbol.y);
      p.fill(34, 139, 34, symbol.alpha);
      p.strokeWeight(2);
      p.stroke(255, 215, 0, symbol.alpha);

      if (symbol.type === 0) {
        // Celtic knot
        p.noFill();
        p.circle(0, 0, 30);
        p.circle(-10, 0, 15);
        p.circle(10, 0, 15);
      } else if (symbol.type === 1) {
        // Spear
        p.line(0, -20, 0, 20);
        p.triangle(0, -20, -5, -10, 5, -10);
      } else {
        // Harp
        p.arc(0, 0, 25, 40, 0, p.PI);
        for (let j = 0; j < 4; j++) {
          p.line(-8, -15 + j * 8, 8, -15 + j * 8);
        }
      }
      p.pop();

      symbol.y += symbol.drift;
      symbol.x += p.sin(p.millis() * 0.001 + symbol.x) * 0.3;
      symbol.alpha += p.sin(p.millis() * 0.002 + symbol.y) * 0.5;

      if (symbol.y > 600) symbol.y = -50;
    }
    p.pop();

    // Pub patrons
    for (let patron of pubPatrons) {
      p.push();
      p.translate(patron.x, patron.y);
      p.rotate(p.sin(patron.sway + p.millis() * 0.001) * 0.1 * patron.drunkness);

      // Body
      p.fill(80, 60, 40);
      p.rect(-8, -15, 16, 30);

      // Head
      p.fill(200, 160, 120);
      p.circle(0, -25, 16);

      // Pint glass
      p.fill(255, 215, 0, 150);
      p.rect(10, -5, 8, 15);
      p.fill(139, 69, 19);
      p.rect(10, -3, 8, 8);

      p.pop();

      patron.sway += 0.01;
    }

    // The Citizen (enormous, cyclops-like)
    p.push();
    p.translate(citizen.x, citizen.y);

    // Rage intensity based on mouse proximity
    let mouseDistance = p.dist(p.mouseX, p.mouseY, citizen.x, citizen.y);
    citizen.rage = p.map(mouseDistance, 0, 200, 2, 0.2);
    citizen.rage = p.constrain(citizen.rage, 0.2, 2);

    // Giant body
    p.scale(citizen.rage);
    p.fill(34, 139, 34);
    p.stroke(255, 215, 0);
    p.strokeWeight(3);
    p.rect(-40, 0, 80, 100);

    // Celtic symbols on clothing
    p.fill(255, 215, 0);
    p.noStroke();
    p.circle(-20, 30, 8);
    p.circle(20, 30, 8);
    p.triangle(0, 50, -10, 70, 10, 70);

    // Arms
    p.stroke(34, 139, 34);
    p.strokeWeight(12);

    // Throwing arm
    citizen.armAngle = p.sin(p.millis() * 0.01) * 0.3 - 0.5;
    p.push();
    p.translate(-30, 20);
    p.rotate(citizen.armAngle);
    p.line(0, 0, -30, -10);
    p.pop();

    // Other arm
    p.push();
    p.translate(30, 20);
    p.line(0, 0, 20, 15);
    p.pop();

    // Giant head
    p.fill(160, 80, 80);
    p.stroke(34, 139, 34);
    p.strokeWeight(2);
    p.circle(0, -30, 60);

    // Single enormous eye (nationalism as blindness)
    p.fill(255);
    p.circle(0, -35, citizen.eyeSize);
    p.fill(255, 0, 0);
    p.circle(0, -35, citizen.eyeSize * 0.6);
    p.fill(0);
    p.circle(0, -35, citizen.eyeSize * 0.3);

    // Eye follows mouse (menacingly)
    let eyeX = p.map(p.mouseX, 0, 400, -5, 5);
    let eyeY = p.map(p.mouseY, 0, 600, -5, 5);
    p.fill(255);
    p.circle(eyeX, -35 + eyeY, 8);

    // Mouth (shouting)
    p.fill(0);
    p.ellipse(0, -10, 20, 30);

    p.pop();

    // Bloom (small but dignified)
    p.push();
    p.translate(bloom.x, bloom.y);

    // Backing away animation
    if (citizen.rage > 1.5) {
      bloom.backing = true;
      bloom.x += 0.5;
    }

    // Body
    p.fill(40, 40, 80);
    p.rect(-6, 0, 12, 25);

    // Head
    p.fill(200, 160, 120);
    p.circle(0, -8, 12);

    // Glasses (suggesting Jewishness subtly)
    p.noFill();
    p.stroke(0);
    p.strokeWeight(1);
    p.circle(-3, -8, 6);
    p.circle(3, -8, 6);
    p.line(-0.5, -8, 0.5, -8);

    // Expression (fear but moral certainty)
    p.noStroke();
    p.fill(0);
    p.circle(-2, -9, 1);
    p.circle(2, -9, 1);
    p.line(-2, -5, 2, -5);

    // Hand raised reasonably
    p.stroke(200, 160, 120);
    p.strokeWeight(3);
    p.line(6, 5, 12, -5);

    p.pop();

    // Biscuit tin in flight
    p.push();
    p.translate(biscuitTin.x, biscuitTin.y);
    p.rotate(biscuitTin.rotation);

    if (citizen.rage > 1.5 && !biscuitTin.thrown) {
      biscuitTin.thrown = true;
    }

    if (biscuitTin.thrown) {
      biscuitTin.x += biscuitTin.vx;
      biscuitTin.y += biscuitTin.vy;
      biscuitTin.rotation += 0.2;
      biscuitTin.vy += 0.1; // gravity

      // Reset if off screen
      if (biscuitTin.x > 450) {
        biscuitTin.x = 180;
        biscuitTin.y = 280;
        biscuitTin.vx = 3;
        biscuitTin.vy = 2;
        biscuitTin.rotation = 0;
        biscuitTin.thrown = false;
      }
    }

    p.fill(200, 200, 200);
    p.stroke(150);
    p.strokeWeight(1);
    p.rect(-8, -3, 16, 6, 2);
    p.fill(255, 0, 0);
    p.text("BISCUITS", -15, 0);
    p.pop();

    // Dog (Garryowen) barking
    p.push();
    p.translate(dog.x, dog.y);

    dog.bark = p.sin(p.millis() * 0.02) * 10;

