    // Initialize wave points
    for (let i = 0; i < 50; i++) {
      waves.push({
        x: i * 10,
        baseY: 480 + p.random(-20, 20),
        offset: p.random(p.TWO_PI)
      });
    }

    // Create initial fireworks
    for (let i = 0; i < 3; i++) {
      createFirework();
    }
  };

  p.draw = function() {
    time += 0.01;

    // Create split composition background
    drawSky();
    drawBeach();
    drawChurch();
    drawGerty();
    drawBloom();
    drawWaves();
    updateFireworks();
    drawFireworks();

    // Subtle interaction - brightness responds to mouse position
    let proximity = p.dist(p.mouseX, p.mouseY, 200, 300);
    let brightness = p.map(proximity, 0, 300, 1.5, 0.8);
    p.tint(255 * brightness);
    p.noTint();
  };

  function drawSky() {
