      // Left side - romantic purple
      p.stroke(120 + p.sin(time) * 20, 80 + p.sin(time + 1) * 15, 180 + p.sin(time + 2) * 30, leftAlpha * 255);
      p.line(0, y, 200, y);

      // Right side - realistic blue-gray
      p.stroke(80 + p.sin(time * 0.5) * 10, 90 + p.sin(time * 0.7) * 10, 120 + p.sin(time) * 15, rightAlpha * 255);
      p.line(200, y, 400, y);
    }
  };

  function drawBeach() {
    // Sand gradient
    for (let y = 350; y < 600; y++) {
