    p.rect(50, 280, 80, 70);
    p.triangle(50, 280, 90, 240, 130, 280);

    // Virgin Mary window - soft glow
    p.fill(200, 200, 255, 100 + p.sin(time * 2) * 50);
    p.ellipse(90, 310, 15, 20);
  };

  function drawGerty() {
    p.pushMatrix();
    p.translate(90, 360);

    // Romantic soft focus effect
    p.drawingContext.filter = 'blur(1px)';

    // Gerty's figure - romanticized
    p.fill(255, 200, 220, gertyAlpha);
    p.noStroke();
    p.ellipse(0, -20, 25, 30); // head

