    p.ellipse(-15, 0, 8, 25);
    p.ellipse(15, 5, 8, 25);

    p.drawingContext.filter = 'none';
    p.popMatrix();

    // Walking away figure with limp - tender portrayal
    if (p.sin(time * 0.5) > 0) {
      p.pushMatrix();
      p.translate(150, 420);
      p.fill(180, 150, 200, 180);
      p.noStroke();
      p.ellipse(0, -15, 20, 25); // head
      p.ellipse(0, 5, 25, 40); // body

      // Legs showing limp - one shorter
      p.fill(255, 200, 220, 180);
      p.ellipse(-5, 25, 6, 20); // good leg
      p.ellipse(5, 28, 6, 14); // shorter leg
      p.popMatrix();
    }
  };

  function drawBloom() {
    p.pushMatrix();
    p.translate(320, 390);

    // Realistic rendering - sharper, more detailed
