    p.ellipse(0, 10, 35, 50);

    // Arms - one positioned suggestively but tastefully
    p.fill(200, 180, 160, bloomAlpha);
    p.ellipse(-12, 5, 7, 20);
    p.ellipse(8, 15, 7, 18);

    p.popMatrix();
  };

  function drawWaves() {
    p.stroke(100, 120, 150, 150);
    p.strokeWeight(2);
    p.noFill();

    p.beginShape();
    for (let i = 0; i < waves.length; i++) {
      let wave = waves[i];
      let y = wave.baseY + p.sin(time * 3 + wave.offset) * 15;
      p.vertex(wave.x, y);
    }
    p.endShape();

    // Foam
    p.stroke(255, 255, 255, 100);
    p.strokeWeight(1);
    p.beginShape();
    for (let i = 0; i < waves.length; i++) {
      let wave = waves[i];
      let y = wave.baseY + p.sin(time * 3 + wave.offset + 0.5) * 12 + 5;
      p.vertex(wave.x, y);
    }
    p.endShape();
  };

  function createFirework() {
    fireworks.push({
      x: p.random(100, 300),
      y: p.random(50, 200),
      particles: [],
      life: 100,
      maxLife: 100
    });

    let fw = fireworks[fireworks.length - 1];
    for (let i = 0; i < 12; i++) {
