        x: fw.x,
        y: fw.y,
        vx: p.cos(i * p.TWO_PI / 12) * p.random(2, 5),
        vy: p.sin(i * p.TWO_PI / 12) * p.random(2, 5),
        life: p.random(30, 60)
      });
    }
  };

  function updateFireworks() {
    for (let i = fireworks.length - 1; i >= 0; i--) {
      let fw = fireworks[i];
      fw.life--;

      for (let j = fw.particles.length - 1; j >= 0; j--) {
        let p = fw.particles[j];
        p.x += p.vx;
        p.y += p.vy;
        p.vy += 0.1; // gravity
        p.life--;

        if (p.life <= 0) {
          fw.particles.splice(j, 1);
        }
      }

      if (fw.life <= 0 || fw.particles.length === 0) {
        fireworks.splice(i, 1);
      }
    }

    // Create new fireworks periodically
    if (p.random() < 0.02) {
      createFirework();
    }
  };

  function drawFireworks() {
    for (let fw of fireworks) {
      for (let particle of fw.particles) {
