        if (distToGerty < 100) {
          gertyAlpha = p.min(255, gertyAlpha + 2);
        }
        if (distToBloom < 100) {
          bloomAlpha = p.min(255, bloomAlpha + 2);
        }
      }
    }

    // Fade effect
    gertyAlpha = p.max(180, gertyAlpha - 0.5);
    bloomAlpha = p.max(180, bloomAlpha - 0.5);
  };
}

