function sketch(p) {
  let streams = [];
  let memoryFragments = [];
  let yesTexts = [];
  let time = 0;
  let bodyPoints = [];
  let flowField = [];
  let cols, rows;
  let scl = 20;

  p.setup = function() {
    p.createCanvas(400, 600);
    p.colorMode(p.HSB, 360, 100, 100, 100);

    cols = p.floor(p.width / scl);
    rows = p.floor(p.height / scl);

    // Initialize body silhouette points
    for (let i = 0; i < 50; i++) {
      bodyPoints.push({
        x: p.random(120, 280),
        y: p.random(200, 400),
        baseX: p.random(120, 280),
        baseY: p.random(200, 400),
        offset: p.random(p.TWO_PI)
      });
    }

    // Initialize consciousness streams
    for (let i = 0; i < 30; i++) {
      streams.push({
        x: p.random(p.width),
        y: p.random(p.height),
        vx: p.random(-1, 1),
        vy: p.random(-1, 1),
        size: p.random(2, 8),
        hue: p.random(15, 45),
        alpha: p.random(30, 80)
      });
    }

    // Initialize memory fragments
    for (let i = 0; i < 15; i++) {
      memoryFragments.push({
        x: p.random(p.width),
        y: p.random(p.height),
        size: p.random(20, 60),
        rotation: 0,
        type: p.floor(p.random(4)),
        hue: p.random(300, 360),
        alpha: p.random(20, 60),
        speed: p.random(0.002, 0.008)
      });
    }

    // Initialize YES texts
    for (let i = 0; i < 8; i++) {
      yesTexts.push({
        x: p.random(50, 350),
        y: p.random(100, 500),
        size: p.random(12, 36),
        alpha: p.random(40, 90),
        pulse: p.random(p.TWO_PI),
        drift: p.random(0.01, 0.03)
      });
    }
  };

  p.draw = function() {
    // Flowing background gradient
    for (let y = 0; y < p.height; y++) {
      let inter = p.map(y, 0, p.height, 0, 1);
      let c = p.lerpColor(
        p.color(25, 60, 95),  // warm peach
        p.color(340, 40, 80), // soft pink
        inter
      );
      p.stroke(c);
      p.line(0, y, p.width, y);
    }

    time += 0.01;

    // Create flow field for organic movement
    for (let y = 0; y < rows; y++) {
      for (let x = 0; x < cols; x++) {
        let index = x + y * cols;
        let angle = p.noise(x * 0.1, y * 0.1, time * 0.5) * p.TWO_PI * 2;
        flowField[index] = p.createVector(p.cos(angle), p.sin(angle));
      }
    }

    // Draw body silhouette with flowing edges
    p.fill(15, 40, 85, 60);
    p.noStroke();
    p.beginShape();
    for (let i = 0; i < bodyPoints.length; i++) {
      let bp = bodyPoints[i];
      bp.x = bp.baseX + p.sin(time + bp.offset) * 15;
      bp.y = bp.baseY + p.cos(time * 0.7 + bp.offset) * 10;

      if (i === 0) {
        p.vertex(bp.x, bp.y);
      } else {
        let prevBp = bodyPoints[i - 1];
        p.bezierVertex(
          prevBp.x + p.random(-10, 10),
          prevBp.y + p.random(-10, 10),
          bp.x + p.random(-10, 10),
          bp.y + p.random(-10, 10),
          bp.x,
          bp.y
        );
      }
    }
    p.endShape(p.CLOSE);

    // Draw consciousness streams
    for (let i = 0; i < streams.length; i++) {
      let stream = streams[i];

      // Follow flow field
      let col = p.floor(p.constrain(stream.x / scl, 0, cols - 1));
      let row = p.floor(p.constrain(stream.y / scl, 0, rows - 1));
      let index = col + row * cols;
      if (flowField[index]) {
        stream.vx += flowField[index].x * 0.01;
        stream.vy += flowField[index].y * 0.01;
      }

      stream.x += stream.vx;
      stream.y += stream.vy;

      // Wrap around edges
      if (stream.x < 0) stream.x = p.width;
      if (stream.x > p.width) stream.x = 0;
      if (stream.y < 0) stream.y = p.height;
      if (stream.y > p.height) stream.y = 0;

      // Draw stream particle
      p.fill(stream.hue, 70, 90, stream.alpha);
      p.noStroke();
      p.ellipse(stream.x, stream.y, stream.size);

      // Add trailing effect
      p.fill(stream.hue, 50, 95, stream.alpha * 0.3);
      p.ellipse(stream.x - stream.vx * 5, stream.y - stream.vy * 5, stream.size * 0.6);
    }

    // Draw memory fragments
    for (let fragment of memoryFragments) {
      p.pushMatrix();
      p.translate(fragment.x, fragment.y);
      p.rotate(fragment.rotation);

      fragment.rotation += fragment.speed;
      fragment.x += p.sin(time * fragment.speed * 20) * 0.5;
      fragment.y += p.cos(time * fragment.speed * 15) * 0.3;

      p.fill(fragment.hue, 80, 70, fragment.alpha);
      p.noStroke();

      // Different memory shapes
      if (fragment.type === 0) {
        // Howth Head (mountain-like)
        p.triangle(-fragment.size/2, fragment.size/4, 0, -fragment.size/2, fragment.size/2, fragment.size/4);
      } else if (fragment.type === 1) {
        // Flower (rhododendrons)
        for (let i = 0; i < 6; i++) {
          let angle = i * p.PI / 3;
          let x = p.cos(angle) * fragment.size/3;
          let y = p.sin(angle) * fragment.size/3;
          p.ellipse(x, y, fragment.size/4);
        }
      } else if (fragment.type === 2) {
        // Heart shape (love memories)
        p.bezier(-fragment.size/4, 0, -fragment.size/2, -fragment.size/3, 
                fragment.size/2, -fragment.size/3, fragment.size/4, 0);
      } else {
        // Abstract memory blob
        p.ellipse(0, 0, fragment.size, fragment.size * 0.7);
      }

      p.popMatrix();
    }

    // Draw YES texts with pulsing
    p.textAlign(p.CENTER, p.CENTER);
    for (let yes of yesTexts) {
      let pulsSize = yes.size + p.sin(time * 2 + yes.pulse) * 8;
      let pulsAlpha = yes.alpha + p.sin(time * 3 + yes.pulse) * 20;

      yes.x += p.sin(time * yes.drift) * 0.5;
      yes.y += p.cos(time * yes.drift * 0.8) * 0.3;

      p.fill(350, 30, 95, pulsAlpha);
      p.textSize(pulsSize);
      p.text("yes", yes.x, yes.y);
    }

    // Large central YES that grows with mouse proximity
    let centerX = p.width / 2;
    let centerY = p.height * 0.75;
    let mouseDistance = p.dist(p.mouseX, p.mouseY, centerX, centerY);
    let centerSize = p.map(mouseDistance, 0, 200, 80, 40);
    centerSize = p.constrain(centerSize, 40, 80);
    centerSize += p.sin(time * 4) * 10;

    p.fill(0, 0, 100, 90);
    p.textSize(centerSize);
    p.text("YES", centerX, centerY);

    // Subtle flowing particles around the YES
    for (let i = 0; i < 10; i++) {
      let angle = (time * 2 + i * p.TWO_PI / 10) % p.TWO_PI;
      let radius = 60 + p.sin(time * 3 + i) * 20;
      let x = centerX + p.cos(angle) * radius;
      let y = centerY + p.sin(angle) * radius;

      p.fill(15, 60, 95, 40);
      p.noStroke();
      p.ellipse(x, y, 4);
    }
  };
}

