function sketch(p) {
  let cities = [];
  let manuscripts = [];
  let warParticles = [];
  let pen;
  let signatureAlpha = 0;
  let yearProgress = 0;

  p.setup = function() {
    p.createCanvas(400, 600);

    // Initialize cities
    cities = [
      { name: "Trieste", x: 220, y: 350, year: 1914, active: false },
      { name: "Zurich", x: 180, y: 280, year: 1915, active: false },
      { name: "Paris", x: 140, y: 260, year: 1920, active: false }
    ];

    // Initialize manuscripts
    for(let i = 0; i < 150; i++) {
      manuscripts.push({
        x: p.random(50, 350),
        y: p.random(400, 580),
        size: p.random(2, 8),
        alpha: p.random(50, 200),
        drift: p.random(-0.5, 0.5)
      });
    }

    // Initialize war particles
    for(let i = 0; i < 80; i++) {
      warParticles.push({
        x: p.random(400),
        y: p.random(100, 300),
        vx: p.random(-1, 1),
        vy: p.random(-0.5, 0.5),
        size: p.random(1, 4),
        alpha: p.random(20, 80)
      });
    }

    pen = {
      x: 200,
      y: 520,
      angle: 0
    };
  };

  p.draw = function() {
    // Sepia background
    p.background(245, 235, 215);

    // Map outline
    p.stroke(101, 67, 33, 120);
    p.strokeWeight(2);
    p.noFill();
    p.beginShape();
    p.vertex(80, 200);
    p.bezierVertex(120, 180, 200, 190, 280, 220);
    p.bezierVertex(320, 240, 340, 280, 320, 320);
    p.bezierVertex(300, 360, 250, 380, 200, 370);
    p.bezierVertex(150, 360, 100, 320, 80, 280);
    p.bezierVertex(60, 240, 70, 220, 80, 200);
    p.endShape();

    // Time progression
    yearProgress = (p.sin(p.millis() * 0.0008) + 1) * 0.5;
    let currentYear = 1914 + yearProgress * 7;

    // War background
    drawWarBackground();

    // Cities and writing scenes
    for(let i = 0; i < cities.length; i++) {
      let city = cities[i];
      let isActive = currentYear >= city.year && (i === cities.length - 1 || currentYear < cities[i + 1].year);

      // City marker
      p.fill(139, 69, 19, isActive ? 255 : 100);
      p.noStroke();
      p.ellipse(city.x, city.y, 8, 8);

      // Writing figure
      if(isActive) {
        drawWritingFigure(city.x, city.y - 30, i);
      }

      // City glow
      if(isActive) {
        p.fill(218, 165, 32, 60);
        p.ellipse(city.x, city.y, 25, 25);
      }
    }

    // Manuscript accumulation
    drawManuscripts();

    // Signature formation
    if(currentYear > 1920.5) {
      signatureAlpha = p.min(255, signatureAlpha + 3);
      drawSignature();
    }

    // Pen movement
    pen.angle += 0.02;
    pen.x = 200 + p.cos(pen.angle) * 15;

    if(signatureAlpha > 100) {
      drawPen();
    }

    // Aging effect
    drawAgingOverlay();
  };

  function drawWarBackground() {
    // Subtle war suggestions
    for(let particle of warParticles) {
      particle.x += particle.vx;
      particle.y += particle.vy;

      if(particle.x < 0 || particle.x > 400) particle.vx *= -1;
      if(particle.y < 100 || particle.y > 300) particle.vy *= -1;

      p.fill(101, 67, 33, particle.alpha * 0.3);
      p.noStroke();
      p.ellipse(particle.x, particle.y, particle.size, particle.size);
    }

    // Distant explosions
    let explosionIntensity = p.noise(p.millis() * 0.01) * 100;
    if(explosionIntensity > 80) {
      p.fill(139, 69, 19, 20);
      p.ellipse(p.random(400), p.random(100, 200), 30, 30);
    }
  };

  function drawWritingFigure(x, y, cityIndex) {
    p.push();
    p.translate(x, y);

    // Figure aging
    let ageOffset = cityIndex * 2;

    // Head
    p.fill(160, 120, 80);
    p.noStroke();
    p.ellipse(0, 0, 12 + ageOffset, 12 + ageOffset);

    // Body hunched over writing
    p.stroke(101, 67, 33, 180);
    p.strokeWeight(3);
    p.line(0, 6, -5, 20);
    p.line(-5, 20, -15, 25); // writing arm

    // Manuscript
    p.fill(245, 235, 215, 200);
    p.noStroke();
    p.rect(-20, 20, 15, 10);

    // Writing motion
    let writingOffset = p.sin(p.millis() * 0.05) * 2;
    p.fill(101, 67, 33);
    p.ellipse(-15 + writingOffset, 25, 2, 2);

    p.pop();
  };

  function drawManuscripts() {
    for(let ms of manuscripts) {
      ms.y += ms.drift * 0.2;
      if(ms.y < 400) ms.y = 580;
      if(ms.y > 580) ms.y = 400;

      let fadeIn = p.map(yearProgress, 0, 1, 50, ms.alpha);
      p.fill(101, 67, 33, fadeIn);
      p.noStroke();
      p.rect(ms.x, ms.y, ms.size, ms.size * 0.6);

      // Text lines
      if(ms.size > 4) {
        p.stroke(101, 67, 33, fadeIn * 0.8);
        p.strokeWeight(0.5);
        for(let i = 0; i < 3; i++) {
          p.line(ms.x + 1, ms.y + 1 + i * 1.5, ms.x + ms.size - 1, ms.y + 1 + i * 1.5);
        }
      }
    }
  };

  function drawSignature() {
    p.push();
    p.translate(200, 520);

    // Signature background
    p.fill(245, 235, 215, signatureAlpha * 0.9);
    p.noStroke();
    p.rect(-120, -20, 240, 40);

    // City names in cursive style
    p.fill(101, 67, 33, signatureAlpha);
    p.textAlign(p.CENTER);
    p.textSize(16);

    let dashAlpha = p.map(signatureAlpha, 100, 255, 0, 255);

    // Simulate handwritten signature
    let jitter = p.noise(p.millis() * 0.01) * 0.5;

    p.push();
    p.translate(jitter, jitter);
    // Trieste
    drawHandwrittenText("Trieste", -60, -5, dashAlpha);
    // Dash
    p.stroke(101, 67, 33, dashAlpha);
    p.strokeWeight(2);
    p.line(-25, -5, -5, -5);
    // Zurich
    drawHandwrittenText("Zurich", 0, -5, dashAlpha);
    // Dash
    p.line(25, -5, 45, -5);
    // Paris
    drawHandwrittenText("Paris", 70, -5, dashAlpha);

    // Years
    p.textSize(12);
    drawHandwrittenText("1914-1921", 0, 15, dashAlpha);
    p.pop();

    p.pop();
  };

  function drawHandwrittenText(text, x, y, alpha) {
    p.fill(101, 67, 33, alpha);
    p.noStroke();

    // Add slight irregularity to simulate handwriting
    let offset = p.noise(p.millis() * 0.001 + x) * 1;
    p.text(text, x + offset, y);
  };

  function drawPen() {
    p.push();
    p.translate(pen.x, pen.y);
    p.rotate(p.PI / 4);

    // Pen body
    p.fill(139, 69, 19, signatureAlpha);
    p.noStroke();
    p.rect(-15, -2, 30, 4);

    // Pen tip
    p.fill(101, 67, 33, signatureAlpha);
    p.triangle(15, -2, 15, 2, 20, 0);

    // Ink flow
    if(p.random() > 0.7) {
      p.fill(101, 67, 33, 100);
      p.ellipse(22, 0, 2, 2);
    }

    p.pop();
  };

  function drawAgingOverlay() {
    // Paper texture
    for(let i = 0; i < 100; i++) {
      p.fill(101, 67, 33, p.random(5, 15));
      p.noStroke();
      p.ellipse(p.random(400), p.random(600), 1, 1);
    }

    // Sepia vignette
    for(let i = 0; i < 50; i++) {
      let alpha = p.map(i, 0, 50, 20, 0);
      p.stroke(101, 67, 33, alpha);
      p.strokeWeight(2);
      p.noFill();
      p.rect(i, i, 400 - i * 2, 600 - i * 2);
    }
  };
}

