function sketch(p) {
  let particles = [];
  let words = [];
  let riverPoints = [];
  let landmarks = [];

  p.setup = function() {
    p.createCanvas(400, 600);
    p.colorMode(p.HSB, 360, 100, 100, 100);

    // Initialize river curve points
    for (let i = 0; i < 50; i++) {
      riverPoints.push({
        x: p.map(i, 0, 49, -50, 450),
        y: p.map(i, 0, 49, 100, 500),
        baseY: p.map(i, 0, 49, 100, 500),
        offset: p.random(p.TWO_PI)
      });
    }

    // Initialize word particles
    let textFragments = [
      'riverrun', 'bababadalgharaghtak', 'Eve and Adams', 'Howth Castle',
      'commodius vicus', 'recirculation', 'wake', 'Anna Livia',
      'swerve of shore', 'bend of bay', 'Finnegans', 'night',
      'dream', 'flowing', 'eternal', 'cycle', 'beginning'
    ];

    for (let i = 0; i < 80; i++) {
      words.push({
        text: p.random(textFragments),
        x: p.random(400),
        y: p.random(600),
        vx: p.random(-0.5, 0.5),
        vy: p.random(-0.3, 0.3),
        alpha: p.random(30, 80),
        size: p.random(8, 16),
        dissolve: p.random(100)
      });
    }

    // Initialize water particles
    for (let i = 0; i < 200; i++) {
      particles.push({
        x: p.random(400),
        y: p.random(200, 500),
        vx: p.random(-1, 2),
        vy: p.random(-0.5, 0.5),
        size: p.random(2, 6),
        hue: p.random(200, 260),
        alpha: p.random(20, 60)
      });
    }

    // Initialize landmarks
    landmarks.push({
      name: "Eve and Adams",
      x: 80,
      y: 200,
      type: "church"
    });

    landmarks.push({
      name: "Howth Castle",
      x: 320,
      y: 150,
      type: "castle"
    });
  };

  p.draw = function() {
    // Night sky background with flowing gradient
    for (let y = 0; y < p.height; y++) {
      let inter = p.map(y, 0, p.height, 0, 1);
      let c = p.lerpColor(p.color(240, 60, 15), p.color(200, 80, 5), inter);
      p.stroke(c);
      p.line(0, y, p.width, y);
    }

    // Floating stars that merge with river
    p.fill(60, 30, 100, 40);
    p.noStroke();
    for (let i = 0; i < 30; i++) {
      let x = (p.noise(i * 0.1, p.frameCount * 0.005) * p.width);
      let y = (p.noise(i * 0.1 + 100, p.frameCount * 0.005) * p.height * 0.4);
      p.circle(x, y, 3);
    }

    // Update and animate river points
    for (let i = 0; i < riverPoints.length; i++) {
      let point = riverPoints[i];
      point.y = point.baseY + p.sin(p.frameCount * 0.01 + point.offset) * 30;
    }

    // Draw river as flowing curve made of text particles
    p.strokeWeight(2);
    for (let layer = 0; layer < 3; layer++) {
      p.stroke(220, 60, 30 + layer * 20, 60 - layer * 15);
      p.noFill();
      p.beginShape();
      for (let i = 0; i < riverPoints.length; i++) {
        let point = riverPoints[i];
        let offsetY = layer * 15;
        p.curveVertex(point.x, point.y + offsetY);
      }
      p.endShape();
    }

    // Update and draw word particles dissolving into river
    p.textAlign(p.CENTER, p.CENTER);
    for (let word of words) {
      word.x += word.vx;
      word.y += word.vy;

      // Attract words toward river
      let riverY = getRiverY(word.x);
      if (riverY > 0) {
        let attraction = (riverY - word.y) * 0.001;
        word.vy += attraction;
      }

      // Dissolve effect
      word.dissolve += p.random(-2, 1);
      word.dissolve = p.constrain(word.dissolve, 0, 100);

      // Wrap around screen
      if (word.x > p.width + 50) word.x = -50;
      if (word.x < -50) word.x = p.width + 50;
      if (word.y > p.height + 50) word.y = -50;
      if (word.y < -50) word.y = p.height + 50;

      // Draw word with dissolve effect
      p.textSize(word.size);
      let textAlpha = p.map(word.dissolve, 0, 100, 0, word.alpha);
      p.fill(180, 40, 90, textAlpha);
      p.noStroke();

      // Portmanteau effect - merge letters
      let displayText = word.text;
      if (word.dissolve < 50) {
        let chars = displayText.split('');
        displayText = '';
        for (let i = 0; i < chars.length; i++) {
          if (p.random(100) > word.dissolve) {
            displayText += chars[i];
          } else {
            displayText += p.random(['~', '∞', '○', '◊']);
          }
        }
      }

      p.text(displayText, word.x, word.y);
    }

    // Update and draw water particles
    for (let particle of particles) {
      particle.x += particle.vx;
      particle.y += particle.vy;

      // Flow along river
      let riverY = getRiverY(particle.x);
      if (riverY > 0 && p.abs(particle.y - riverY) < 100) {
        particle.vx += 0.02;
        particle.vy += (riverY - particle.y) * 0.001;
      }

      // Wrap around
      if (particle.x > p.width) particle.x = 0;
      if (particle.y > p.height) particle.y = 0;
      if (particle.y < 0) particle.y = p.height;

      p.fill(particle.hue, 60, 80, particle.alpha);
      p.noStroke();
      p.circle(particle.x, particle.y, particle.size);
    }

    // Draw dissolving landmarks
    p.fill(240, 40, 60, 40);
    p.noStroke();
    for (let landmark of landmarks) {
      let shimmer = p.sin(p.frameCount * 0.02) * 10;
      if (landmark.type === "church") {
        // Simple church shape
        p.rect(landmark.x - 10, landmark.y, 20, 30);
        p.triangle(landmark.x - 12, landmark.y, landmark.x + 12, landmark.y, landmark.x, landmark.y - 15);
      } else if (landmark.type === "castle") {
        // Simple castle shape
        p.rect(landmark.x - 15, landmark.y, 30, 25);
        p.rect(landmark.x - 5, landmark.y - 10, 10, 15);
      }
    }

    // Circular "riverrun" text at top and bottom
    let time = p.frameCount * 0.01;
    drawCircularText("riverrun", 200, 80, 60, time);
    drawCircularText("riverrun", 200, 520, 60, -time);

    // Interactive mouse effect - ripples in the river
    if (p.mouseX > 0 && p.mouseX < p.width && p.mouseY > 0 && p.mouseY < p.height) {
      p.noFill();
      p.stroke(200, 80, 100, 30);
      p.strokeWeight(1);
      let rippleSize = p.sin(p.frameCount * 0.1) * 20 + 40;
      p.circle(p.mouseX, p.mouseY, rippleSize);
      p.circle(p.mouseX, p.mouseY, rippleSize * 1.5);
    }
  };

  function getRiverY(x) {
    if (x < 0 || x > 400) return -1;
    let index = p.map(x, 0, 400, 0, riverPoints.length - 1);
    let i = p.floor(index);
    let fraction = index - i;

    if (i >= riverPoints.length - 1) return riverPoints[riverPoints.length - 1].y;

    return p.lerp(riverPoints[i].y, riverPoints[i + 1].y, fraction);
  }

  function drawCircularText(text, cx, cy, radius, rotation) {
    p.push();
    p.translate(cx, cy);
    p.rotate(rotation);

    let angleStep = p.TWO_PI / text.length;
    p.textAlign(p.CENTER, p.CENTER);
    p.textSize(14);
    p.fill(60, 60, 100, 70);
    p.noStroke();

    for (let i = 0; i < text.length; i++) {
      p.push();
      p.rotate(angleStep * i);
      p.translate(0, -radius);
      p.text(text[i], 0, 0);
      p.pop();
    }

    p.pop();
  }
}

