function sketch(p) {
  let tower;
  let figure;
  let key;
  let clouds = [];
  let keyFloat = 0;
  let doorAngle = 0;
  let figureOpacity = 200;
  let ambiguousMotion = 0;

  p.setup = function() {
    p.createCanvas(400, 600);

    // Initialize clouds
    for (let i = 0; i < 8; i++) {
      clouds.push({
        x: p.random(p.width),
        y: p.random(50, 200),
        size: p.random(30, 80),
        speed: p.random(0.2, 0.8)
      });
    }
  };

  p.draw = function() {
    // Grey Irish sky gradient
    for (let i = 0; i <= p.height; i++) {
      let inter = p.map(i, 0, p.height, 0, 1);
      let c = p.lerpColor(p.color(140, 150, 160), p.color(80, 90, 100), inter);
      p.stroke(c);
      p.line(0, i, p.width, i);
    }

    // Animated clouds
    p.noStroke();
    for (let cloud of clouds) {
      p.fill(160, 170, 180, 120);
      p.ellipse(cloud.x, cloud.y, cloud.size, cloud.size * 0.6);
      cloud.x += cloud.speed;
      if (cloud.x > p.width + cloud.size) cloud.x = -cloud.size;
    }

    // Sea at bottom
    p.fill(60, 80, 100);
    p.rect(0, p.height - 80, p.width, 80);

    // Wave animation
    p.stroke(80, 100, 120);
    p.strokeWeight(2);
    for (let x = 0; x < p.width; x += 20) {
      let waveY = p.height - 60 + p.sin((x + p.frameCount) * 0.02) * 8;
      p.line(x, waveY, x + 10, waveY);
    }

    // Martello Tower
    p.noStroke();
    p.fill(90, 95, 105);

