    let towerX = p.width * 0.6;
    let towerBottom = p.height - 150;
    let towerTop = 180;
    let baseWidth = 120;
    let topWidth = 100;

    // Tower body
    p.quad(
      towerX - baseWidth/2, towerBottom,
      towerX + baseWidth/2, towerBottom,
      towerX + topWidth/2, towerTop,
      towerX - topWidth/2, towerTop
    );

    // Crenellations (sharp, angular)
    p.fill(70, 75, 85);
    for (let i = 0; i < 5; i++) {
      let crenX = towerX - topWidth/2 + (i * topWidth/4);
      if (i % 2 === 0) {
        p.rect(crenX, towerTop - 20, topWidth/4, 20);
      }
    }

    // Tower door
    doorAngle = p.sin(p.frameCount * 0.01) * 0.1;
    p.push();
    p.translate(towerX - 15, towerBottom - 40);
    p.rotate(doorAngle);
    p.fill(40, 45, 55);
    p.rect(0, 0, 30, 60);
    p.fill(60, 65, 75);
    p.rect(3, 3, 24, 54);
    p.pop();

    // Interior glimpse (cramped intellectual space)
    p.fill(50, 55, 65, 150);
    p.ellipse(towerX, towerTop + 40, 80, 60);
    p.stroke(70, 75, 85);
    p.strokeWeight(1);
