    p.rect(figureX - 15, figureY - 45, 4, 20);

    // Legs
    p.rect(figureX - 6, figureY, 4, 40);
    p.rect(figureX + 2, figureY, 4, 40);

    // The Key (prominent in foreground)
    keyFloat = p.sin(p.frameCount * 0.03) * 3;

