function sketch(p) {
  let leftTowerOpacity = 255;
  let rightTowerHeight = 0;
  let figureX = 150;
  let particles = [];
  let timeOffset = 0;

  p.setup = function() {
    p.createCanvas(400, 600);

    // Initialize particles for dissolving effect
    for (let i = 0; i < 30; i++) {
      particles.push({
        x: p.random(50, 150),
        y: p.random(200, 450),
        vx: p.random(-1, 1),
        vy: p.random(-2, 0),
        alpha: 255,
        size: p.random(2, 6)
      });
    }
  };

  p.draw = function() {
    timeOffset += 0.01;

    // Sky gradient - transitional dawn/dusk
    for (let i = 0; i <= p.height; i++) {
      let inter = p.map(i, 0, p.height, 0, 1);
      let c1 = p.color(20, 30, 60);  // Dark blue
      let c2 = p.color(80, 60, 90);  // Purple-grey
      let c3 = p.color(120, 100, 80); // Warm grey
      let skyColor;

      if (inter < 0.5) {
        skyColor = p.lerpColor(c1, c2, inter * 2);
      } else {
        skyColor = p.lerpColor(c2, c3, (inter - 0.5) * 2);
      }

      p.stroke(skyColor);
      p.line(0, i, p.width, i);
    }

    // Animate transitions
    let mouseInfluence = p.map(p.mouseX, 0, p.width, 0, 1);
    let targetLeftOpacity = p.map(mouseInfluence, 0, 1, 255, 50);
    let targetRightHeight = p.map(mouseInfluence, 0, 1, 100, 300);
    let targetFigureX = p.map(mouseInfluence, 0, 1, 120, 280);

    leftTowerOpacity = p.lerp(leftTowerOpacity, targetLeftOpacity, 0.02);
    rightTowerHeight = p.lerp(rightTowerHeight, targetRightHeight, 0.03);
    figureX = p.lerp(figureX, targetFigureX, 0.02);

    // Left Tower (Martello-inspired, fading)
    p.push();
    p.fill(60, 80, 120, leftTowerOpacity);
    p.stroke(40, 60, 100, leftTowerOpacity);
    p.strokeWeight(2);

    // Cylindrical tower base
    p.rect(70, 450, 80, -200, 5);
    // Tower top
    p.ellipse(110, 250, 90, 30);

    // Windows and details
    p.fill(30, 40, 60, leftTowerOpacity * 0.7);
    p.rect(95, 320, 30, 40, 2);
    p.rect(95, 380, 30, 20, 2);

    // Tower suit symbol on left tower
    p.fill(150, 130, 100, leftTowerOpacity);
    p.textAlign(p.CENTER);
    p.textSize(12);
    p.text("🏰", 110, 300);

    p.pop();

    // Dissolving particles from left tower
    for (let i = particles.length - 1; i >= 0; i--) {
      let particle = particles[i];

      if (leftTowerOpacity < 200) {
        p.fill(60, 80, 120, particle.alpha);
        p.noStroke();
        p.circle(particle.x, particle.y, particle.size);

        particle.x += particle.vx;
        particle.y += particle.vy;
        particle.alpha -= 2;

        if (particle.alpha <= 0) {
          particle.x = p.random(50, 150);
          particle.y = p.random(200, 450);
          particle.alpha = 100;
        }
      }
    }

    // Right Tower (modern, solidifying)
    p.push();
    let rightOpacity = p.map(rightTowerHeight, 0, 300, 100, 255);
    p.fill(80, 90, 110, rightOpacity);
    p.stroke(60, 70, 90, rightOpacity);
    p.strokeWeight(3);

    // Angular modern tower
    let towerTop = 450 - rightTowerHeight;
    p.beginShape();
    p.vertex(250, 450);
    p.vertex(330, 450);
    p.vertex(320, towerTop);
    p.vertex(260, towerTop);
    p.endShape(p.CLOSE);

    // Modern windows - geometric
    if (rightTowerHeight > 100) {
      p.fill(40, 50, 70, rightOpacity * 0.8);
      for (let i = 0; i < 3; i++) {
        let windowY = 420 - (i * 60);
        if (windowY > towerTop + 20) {
          p.rect(270, windowY, 40, 15, 1);
        }
      }
    }

    // Tower suit symbol on right tower
    if (rightTowerHeight > 150) {
      p.fill(150, 130, 100, rightOpacity);
      p.textAlign(p.CENTER);
      p.textSize(12);
      p.text("🏰", 290, towerTop + 40);
    }

    p.pop();

    // Figure in transition
    p.push();
    p.fill(20, 25, 35);
    p.stroke(40, 45, 55);
    p.strokeWeight(1);

    // Body
    p.ellipse(figureX, 480, 12, 25);
    // Head
    p.ellipse(figureX, 465, 8, 8);
    // Arms suggesting movement
    let armSway = p.sin(timeOffset * 3) * 5;
    p.line(figureX - 6, 475, figureX - 10 + armSway, 485);
    p.line(figureX + 6, 475, figureX + 10 + armSway, 485);

    // Legs in walking motion
    let legOffset = p.sin(timeOffset * 4) * 3;
    p.line(figureX - 3, 492, figureX - 3 + legOffset, 505);
    p.line(figureX + 3, 492, figureX + 3 - legOffset, 505);

    p.pop();

    // Connection lines between towers (fading)
    p.stroke(100, 110, 130, 80);
    p.strokeWeight(1);
    let connectionAlpha = p.map(p.mouseX, 0, p.width, 50, 0);
    p.stroke(100, 110, 130, connectionAlpha);
    p.line(150, 350, 250, 350);

    // Subtle glow effects
    p.push();
    p.drawingContext.shadowBlur = 20;
    p.drawingContext.shadowColor = 'rgba(100, 120, 150, 0.3)';
    p.noFill();
    p.stroke(120, 140, 170, 30);
    p.strokeWeight(2);
    p.rect(69, 449, 82, -202, 5);
    if (rightTowerHeight > 50) {
      p.beginShape();
      p.vertex(249, 451);
      p.vertex(331, 451);
      p.vertex(321, 450 - rightTowerHeight + 1);
      p.vertex(259, 450 - rightTowerHeight + 1);
      p.endShape(p.CLOSE);
    }
    p.pop();
  };
}

