function sketch(p) {
  let towers = [];
  let centerFigure = {};
  let connectionPaths = [];
  let timeOfDay = 0;

  p.setup = function() {
    p.createCanvas(400, 600);

    // Initialize three towers in triangular arrangement
    towers = [
      {
        x: 200, y: 120,
        type: 'church',
        lightPhase: 0, // morning
        height: 180,
        windows: []
      },
      {
        x: 120, y: 380,
        type: 'modernist',
        lightPhase: p.TWO_PI / 3, // afternoon
        height: 160,
        windows: []
      },
      {
        x: 280, y: 380,
        type: 'classical',
        lightPhase: 4 * p.TWO_PI / 3, // night
        height: 170,
        windows: []
      }
    ];

    // Generate windows for each tower
    for (let tower of towers) {
      for (let i = 0; i < 8; i++) {
        tower.windows.push({
          x: tower.x + p.random(-15, 15),
          y: tower.y + p.random(20, tower.height - 20),
          lit: p.random() > 0.6
        });
      }
    }

    // Center figure
    centerFigure = {
      x: 200,
      y: 300,
      angle: 0,
      contemplation: 0
    };

    // Connection paths
    connectionPaths = [
      { from: 0, to: 1, particles: [] },
      { from: 1, to: 2, particles: [] },
      { from: 2, to: 0, particles: [] }
    ];
  };

  p.draw = function() {
    timeOfDay += 0.005;

    // Sky gradient based on time
    for (let i = 0; i <= p.height; i++) {
      let inter = p.map(i, 0, p.height, 0, 1);
      let skyColor = p.lerpColor(
        p.color(25, 25, 45),
        p.color(60, 60, 80),
        inter
      );
      p.stroke(skyColor);
      p.line(0, i, p.width, i);
    }

    // Draw connection lines with flowing particles
    p.strokeWeight(1);
    for (let path of connectionPaths) {
      let from = towers[path.from];
      let to = towers[path.to];

      // Subtle connection line
      p.stroke(150, 150, 180, 60);
      p.line(from.x, from.y + from.height/2, to.x, to.y + to.height/2);

      // Add particles along path
      if (p.frameCount % 60 === 0) {
        path.particles.push({
          x: from.x,
          y: from.y + from.height/2,
          targetX: to.x,
          targetY: to.y + to.height/2,
          progress: 0
        });
      }

      // Update and draw particles
      for (let i = path.particles.length - 1; i >= 0; i--) {
        let particle = path.particles[i];
        particle.progress += 0.01;

        particle.x = p.lerp(from.x, to.x, particle.progress);
        particle.y = p.lerp(from.y + from.height/2, to.y + to.height/2, particle.progress);

        p.fill(200, 200, 255, 200 * (1 - particle.progress));
        p.noStroke();
        p.circle(particle.x, particle.y, 3);

        if (particle.progress >= 1) {
          path.particles.splice(i, 1);
        }
      }
    }

    // Draw towers
    for (let i = 0; i < towers.length; i++) {
      let tower = towers[i];
      drawTower(tower, i);
    }

    // Draw center figure
    drawCenterFigure();

    // Mouse interaction - figure looks toward mouse
    if (p.dist(p.mouseX, p.mouseY, centerFigure.x, centerFigure.y) < 100) {
      centerFigure.angle = p.atan2(p.mouseY - centerFigure.y, p.mouseX - centerFigure.x);
      centerFigure.contemplation = p.min(centerFigure.contemplation + 0.02, 1);
    } else {
      centerFigure.contemplation = p.max(centerFigure.contemplation - 0.01, 0);
    }
  };

  function drawTower(tower, index) {
    p.push();
    p.translate(tower.x, tower.y);

    // Calculate lighting based on time and tower's phase
    let lightIntensity = (p.sin(timeOfDay + tower.lightPhase) + 1) / 2;
    let shadowIntensity = 1 - lightIntensity;

    // Tower base colors
    let baseColors = [
      p.color(80, 70, 60),   // church - stone
      p.color(60, 60, 70),   // modernist - concrete
      p.color(90, 80, 70)    // classical - marble
    ];

    let towerColor = p.lerpColor(
      p.color(40, 40, 50),
      baseColors[index],
      lightIntensity
    );

    p.fill(towerColor);
    p.stroke(0, 0, 0, 100);
    p.strokeWeight(2);

    // Main tower structure
    if (tower.type === 'church') {
      // Gothic spire
      p.rect(-20, 0, 40, tower.height);
      p.triangle(-15, 0, 15, 0, 0, -30);
      // Cross
      p.line(0, -25, 0, -35);
      p.line(-5, -30, 5, -30);
    } else if (tower.type === 'modernist') {
      // Blocky, angular
      p.rect(-18, 0, 36, tower.height);
      p.rect(-12, -20, 24, 20);
      p.rect(-8, -35, 16, 15);
    } else { // classical
      // Classical proportions
      p.rect(-22, 0, 44, tower.height);
      // Columns
      for (let i = -15; i <= 15; i += 10) {
        p.rect(i-2, 10, 4, tower.height-20);
      }
      // Pediment
      p.triangle(-25, -10, 25, -10, 0, -30);
    }

    // Crenellations
    for (let i = -20; i < 20; i += 8) {
      p.rect(i, -5, 6, 10);
    }

    // Windows with varying light
    p.noStroke();
    for (let window of tower.windows) {
      if (window.lit && lightIntensity > 0.3) {
        p.fill(255, 255, 180, lightIntensity * 255);
      } else {
        p.fill(20, 20, 30);
      }
      p.rect(window.x - tower.x - 2, window.y - tower.y - 2, 4, 6);
    }

    p.pop();
  }

  function drawCenterFigure() {
    p.push();
    p.translate(centerFigure.x, centerFigure.y);

    // Figure grows more defined with contemplation
    let alpha = 100 + centerFigure.contemplation * 155;

    p.fill(180, 160, 140, alpha);
    p.noStroke();

    // Body
    p.ellipse(0, 0, 12, 20);

    // Head turned toward contemplation direction
    p.push();
    p.rotate(centerFigure.angle * centerFigure.contemplation);
    p.ellipse(0, -12, 8, 8);
    p.pop();

    // Arms reaching toward towers (subtle)
    p.stroke(180, 160, 140, alpha);
    p.strokeWeight(2);
    for (let i = 0; i < 3; i++) {
      let angle = i * p.TWO_PI / 3 + timeOfDay * 0.1;
      let reach = 15 + centerFigure.contemplation * 10;
      p.line(0, 0, p.cos(angle) * reach, p.sin(angle) * reach);
    }

    // Meditation circle
    if (centerFigure.contemplation > 0.5) {
      p.noFill();
      p.stroke(255, 255, 255, centerFigure.contemplation * 100);
      p.strokeWeight(1);
      p.circle(0, 0, 40 + p.sin(timeOfDay * 2) * 5);
    }

    p.pop();
  }
}

