function sketch(p) {
  let towers = [];
  let figure = { x: 200, y: 550, targetX: 200, speed: 0.5 };
  let liffey = [];
  let shadows = [];
  let time = 0;

  p.setup = function() {
    p.createCanvas(400, 600);

    // Create Dublin's towers - churches, monuments, buildings
    towers.push({ x: 80, y: 200, height: 180, type: 'church', sway: 0 });
    towers.push({ x: 150, y: 250, height: 120, type: 'monument', sway: 0 });
    towers.push({ x: 220, y: 180, height: 200, type: 'church', sway: 0 });
    towers.push({ x: 320, y: 220, height: 160, type: 'building', sway: 0 });
    towers.push({ x: 50, y: 280, height: 100, type: 'building', sway: 0 });
    towers.push({ x: 280, y: 160, height: 140, type: 'monument', sway: 0 });
    towers.push({ x: 370, y: 300, height: 80, type: 'martello', sway: 0 });
    towers.push({ x: 120, y: 320, height: 90, type: 'building', sway: 0 });
    towers.push({ x: 350, y: 250, height: 110, type: 'church', sway: 0 });
    towers.push({ x: 180, y: 300, height: 95, type: 'building', sway: 0 });

    // Initialize Liffey points
    for (let i = 0; i < 400; i += 20) {
      liffey.push({ x: i, y: 400 + p.sin(i * 0.02) * 15, flow: p.random(0.5, 2) });
    }
  };

  p.draw = function() {
    time += 0.01;

    // Sky gradient - cold Dublin light
    for (let i = 0; i <= 400; i++) {
      let inter = p.map(i, 0, 400, 0, 1);
      let c = p.lerpColor(p.color(220, 225, 235), p.color(180, 185, 195), inter);
      p.stroke(c);
      p.line(0, i, 400, i);
    }

    // Grid streets (the four-square city)
    p.stroke(160, 160, 170, 100);
    p.strokeWeight(1);
    for (let i = 50; i < 400; i += 50) {
      p.line(i, 350, i, 580);
    }
    for (let i = 350; i < 600; i += 40) {
      p.line(20, i, 380, i);
    }

    // Update and draw shadows first
    shadows = [];
    for (let tower of towers) {
      let shadowLength = tower.height * 0.8;
      let shadowAngle = p.PI / 6 + p.sin(time * 0.3) * 0.1;
      shadows.push({
        x1: tower.x,
        y1: tower.y + tower.height,
        x2: tower.x + p.cos(shadowAngle) * shadowLength,
        y2: tower.y + tower.height + p.sin(shadowAngle) * shadowLength
      });
    }

    // Draw shadows
    p.fill(120, 120, 130, 80);
    p.noStroke();
    for (let shadow of shadows) {
      p.quad(shadow.x1 - 5, shadow.y1, shadow.x1 + 5, shadow.y1,
             shadow.x2 + 15, shadow.y2, shadow.x2 - 5, shadow.y2);
    }

    // Draw Liffey
    p.stroke(100, 110, 130);
    p.strokeWeight(3);
    p.noFill();
    p.beginShape();
    for (let point of liffey) {
      point.y = 400 + p.sin(point.x * 0.02 + time * point.flow) * 12;
      p.curveVertex(point.x, point.y);
    }
    p.endShape();

    // Draw towers with subtle animation
    for (let i = 0; i < towers.length; i++) {
      let tower = towers[i];
      tower.sway = p.sin(time + i * 0.5) * 2;

      p.fill(140, 145, 155);
      p.stroke(100, 105, 115);
      p.strokeWeight(2);

      // Tower body
      p.rect(tower.x - 8 + tower.sway * 0.3, tower.y, 16, tower.height);

      // Tower-specific tops
      p.fill(120, 125, 135);
      if (tower.type === 'church') {
        // Spire
        p.triangle(tower.x + tower.sway * 0.3, tower.y - 15, 
                  tower.x - 6 + tower.sway * 0.3, tower.y + 5,
                  tower.x + 6 + tower.sway * 0.3, tower.y + 5);
        // Cross
        p.strokeWeight(1);
        p.line(tower.x + tower.sway * 0.3, tower.y - 10, 
               tower.x + tower.sway * 0.3, tower.y - 5);
        p.line(tower.x - 2 + tower.sway * 0.3, tower.y - 8, 
               tower.x + 2 + tower.sway * 0.3, tower.y - 8);
      } else if (tower.type === 'monument') {
        // Monument top
        p.rect(tower.x - 10 + tower.sway * 0.3, tower.y - 8, 20, 8);
      } else if (tower.type === 'martello') {
        // Round tower
        p.fill(160, 165, 175);
        p.ellipse(tower.x + tower.sway * 0.3, tower.y + tower.height/2, 20, tower.height);
      }

      // Windows - flickering lights
      p.fill(255, 255, 200, p.random(50, 150));
      p.noStroke();
      for (let j = 0; j < 3; j++) {
        if (p.random() > 0.7) {
          p.rect(tower.x - 4 + tower.sway * 0.3, 
                tower.y + 20 + j * 25, 2, 3);
          p.rect(tower.x + 2 + tower.sway * 0.3, 
                tower.y + 20 + j * 25, 2, 3);
        }
      }
    }

    // Update figure position based on mouse
    figure.targetX = p.constrain(p.mouseX, 50, 350);
    figure.x = p.lerp(figure.x, figure.targetX, 0.02);

    // Draw the tiny figure (Stephen-like)
    p.fill(80, 85, 95);
    p.noStroke();
    p.ellipse(figure.x, figure.y - 8, 4, 4); // head
    p.rect(figure.x - 1, figure.y - 4, 2, 8); // body

    // Atmospheric particles (dust, light)
    p.fill(255, 255, 255, 30);
    for (let i = 0; i < 20; i++) {
      let x = (time * 10 + i * 20) % 420;
      let y = 100 + p.sin(time + i) * 50;
      p.ellipse(x, y, 2, 2);
    }

    // Title area darkening
    p.fill(0, 0, 0, 20);
    p.noStroke();
    p.rect(0, 0, 400, 80);
    p.rect(0, 520, 400, 80);
  };
}

