function sketch(p) {
  let towers = [];
  let outsiderTower;
  let particles = [];
  let time = 0;

  p.setup = function() {
    p.createCanvas(400, 600);

    // Create city towers in a grid pattern
    for(let i = 0; i < 4; i++) {
      for(let j = 0; j < 2; j++) {
        towers.push({
          x: 80 + i * 60,
          y: 400 + j * 80,
          height: p.random(80, 120),
          width: 40,
          type: 'city'
        });
      }
    }

    // Create the outsider tower (Martello-style)
    outsiderTower = {
      x: 320,
      y: 150,
      radius: 35,
      height: 100,
      doorAngle: 0
    };

    // Initialize particles for atmosphere
    for(let i = 0; i < 30; i++) {
      particles.push({
        x: p.random(p.width),
        y: p.random(p.height),
        size: p.random(1, 3),
        speed: p.random(0.2, 0.8),
        alpha: p.random(50, 150)
      });
    }
  };

  p.draw = function() {
    time += 0.01;

    // Dark, moody background
    p.background(15, 20, 35);

    // Draw water/separation
    p.fill(25, 35, 55);
    p.noStroke();
    p.rect(0, 300, p.width, 200);

    // Water ripples
    p.stroke(40, 60, 90);
    p.strokeWeight(1);
    for(let i = 0; i < 5; i++) {
      let y = 350 + i * 30;
      let wave = p.sin(time * 2 + i) * 10;
      p.line(0, y + wave, p.width, y + wave);
    }

    // Draw city towers in four-square pattern
    p.fill(45, 50, 70);
    p.stroke(60, 70, 90);
    p.strokeWeight(2);

    for(let tower of towers) {
      // Main tower body
      p.rect(tower.x - tower.width/2, tower.y - tower.height, tower.width, tower.height);

      // Gothic spire top
      p.triangle(tower.x - tower.width/2, tower.y - tower.height,
                tower.x, tower.y - tower.height - 30,
                tower.x + tower.width/2, tower.y - tower.height);

      // Windows
      p.fill(80, 90, 120);
      for(let w = 0; w < 3; w++) {
        p.rect(tower.x - 15 + w * 10, tower.y - tower.height + 20 + w * 25, 8, 12);
      }
      p.fill(45, 50, 70);
    }

    // Draw connection lines showing the grid pattern
    p.stroke(30, 40, 60);
    p.strokeWeight(1);
    for(let i = 0; i < towers.length - 1; i++) {
      for(let j = i + 1; j < towers.length; j++) {
        if(p.dist(towers[i].x, towers[i].y, towers[j].x, towers[j].y) < 100) {
          p.line(towers[i].x, towers[i].y - towers[i].height/2,
                towers[j].x, towers[j].y - towers[j].height/2);
        }
      }
    }

    // Draw the outsider tower (round, fortress-like)
    p.fill(70, 60, 85);
    p.stroke(90, 80, 110);
    p.strokeWeight(3);

    // Main cylindrical body
    p.ellipse(outsiderTower.x, outsiderTower.y, outsiderTower.radius * 2, outsiderTower.radius * 1.5);
    p.rect(outsiderTower.x - outsiderTower.radius, 
           outsiderTower.y - outsiderTower.height/2, 
           outsiderTower.radius * 2, outsiderTower.height);

    // Top dome
    p.ellipse(outsiderTower.x, outsiderTower.y - outsiderTower.height/2, outsiderTower.radius * 2, 40);

    // Door
    outsiderTower.doorAngle = p.sin(time) * 0.3;
    p.fill(20, 15, 30);
    p.rect(outsiderTower.x - 8, outsiderTower.y + 20, 16, 25);

    // Figure in doorway
    if(p.sin(time * 0.5) > 0) {
      p.fill(120, 100, 140);
      p.ellipse(outsiderTower.x, outsiderTower.y + 10, 8, 8); // head
      p.rect(outsiderTower.x - 3, outsiderTower.y + 15, 6, 15); // body
    }

    // Pentagram geometry - show the fifth point
