function sketch(p) {
  let forgeX, forgeY;
  let towerPlans = [];
  let sparks = [];
  let hammerAngle = 0;
  let connectionOpacity = 0;
  let tower1, tower2;
  let forgeGlow = 0;
  let anvilSymbol = { angle: 0, scale: 1 };

  p.setup = function() {
    p.createCanvas(400, 600);

    forgeX = 200;
    forgeY = 450;

    tower1 = { x: 120, y: 200, recognition: 0 };
    tower2 = { x: 280, y: 180, recognition: 0 };

    // Create tower plan points
    for (let i = 0; i < 8; i++) {
      towerPlans.push({
        x: forgeX - 30 + p.random(60),
        y: forgeY - 20 + p.random(40),
        originalX: forgeX - 30 + p.random(60),
        originalY: forgeY - 20 + p.random(40),
        drift: p.random(0.005, 0.02)
      });
    }
  };

  p.draw = function() {
    // Dark angular background
    p.background(15, 20, 35);

    // Dynamic connection recognition
    let mouseInfluence = p.dist(p.mouseX, p.mouseY, 200, 300) / 300;
    connectionOpacity = p.lerp(connectionOpacity, 255 * (1 - mouseInfluence), 0.05);
    tower1.recognition = p.lerp(tower1.recognition, 1 - mouseInfluence, 0.03);
    tower2.recognition = p.lerp(tower2.recognition, 1 - mouseInfluence, 0.03);

    // Background formless materials
    drawFormlessMaterials();

    // Draw towers with recognition glow
    drawTower(tower1.x, tower1.y, 60, 140, tower1.recognition);
    drawTower(tower2.x, tower2.y, 50, 120, tower2.recognition);

    // Connection line between towers
    if (connectionOpacity > 50) {
      p.stroke(255, 200, 100, connectionOpacity);
      p.strokeWeight(2);
      p.line(tower1.x, tower1.y + 70, tower2.x, tower2.y + 60);

      // Recognition particles along line
      for (let i = 0; i < 3; i++) {
        let t = (p.frameCount * 0.01 + i * 0.3) % 1;
        let x = p.lerp(tower1.x, tower2.x, t);
        let y = p.lerp(tower1.y + 70, tower2.y + 60, t);
        p.fill(255, 200, 100, connectionOpacity * 0.7);
        p.noStroke();
        p.circle(x, y, 4);
      }
    }

    // Smithy/forge structure
    drawForge();

    // Forge fire with dynamic glow
    forgeGlow = 128 + 127 * p.sin(p.frameCount * 0.1);
    p.fill(255, 100 + forgeGlow * 0.3, 0);
    p.noStroke();
    p.circle(forgeX, forgeY - 10, 40 + forgeGlow * 0.1);
    p.fill(255, 200, 50, 200);
    p.circle(forgeX, forgeY - 15, 25);

    // Sparks from forge
    manageSparks();

    // Anvil
    drawAnvil();

    // Hammer in motion
    hammerAngle = p.sin(p.frameCount * 0.08) * 0.5;
    drawHammer();

    // Tower plans on anvil (floating, being forged)
    drawTowerPlans();

    // Tower suit symbol being forged on anvil
    drawForgingSymbol();
  };

  function drawFormlessMaterials() {
    for (let i = 0; i < 20; i++) {
      let x = p.random(400);
      let y = p.random(600);
      let size = p.random(10, 30);
      let drift = p.sin(p.frameCount * 0.01 + i) * 2;

      p.fill(40, 45, 60, 100);
      p.noStroke();
      p.circle(x + drift, y, size);
    }
  };

  function drawTower(x, y, width, height, recognition) {
    let glowIntensity = recognition * 100;

    // Glow effect when recognized
    if (recognition > 0.1) {
      p.fill(100, 150, 255, glowIntensity);
      p.noStroke();
      p.rect(x - width/2 - 5, y, width + 10, height, 5);
    }

    // Main tower structure
    p.fill(80, 85, 95);
    p.stroke(120, 125, 140);
    p.strokeWeight(2);
    p.rect(x - width/2, y, width, height, 3);

    // Tower details
    for (let i = 1; i < 4; i++) {
      let segmentY = y + (height/4) * i;
      p.line(x - width/2 + 5, segmentY, x + width/2 - 5, segmentY);
    }

    // Windows
    p.fill(255, 200, 100, 150);
    p.noStroke();
    p.rect(x - 8, y + 20, 4, 8);
    p.rect(x + 4, y + 50, 4, 8);
    p.rect(x - 6, y + 80, 4, 8);
  };

  function drawForge() {
    // Forge structure
    p.fill(60, 55, 50);
    p.stroke(100, 95, 90);
    p.strokeWeight(3);
    p.rect(forgeX - 50, forgeY - 30, 100, 60, 5);

    // Chimney
    p.rect(forgeX - 10, forgeY - 80, 20, 50);

    // Forge opening
    p.fill(20, 15, 10);
    p.noStroke();
    p.arc(forgeX, forgeY - 10, 60, 40, p.PI, p.TWO_PI);
  };

  function drawAnvil() {
    p.fill(70, 75, 80);
    p.stroke(100, 105, 110);
    p.strokeWeight(2);
    p.rect(forgeX - 25, forgeY + 20, 50, 15, 3);
    p.rect(forgeX - 5, forgeY + 35, 10, 20);
  };

  function drawHammer() {
    p.push();
    p.translate(forgeX + 40, forgeY + 10);
    p.rotate(hammerAngle);

    // Handle
    p.stroke(139, 69, 19);
    p.strokeWeight(6);
    p.line(0, 0, 0, 40);

    // Head
    p.fill(90, 95, 100);
    p.noStroke();
    p.rect(-8, -5, 16, 10);

    p.pop();
  };

  function drawTowerPlans() {
    p.stroke(150, 150, 180, 180);
    p.strokeWeight(1);

    for (let i = 0; i < towerPlans.length - 1; i++) {
      let plan = towerPlans[i];
      let nextPlan = towerPlans[i + 1];

      // Gentle drift
      plan.x = plan.originalX + p.sin(p.frameCount * plan.drift) * 3;
      plan.y = plan.originalY + p.cos(p.frameCount * plan.drift * 0.7) * 2;

      p.line(plan.x, plan.y, nextPlan.x, nextPlan.y);
    }

    // Connect back to first
    if (towerPlans.length > 2) {
      p.line(towerPlans[towerPlans.length - 1].x, towerPlans[towerPlans.length - 1].y,
             towerPlans[0].x, towerPlans[0].y);
    }
  };

  function drawForgingSymbol() {
    anvilSymbol.angle += 0.02;
    anvilSymbol.scale = 0.8 + 0.2 * p.sin(p.frameCount * 0.05);

    p.push();
    p.translate(forgeX, forgeY + 27);
    p.rotate(anvilSymbol.angle);
    p.scale(anvilSymbol.scale);

    // Tower suit symbol being forged
    p.stroke(255, 150, 50);
    p.strokeWeight(3);
    p.noFill();
    p.rect(-8, -12, 16, 24);
    p.line(-5, -8, 5, -8);
    p.line(-5, 0, 5, 0);
    p.line(-5, 8, 5, 8);

    p.pop();
  };

  function manageSparks() {
    // Add new sparks
    if (p.frameCount % 8 == 0) {
      sparks.push({
        x: forgeX + p.random(-10, 10),
        y: forgeY - 10,
        vx: p.random(-2, 2),
        vy: p.random(-3, -1),
        life: 255
      });
    }

    // Update and draw sparks
    for (let i = sparks.length - 1; i >= 0; i--) {
      let spark = sparks[i];
      spark.x += spark.vx;
      spark.y += spark.vy;
      spark.vy += 0.1; // gravity
      spark.life -= 3;

      p.fill(255, 200 - (255 - spark.life), 0, spark.life);
      p.noStroke();
      p.circle(spark.x, spark.y, 3);

      if (spark.life <= 0) {
        sparks.splice(i, 1);
      }
    }
  };
}

