function sketch(p) {
  let towers = [];
  let scales = { leftWeight: 0, rightWeight: 0, angle: 0 };
  let figure = { x: 0, y: 0, pulse: 0 };
  let asymmetryPulse = 0;

  p.setup = function() {
    p.createCanvas(400, 600);

    // Create seven towers with intentional asymmetry
    // Three towers on left (Trinity)
    for(let i = 0; i < 3; i++) {
      towers.push({
        x: 60 + i * 35,
        y: p.height - 180,
        baseHeight: 120 + i * 15,
        currentHeight: 0,
        side: 'left',
        index: i,
        wobble: 0
      });
    }

    // Four towers on right (City grid)
    for(let i = 0; i < 4; i++) {
      towers.push({
        x: 250 + i * 35,
        y: p.height - 180,
        baseHeight: 100 + i * 20,
        currentHeight: 0,
        side: 'right',
        index: i + 3,
        wobble: 0
      });
    }

    // Figure position in the gap
    figure.x = 200;
    figure.y = p.height - 120;
  };

  p.draw = function() {
    // Dark, angular background
    p.background(25, 30, 40);

    // Asymmetry pulse for visual discomfort
    asymmetryPulse = p.sin(p.millis() * 0.002) * 0.3 + 0.7;

    // Draw unbalanced ground planes
    p.fill(40, 50, 65);
    p.noStroke();
    // Left side slightly raised
    p.quad(0, p.height - 160, 190, p.height - 155, 190, p.height, 0, p.height);
    // Right side lower
    p.quad(210, p.height - 150, 400, p.height - 145, 400, p.height, 210, p.height);

    // Draw towers with growing animation and asymmetric wobble
    for(let tower of towers) {
      // Animate height growth
      tower.currentHeight = p.lerp(tower.currentHeight, tower.baseHeight, 0.02);

      // Asymmetric wobble - more pronounced on one side
      let wobbleAmount = tower.side === 'left' ? 2 : 4;
      tower.wobble = p.sin(p.millis() * 0.003 + tower.index) * wobbleAmount * asymmetryPulse;

      p.push();
      p.translate(tower.x + tower.wobble, tower.y);

      // Angular, uncomfortable tower design
      p.fill(70 + tower.index * 15, 85 + tower.index * 10, 100 + tower.index * 8);
      p.stroke(120, 130, 140);
      p.strokeWeight(1);

      // Irregular tower shapes that resist symmetry
      p.beginShape();
      p.vertex(-12, 0);
      p.vertex(-8, -tower.currentHeight * 0.8);
      p.vertex(-4, -tower.currentHeight);
      p.vertex(4, -tower.currentHeight * 0.95);
      p.vertex(8, -tower.currentHeight * 0.7);
      p.vertex(12, -5);
      p.endShape(p.CLOSE);

      // Windows with irregular spacing
      p.fill(200, 180, 100, 150);
      p.noStroke();
      for(let w = 0; w < tower.currentHeight / 25; w++) {
        let wx = -6 + (w % 2) * 8;
        let wy = -20 - w * 22;
        if(wy > -tower.currentHeight) {
          p.rect(wx, wy, 3, 4);
        }
      }

      p.pop();
    }

    // Draw the figure in the gap - the source of asymmetry
    figure.pulse = p.sin(p.millis() * 0.004) * 10;
    p.push();
    p.translate(figure.x, figure.y + figure.pulse);

    p.fill(150, 120, 80);
    p.stroke(100, 80, 60);
    p.strokeWeight(2);

    // Abstract human figure creating the imbalance
    p.ellipse(0, -30, 12, 15); // head
    p.line(0, -22, 0, -5); // torso
    p.line(0, -15, -8, -8); // left arm
    p.line(0, -15, 8, -12); // right arm (asymmetric)
    p.line(0, -5, -6, 8); // left leg
    p.line(0, -5, 4, 10); // right leg (different length)

    p.pop();

    // Draw impossible scales that can't balance
    p.push();
    p.translate(200, 180);

    // Scale base
    p.stroke(120, 100, 80);
    p.strokeWeight(3);
    p.line(0, 0, 0, 60);

    // Calculate weights (always uneven)
    scales.leftWeight = 3 * asymmetryPulse;
    scales.rightWeight = 4 * (2 - asymmetryPulse);
    scales.angle = p.atan2(scales.rightWeight - scales.leftWeight, 100) * 0.5;

    // Scale beam (always tilted)
    p.push();
    p.rotate(scales.angle);
    p.line(-80, 0, 80, 0);

    // Left scale pan
    p.push();
    p.translate(-80, 0);
    p.fill(60, 70, 80);
    p.noStroke();
    p.arc(0, 0, 30, 20, 0, p.PI);
    // Weight representation
    for(let i = 0; i < 3; i++) {
      p.fill(100 + i * 20, 90, 70);
      p.ellipse(-8 + i * 8, -5, 6, 4);
    }
    p.pop();

    // Right scale pan
    p.push();
    p.translate(80, 0);
    p.fill(60, 70, 80);
    p.noStroke();
    p.arc(0, 0, 30, 20, 0, p.PI);
    // Weight representation
    for(let i = 0; i < 4; i++) {
      p.fill(80 + i * 15, 95, 85);
      p.ellipse(-12 + i * 8, -5, 6, 4);
    }
    p.pop();

    p.pop();
    p.pop();

    // Draw geometric lines that emphasize the asymmetry
    p.stroke(100, 120, 140, 100);
    p.strokeWeight(1);

    // Lines that try to connect but can't quite meet
    let mouseInfluence = p.map(p.mouseX, 0, p.width, 0, 1);
    p.line(170, 200, 190 + mouseInfluence * 20, 220);
    p.line(230, 200, 210 - mouseInfluence * 20, 220);

    // Angular divisions that create discomfort
    p.line(0, p.height * 0.6, 180, p.height * 0.65);
    p.line(220, p.height * 0.63, 400, p.height * 0.58);

    // Subtle particles that move asymmetrically
    p.fill(150, 160, 170, 80);
    p.noStroke();
    for(let i = 0; i < 7; i++) {
      let px = 50 + i * 50 + p.sin(p.millis() * 0.001 + i) * (i % 2 === 0 ? 20 : 35);
      let py = 100 + p.sin(p.millis() * 0.002 + i * 0.5) * 30;
      p.ellipse(px, py, 3, 3);
    }
  };
}

