function sketch(p) {
  let towers = [];
  let waves = [];
  let figure;
  let timeOffset = 0;

  p.setup = function() {
    p.createCanvas(400, 600);

    // Create towers from different eras - oldest to newest
    towers.push(new Tower(120, 500, 60, 150, p.color(80, 60, 40, 120), "ancient")); // Ancient round tower
    towers.push(new Tower(180, 480, 40, 180, p.color(100, 80, 60, 140), "medieval")); // Medieval spire  
    towers.push(new Tower(250, 460, 50, 200, p.color(120, 100, 80, 160), "martello")); // Martello tower
    towers.push(new Tower(160, 440, 45, 220, p.color(140, 120, 100, 180), "victorian")); // Victorian
    towers.push(new Tower(200, 420, 35, 240, p.color(160, 140, 120, 200), "modern")); // Modern building
    towers.push(new Tower(200, 400, 30, 260, p.color(180, 160, 140, 255), "stephen")); // Stephen's tower

    // Create wave particles for the ocean of history
    for(let i = 0; i < 150; i++) {
      waves.push(new Wave(p.random(400), p.random(500, 600)));
    }

    // Figure struggling with/against history
    figure = new Figure(220, 380);
  };

  p.draw = function() {
    // Dark, oppressive background suggesting weight of history
    p.background(20, 25, 35);

    timeOffset += 0.01;

    // Draw waves of history - the ocean that carries and drowns
    for(let wave of waves) {
      wave.update();
      wave.display();
    }

    // Draw towers from oldest to newest (geological layers)
    for(let i = 0; i < towers.length; i++) {
      let tower = towers[i];
      tower.update(i);
      tower.display();
    }

    // Draw the figure
    figure.update();
    figure.display();

    // Add atmospheric effects - particles of time and history
    drawHistoricalParticles();
  };

  class Tower {
    constructor(x, baseY, width, height, col, era) {
      this.x = x;
      this.baseY = baseY;
      this.width = width;
      this.height = height;
      this.color = col;
      this.era = era;
      this.sway = 0;
      this.crumble = 0;
    }

    update(index) {
      // Towers sway slightly under historical weight
      this.sway = p.sin(timeOffset * 2 + index * 0.5) * (index + 1);

      // Older towers show more decay
      this.crumble = p.noise(timeOffset * 0.5 + index) * index * 2;

      // Interactive element - mouse proximity affects towers
      let mouseDistance = p.dist(p.mouseX, p.mouseY, this.x, this.baseY - this.height/2);
      if(mouseDistance < 100) {
        this.sway += p.sin(timeOffset * 5) * 3;
      }
    }

    display() {
      p.push();
      p.translate(this.x + this.sway, this.baseY);

      // Draw tower with era-appropriate shape
      p.fill(this.color);
      p.stroke(p.red(this.color) + 40, p.green(this.color) + 40, p.blue(this.color) + 40, p.alpha(this.color));
      p.strokeWeight(1);

      if(this.era === "ancient") {
        // Round tower
        p.ellipse(0, -this.height/2, this.width, this.height);
        // Add stones
        for(let i = 0; i < this.height; i += 15) {
          p.stroke(60, 50, 30, 60);
          p.line(-this.width/2, -i, this.width/2, -i);
        }
      } else if(this.era === "medieval") {
        // Gothic spire
        p.rect(-this.width/2, -this.height, this.width, this.height);
        p.triangle(-this.width/2, -this.height, this.width/2, -this.height, 0, -this.height - 30);
      } else if(this.era === "martello") {
        // Cylindrical fortification
        p.ellipse(0, -this.height/2, this.width, this.height * 0.8);
        p.rect(-this.width/2, -this.height * 0.9, this.width, this.height * 0.4);
      } else {
        // Modern rectangular towers
        p.rect(-this.width/2, -this.height, this.width, this.height);

        // Add windows for modern towers
        if(this.era === "modern" || this.era === "stephen") {
          p.fill(80, 100, 120, 150);
          p.noStroke();
          for(let i = 10; i < this.height - 20; i += 25) {
            for(let j = -this.width/3; j <= this.width/3; j += this.width/3) {
              p.rect(j - 3, -i, 6, 12);
            }
          }
        }
      }

      // Show crumbling/ruins for older towers
      if(this.crumble > 0) {
        p.fill(p.red(this.color) - 20, p.green(this.color) - 20, p.blue(this.color) - 20, 100);
        p.noStroke();
        for(let i = 0; i < this.crumble; i++) {
          let debrisX = p.random(-this.width, this.width);
          let debrisY = p.random(-this.height, 20);
          p.ellipse(debrisX, debrisY, p.random(3, 8));
        }
      }

      p.pop();
    }
  }

  class Wave {
    constructor(x, y) {
      this.x = x;
      this.y = y;
      this.baseY = y;
      this.speed = p.random(0.5, 2);
      this.amplitude = p.random(5, 15);
      this.size = p.random(2, 6);
    }

    update() {
      this.x += this.speed;
      this.y = this.baseY + p.sin(timeOffset * 3 + this.x * 0.01) * this.amplitude;

      if(this.x > 450) {
        this.x = -50;
        this.baseY = p.random(500, 600);
      }
    }

    display() {
      p.fill(40, 60, 120, 80);
      p.noStroke();
      p.ellipse(this.x, this.y, this.size);

      // Add foam/spray
      if(p.random() < 0.1) {
        p.fill(80, 100, 140, 60);
        p.ellipse(this.x + p.random(-5, 5), this.y - p.random(5, 15), 2);
      }
    }
  }

  class Figure {
    constructor(x, y) {
      this.x = x;
      this.y = y;
      this.baseY = y;
      this.struggle = 0;
    }

    update() {
      // Figure struggles against the waves of history
      this.struggle = p.sin(timeOffset * 4) * 8;
      this.y = this.baseY + this.struggle;

      // Mouse interaction - figure reaches toward cursor
      let mouseDistance = p.dist(p.mouseX, p.mouseY, this.x, this.y);
      if(mouseDistance < 150) {
        this.x += (p.mouseX - this.x) * 0.02;
        this.y += (p.mouseY - this.y) * 0.02;
      } else {
        this.x += (220 - this.x) * 0.05;
        this.y += (this.baseY - this.y) * 0.05;
      }
    }

    display() {
      p.push();
      p.translate(this.x, this.y);

      // Draw simple figure silhouette
      p.fill(200, 180, 160, 200);
      p.stroke(160, 140, 120, 150);
      p.strokeWeight(1);

      // Head
      p.ellipse(0, -15, 12, 15);

      // Body
      p.line(0, -8, 0, 15);

      // Arms reaching/struggling
      let armAngle = p.sin(timeOffset * 6) * 0.3;
      p.line(0, 0, -12 + p.cos(armAngle) * 8, 8 + p.sin(armAngle) * 8);
      p.line(0, 0, 12 + p.cos(-armAngle) * 8, 8 + p.sin(-armAngle) * 8);

      // Legs
      p.line(0, 15, -6, 25);
      p.line(0, 15, 6, 25);

      p.pop();
    }
  }

  function drawHistoricalParticles() {
    // Particles representing the weight and flow of time
    p.fill(120, 100, 80, 30);
    p.noStroke();

    for(let i = 0; i < 20; i++) {
      let x = p.noise(timeOffset + i * 0.1) * 400;
      let y = p.noise(timeOffset + i * 0.1 + 100) * 600;
      let size = p.noise(timeOffset + i * 0.1 + 200) * 4 + 1;

      p.ellipse(x, y, size);
    }

    // Vertical streams suggesting the compression of time
    p.stroke(140, 120, 100, 20);
    p.strokeWeight(1);
    for(let i = 0; i < 10; i++) {
      let x = i * 40 + p.sin(timeOffset + i) * 20;
