function sketch(p) {
  let stars = [];
  let doorGlow = 0;
  let figureY = 0;
  let breathe = 0;
  let particles = [];

  p.setup = function() {
    p.createCanvas(400, 600);

    // Create stars beyond the door
    for(let i = 0; i < 30; i++) {
      stars.push({
        x: p.random(140, 260),
        y: p.random(80, 180),
        size: p.random(1, 3),
        twinkle: p.random(p.TWO_PI)
      });
    }

    // Create light particles
    for(let i = 0; i < 50; i++) {
      particles.push({
        x: p.random(140, 260),
        y: p.random(100, 200),
        vx: p.random(-0.5, 0.5),
        vy: p.random(-0.3, 0.1),
        life: p.random(100, 255),
        maxLife: p.random(100, 255)
      });
    }
  };

  p.draw = function() {
    // Deep night sky background
    p.background(15, 20, 35);

    // Animate breathing and hovering
    breathe = p.sin(p.frameCount * 0.02) * 3;
    figureY = p.sin(p.frameCount * 0.015) * 2;
    doorGlow = p.sin(p.frameCount * 0.03) * 30 + 60;

    // Draw tower body - angular, fortress-like
    p.fill(40, 45, 55);
    p.stroke(60, 65, 75);
    p.strokeWeight(2);
    p.rect(120, 250, 160, 350);

    // Tower crenellations
    p.fill(35, 40, 50);
    for(let i = 0; i < 4; i++) {
      p.rect(120 + i * 40, 230, 25, 20);
    }

    // Tower door opening - the threshold
    p.fill(5, 10, 20);
    p.stroke(80, 90, 110);
    p.rect(150, 160, 100, 120);

    // Light beyond the door - the invitation
    p.noStroke();
    let glowAlpha = doorGlow / 255;
    for(let r = 100; r > 0; r -= 10) {
      p.fill(255, 240, 180, (100 - r) * glowAlpha * 0.8);
      p.ellipse(200, 220, r, r);
    }

    // Stars beyond - twinkling
    for(let star of stars) {
      star.twinkle += 0.05;
      let brightness = p.sin(star.twinkle) * 50 + 150;
      p.fill(255, 245, 200, brightness);
      p.ellipse(star.x, star.y, star.size, star.size);

      // Star glow
      p.fill(255, 245, 200, brightness * 0.3);
      p.ellipse(star.x, star.y, star.size * 3, star.size * 3);
    }

    // Light particles floating from beyond
    for(let particle of particles) {
      particle.x += particle.vx;
      particle.y += particle.vy;
      particle.life -= 0.5;

      if(particle.life <= 0) {
        particle.x = p.random(140, 260);
        particle.y = p.random(200, 220);
        particle.life = particle.maxLife;
        particle.vx = p.random(-0.5, 0.5);
        particle.vy = p.random(-0.3, 0.1);
      }

      let alpha = particle.life / particle.maxLife;
      p.fill(255, 240, 180, alpha * 100);
      p.ellipse(particle.x, particle.y, 2, 2);
    }

    // Figure at threshold - in the moment of decision
    p.fill(60, 70, 90);
    p.stroke(80, 90, 110);
    p.strokeWeight(1);

    let figX = 200;
    let figYPos = 240 + figureY;

    // Body
    p.ellipse(figX, figYPos + 20, 20, 35);
    // Head
    p.ellipse(figX, figYPos, 12, 12);
    // Arms - one reaching toward the light
    p.line(figX - 10, figYPos + 15, figX - 5 + breathe, figYPos + 10);
    p.line(figX + 10, figYPos + 15, figX + 15 - breathe, figYPos + 5);

    // Subtle glow around figure - caught between worlds
    p.noStroke();
    p.fill(100, 120, 150, 30);
    p.ellipse(figX, figYPos + 10, 40, 60);

    // Ground level suggestions - what's beyond towers
    let mouseInfluence = p.map(p.mouseY, 0, 600, 0, 1);
    p.stroke(80, 120, 100, 50 + mouseInfluence * 30);
    p.strokeWeight(1);
    for(let i = 0; i < 8; i++) {
      let waveY = 450 + p.sin(p.frameCount * 0.01 + i * 0.5) * 10;
      p.line(0, waveY + i * 20, 400, waveY + i * 20);
    }

    // Interactive element - mouse proximity affects the invitation's intensity
    let mouseDistance = p.dist(p.mouseX, p.mouseY, 200, 220);
    let proximity = p.map(p.constrain(mouseDistance, 0, 200), 0, 200, 1, 0);

    // Enhanced glow when mouse is near the threshold
    if(proximity > 0.3) {
      p.fill(255, 240, 180, proximity * 20);
      p.ellipse(200, 220, 150, 150);

      // Additional stars appear
      for(let i = 0; i < proximity * 10; i++) {
        let x = 200 + p.cos(p.frameCount * 0.05 + i) * 60;
        let y = 220 + p.sin(p.frameCount * 0.05 + i) * 40;
        p.fill(255, 255, 255, proximity * 100);
        p.ellipse(x, y, 1, 1);
      }
    }
  };
}

