function sketch(p) {
  let towers = [];
  let numTowers = 10;
  let centerX, centerY;
  let radius;
  let time = 0;
  let particles = [];

  p.setup = function() {
    p.createCanvas(400, 600);
    centerX = p.width / 2;
    centerY = p.height / 2 + 50;
    radius = 120;

    // Create towers in circular arrangement
    for (let i = 0; i < numTowers; i++) {
      let angle = (i / numTowers) * p.TWO_PI - p.PI / 2;
      let x = centerX + p.cos(angle) * radius;
      let y = centerY + p.sin(angle) * radius;

      towers.push({
        x: x,
        y: y,
        height: p.random(60, 120),
        width: p.random(15, 25),
        angle: angle,
        segments: p.floor(p.random(3, 8)),
        phase: p.random(p.TWO_PI)
      });
    }

    // Initialize particles for river effect
    for (let i = 0; i < 50; i++) {
      particles.push({
        x: p.random(p.width),
        y: p.random(p.height),
        size: p.random(1, 3),
        speed: p.random(0.5, 2),
        alpha: p.random(50, 150)
      });
    }
  };

  p.draw = function() {
    // Dark, atmospheric background with subtle gradient
    for (let y = 0; y < p.height; y++) {
      let inter = p.map(y, 0, p.height, 0, 1);
      let c = p.lerpColor(p.color(15, 20, 35), p.color(5, 10, 25), inter);
      p.stroke(c);
      p.line(0, y, p.width, y);
    }

    time += 0.01;

    // Draw flowing river particles (representing time/recurrence)
    p.noStroke();
    for (let particle of particles) {
      p.fill(100, 150, 200, particle.alpha);
      p.circle(particle.x, particle.y, particle.size);

      particle.x += particle.speed;
      if (particle.x > p.width + 10) {
        particle.x = -10;
        particle.y = p.random(p.height);
      }
    }

    // Draw connection lines between towers (the cycle)
    p.stroke(120, 100, 80, 100);
    p.strokeWeight(2);
    p.noFill();
    p.beginShape();
    for (let i = 0; i <= numTowers; i++) {
      let tower = towers[i % numTowers];
      let breathe = p.sin(time * 2 + tower.phase) * 5;
      p.vertex(tower.x + breathe, tower.y);
    }
    p.endShape();

    // Draw towers with recurrence effect
    for (let i = 0; i < numTowers; i++) {
      let tower = towers[i];
      let nextTower = towers[(i + 1) % numTowers];

      // Breathing effect
      let breathe = p.sin(time * 2 + tower.phase) * 3;
      let currentHeight = tower.height + breathe;

      // Tower color based on position in cycle
      let hue = p.map(i, 0, numTowers, 200, 280);
      let sat = 60 + p.sin(time + tower.phase) * 20;
      let bright = 40 + p.sin(time * 0.5 + tower.phase) * 15;

      p.fill(hue, sat, bright);
      p.stroke(hue, sat + 20, bright + 20);
      p.strokeWeight(1);

      // Draw tower segments
      let segmentHeight = currentHeight / tower.segments;
      for (let j = 0; j < tower.segments; j++) {
        let segY = tower.y - (j * segmentHeight);
        let segWidth = tower.width * (1 - j * 0.1);

        // Slight rotation for dynamic feel
        p.push();
        p.translate(tower.x + breathe, segY);
        p.rotate(p.sin(time + tower.phase + j) * 0.02);
        p.rect(-segWidth/2, -segmentHeight/2, segWidth, segmentHeight);
        p.pop();
      }

      // Connection effect showing recurrence
      let connectionOpacity = p.map(p.sin(time * 3 + i), -1, 1, 50, 200);
      p.stroke(255, 200, 150, connectionOpacity);
      p.strokeWeight(2);

      // Line from top of current tower to base of next
      let topX = tower.x + breathe;
      let topY = tower.y - currentHeight;
      let baseX = nextTower.x + p.sin(time * 2 + nextTower.phase) * 3;
      let baseY = nextTower.y;

      // Curved connection showing the cycle
      p.noFill();
      p.bezier(
        topX, topY,
        topX + 30, topY - 20,
        baseX - 30, baseY + 20,
        baseX, baseY
      );
    }

    // Central spiral showing infinite recurrence
    p.stroke(255, 220, 100, 150);
    p.strokeWeight(3);
    p.noFill();

    let spiralRadius = 40 + p.sin(time) * 10;
    p.beginShape();
    for (let angle = 0; angle < p.TWO_PI * 3; angle += 0.1) {
      let r = spiralRadius * (1 - angle / (p.TWO_PI * 3));
      let x = centerX + p.cos(angle + time) * r;
      let y = centerY + p.sin(angle + time) * r;
      p.vertex(x, y);
    }
    p.endShape();

    // Climbing figure (subtle, impressionistic)
    let figureAngle = time * 0.5;
    let figureX = centerX + p.cos(figureAngle) * (radius * 0.7);
    let figureY = centerY + p.sin(figureAngle) * (radius * 0.7);

    p.fill(200, 150, 100, 180);
    p.noStroke();
    p.circle(figureX, figureY, 8);
    p.rect(figureX - 2, figureY + 4, 4, 12);

    // Mouse interaction - towers lean toward cursor
    if (p.mouseX > 0 && p.mouseX < p.width && p.mouseY > 0 && p.mouseY < p.height) {
      for (let tower of towers) {
        let dx = p.mouseX - tower.x;
        let dy = p.mouseY - tower.y;
        let influence = 1 / (p.dist(p.mouseX, p.mouseY, tower.x, tower.y) / 50 + 1);

        p.stroke(255, 255, 255, influence * 100);
        p.strokeWeight(1);
        p.line(tower.x, tower.y - tower.height, 
               tower.x + dx * influence * 0.1, 
               tower.y - tower.height + dy * influence * 0.1);
      }
    }
  };
}

