function sketch(p) {
  let books = [];
  let particles = [];
  let towerStones = [];
  let scaffolding = [];
  let stephen;
  let time = 0;
  let bookPages = [];

  p.setup = function() {
    p.createCanvas(400, 600);

    // Initialize Stephen figure
    stephen = {
      x: 120,
      y: 450,
      sway: 0
    };

    // Create scattered books
    for (let i = 0; i < 12; i++) {
      books.push({
        x: p.random(20, 380),
        y: p.random(480, 580),
        w: p.random(25, 40),
        h: p.random(8, 15),
        angle: p.random(-0.3, 0.3),
        color: p.color(p.random(80, 120), p.random(40, 80), p.random(20, 60)),
        float: p.random(0.5, 1.5)
      });
    }

    // Create tower stones (incomplete tower)
    for (let layer = 0; layer < 8; layer++) {
      let stonesInLayer = layer < 5 ? 4 : p.max(1, 4 - (layer - 4));
      for (let i = 0; i < stonesInLayer; i++) {
        if (p.random() < 0.7 + layer * 0.05) { // Some stones missing at top
          towerStones.push({
            x: 280 + (i - stonesInLayer/2) * 25,
            y: 500 - layer * 20,
            w: 23,
            h: 18,
            placed: layer < 6,
            wobble: p.random(0, p.TWO_PI)
          });
        }
      }
    }

    // Create scaffolding
    for (let i = 0; i < 6; i++) {
      scaffolding.push({
        x1: 250, y1: 500 - i * 25,
        x2: 350, y2: 500 - i * 25,
        alpha: 150 - i * 15
      });
    }

    // Floating book pages
    for (let i = 0; i < 8; i++) {
      bookPages.push({
        x: p.random(50, 350),
        y: p.random(200, 400),
        rotation: p.random(p.TWO_PI),
        drift: p.random(0.5, 1.2),
        size: p.random(15, 25)
      });
    }
  };

  p.draw = function() {
    // Dark Dublin sky with subtle movement
    for (let i = 0; i < p.height; i++) {
      let alpha = p.map(i, 0, p.height, 0.8, 1);
      p.stroke(25 + p.sin(time * 0.01 + i * 0.01) * 5, 
               30 + p.sin(time * 0.008 + i * 0.01) * 8, 
               45 + p.sin(time * 0.012 + i * 0.01) * 10, 
               255 * alpha);
      p.line(0, i, 400, i);
    }

    time += 1;

    // Distant Martello Tower (background reference)
    p.fill(40, 45, 60, 180);
    p.noStroke();
    p.rect(50, 150, 30, 80);
    p.ellipse(65, 150, 35, 20);

    // Floating book pages (intellectual atmosphere)
    p.fill(220, 215, 200, 120);
    bookPages.forEach((page, i) => {
      p.push();
      p.translate(page.x + p.sin(time * 0.01 + i) * 10, 
                  page.y + p.cos(time * 0.008 + i) * 8);
      p.rotate(page.rotation + time * 0.005);
      p.rect(-page.size/2, -page.size/2, page.size, page.size * 1.3);
      // Text lines
      p.stroke(60, 50, 40, 80);
      p.strokeWeight(0.5);
      for (let j = 0; j < 4; j++) {
        p.line(-page.size/3, -page.size/3 + j * 4, page.size/3, -page.size/3 + j * 4);
      }
      p.pop();
    });

    // Ground books (foundation/materials)
    books.forEach((book, i) => {
      p.push();
      p.translate(book.x, book.y + p.sin(time * 0.02 + i) * book.float);
      p.rotate(book.angle);
      p.fill(book.color);
      p.noStroke();
      p.rect(-book.w/2, -book.h/2, book.w, book.h);
      // Book spine detail
      p.fill(p.red(book.color) - 30, p.green(book.color) - 20, p.blue(book.color) - 10);
      p.rect(-book.w/2, -book.h/2, 3, book.h);
      p.pop();
    });

    // Stephen figure
    p.push();
    p.translate(stephen.x + p.sin(time * 0.03) * 2, stephen.y);

    // Body (thin, angular)
    p.fill(20, 18, 25);
    p.noStroke();
    p.rect(-8, -40, 16, 35); // torso

    // Arms (one reaching toward tower, one holding book/pen)
    p.stroke(20, 18, 25);
    p.strokeWeight(4);
    // Reaching arm
    p.line(8, -25, 25 + p.sin(time * 0.04) * 5, -20);
    // Holding arm
    p.line(-8, -25, -20, -15);

    // Head
    p.fill(180, 160, 140);
    p.noStroke();
    p.ellipse(0, -50, 16, 20);

    // Hair (dark, unkempt)
    p.fill(15, 10, 8);
    p.ellipse(0, -58, 20, 12);

    // Eyes (bright, searching)
    p.fill(40, 80, 120);
    p.ellipse(-3, -52, 2, 3);
    p.ellipse(3, -52, 2, 3);

    // Book/pen in hand
    p.fill(140, 120, 100);
    p.rect(-25, -18, 8, 12);
    p.stroke(60, 40, 20);
    p.strokeWeight(2);
    p.line(-21, -25, -21, -10);

    p.pop();

    // Scaffolding (wooden, temporary structure)
    p.stroke(120, 80, 40, 100);
    p.strokeWeight(3);
    scaffolding.forEach((beam, i) => {
      p.stroke(120, 80, 40, beam.alpha + p.sin(time * 0.02 + i) * 20);
      p.line(beam.x1, beam.y1, beam.x2, beam.y2);
      // Vertical supports
      if (i % 2 === 0) {
        p.line(beam.x1, beam.y1, beam.x1, beam.y1 + 25);
        p.line(beam.x2, beam.y2, beam.x2, beam.y2 + 25);
      }
    });

    // Tower stones (incomplete structure)
    towerStones.forEach((stone, i) => {
      let wobbleAmount = stone.placed ? 0 : p.sin(time * 0.05 + stone.wobble) * 2;
      p.fill(stone.placed ? 100 + wobbleAmount * 5 : 120, 
             stone.placed ? 95 + wobbleAmount * 3 : 110, 
             stone.placed ? 85 + wobbleAmount * 2 : 95);
      p.noStroke();
      p.rect(stone.x + wobbleAmount, stone.y + wobbleAmount, stone.w, stone.h);

      // Mortar lines for placed stones
      if (stone.placed) {
        p.stroke(70, 65, 60);
        p.strokeWeight(1);
        p.line(stone.x, stone.y + stone.h, stone.x + stone.w, stone.y + stone.h);
      }
    });

    // Thought particles rising from Stephen (ideas, ambition)
    if (p.frameCount % 8 === 0) {
      particles.push({
        x: stephen.x + p.random(-10, 10),
        y: stephen.y - 50,
        vx: p.random(-0.5, 0.5),
        vy: p.random(-2, -1),
        life: 255,
        size: p.random(2, 6)
      });
    }

    // Update and draw particles
    for (let i = particles.length - 1; i >= 0; i--) {
      let part = particles[i];
      part.x += part.vx;
      part.y += part.vy;
      part.life -= 3;
      part.vy *= 0.995; // Slow down

      p.fill(200, 180, 120, part.life);
      p.noStroke();
      p.ellipse(part.x, part.y, part.size);

      if (part.life <= 0 || part.y < 0) {
        particles.splice(i, 1);
      }
    }

    // Interactive glow around mouse position
    if (p.mouseX > 0 && p.mouseX < 400 && p.mouseY > 0 && p.mouseY < 600) {
      p.fill(100, 120, 140, 30);
      p.noStroke();
      p.ellipse(p.mouseX, p.mouseY, 80, 80);
    }
  };
}

