function sketch(p) {
  let towers = [];
  let particles = [];
  let figure = {};
  let timeOffset = 0;

  p.setup = function() {
    p.createCanvas(400, 600);

    // Initialize towers at different stages
    towers = [
      { x: 80, y: 200, height: 180, stage: 'complete', alpha: 0.8 },
      { x: 150, y: 250, height: 120, stage: 'partial', alpha: 0.6 },
      { x: 220, y: 180, height: 200, stage: 'ruined', alpha: 0.4 },
      { x: 290, y: 240, height: 100, stage: 'abandoned', alpha: 0.5 },
      { x: 340, y: 220, height: 80, stage: 'partial', alpha: 0.3 }
    ];

    // Figure properties
    figure = {
      x: 200,
      y: 450,
      sway: 0
    };

    // Initialize floating particles (dust, memories)
    for(let i = 0; i < 15; i++) {
      particles.push({
        x: p.random(400),
        y: p.random(600),
        size: p.random(2, 6),
        speed: p.random(0.3, 0.8),
        alpha: p.random(30, 80)
      });
    }
  };

  p.draw = function() {
    // Gradient background - twilight wisdom
    for(let i = 0; i <= 600; i++) {
      let inter = p.map(i, 0, 600, 0, 1);
      let c = p.lerpColor(p.color(40, 45, 70), p.color(80, 85, 110), inter);
      p.stroke(c);
      p.line(0, i, 400, i);
    }

    timeOffset += 0.01;

    // Draw floating particles
    p.noStroke();
    for(let particle of particles) {
      p.fill(200, 200, 220, particle.alpha);
      p.ellipse(particle.x, particle.y, particle.size);
      particle.y -= particle.speed;
      particle.x += p.sin(particle.y * 0.01) * 0.5;
      if(particle.y < -10) {
        particle.y = 610;
        particle.x = p.random(400);
      }
    }

    // Draw towers in background
    for(let tower of towers) {
      drawTower(tower);
    }

    // Ground line
    p.stroke(100, 100, 120);
    p.strokeWeight(2);
    p.line(0, 500, 400, 500);

    // Draw the father figure
    drawFigure();

    // Subtle tools on ground
    drawTools();
  };

  function drawTower(tower) {
    p.push();
    p.translate(tower.x, tower.y);

    let segments = Math.floor(tower.height / 30);

    for(let i = 0; i < segments; i++) {
      let segmentAlpha = tower.alpha;

      if(tower.stage === 'ruined' && i > segments * 0.6) {
        segmentAlpha *= p.random(0.3, 0.7);
      } else if(tower.stage === 'partial' && i > segments * 0.7) {
        break;
      } else if(tower.stage === 'abandoned') {
        segmentAlpha *= 0.6;
      }

      p.fill(120 + i * 5, 125 + i * 5, 140 + i * 5, segmentAlpha * 255);
      p.stroke(80, 85, 100, segmentAlpha * 200);
      p.strokeWeight(1);

      let width = 25 - i * 1;
      p.rect(-width/2, -i * 30, width, 28);

      // Windows
      if(tower.stage !== 'ruined' || i < segments * 0.6) {
        p.fill(60, 65, 90, segmentAlpha * 150);
        p.noStroke();
        p.rect(-width/4, -i * 30 + 8, 3, 8);
        p.rect(width/4 - 3, -i * 30 + 8, 3, 8);
      }
    }

    p.pop();
  }

  function drawFigure() {
    figure.sway = p.sin(timeOffset * 2) * 2;

    p.push();
    p.translate(figure.x + figure.sway, figure.y);

    // Shadow
    p.fill(30, 35, 50, 100);
    p.noStroke();
    p.ellipse(0, 50, 60, 15);

    // Body
    p.fill(85, 90, 110);
    p.stroke(60, 65, 85);
    p.strokeWeight(2);
    p.rect(-15, -20, 30, 60, 5);

    // Arms
    p.strokeWeight(6);
    p.stroke(75, 80, 100);
    p.line(-15, -5, -35 + p.sin(timeOffset) * 3, 10);
    p.line(15, -5, 35 - p.sin(timeOffset) * 3, 10);

    // Head
    p.fill(120, 115, 105);
    p.stroke(90, 85, 80);
    p.strokeWeight(2);
    p.ellipse(0, -40, 25, 30);

    // Eyes - kind but weary
    p.fill(40, 50, 70);
    p.noStroke();
    p.ellipse(-5, -42, 3, 2);
    p.ellipse(5, -42, 3, 2);

    // Slight smile
    p.stroke(70, 65, 60);
    p.strokeWeight(1);
    p.noFill();
    p.arc(0, -35, 8, 4, 0, p.PI);

    // Hair - greying
    p.fill(90, 90, 95);
    p.noStroke();
    p.ellipse(0, -50, 20, 10);

    p.pop();
  }

  function drawTools() {
    // Hammer laid down
    p.push();
    p.translate(120 + p.sin(timeOffset * 0.5) * 2, 490);
    p.rotate(0.3);

    p.fill(80, 70, 60);
    p.stroke(60, 50, 40);
    p.strokeWeight(1);
    p.rect(-15, -2, 30, 4);
