function sketch(p) {
  let towers = [];
  let particles = [];
  let mother;
  let groundLevel;

  p.setup = function() {
    p.createCanvas(400, 600);
    groundLevel = p.height * 0.75;

    // Initialize mother figure
    mother = {
      x: p.width * 0.5,
      y: groundLevel - 40,
      breathe: 0
    };

    // Create towers at different distances
    for (let i = 0; i < 8; i++) {
      towers.push({
        x: p.random(p.width),
        y: groundLevel,
        height: p.random(120, 280),
        width: p.random(15, 35),
        sway: p.random(0.01, 0.03),
        phase: p.random(p.TWO_PI),
        distance: p.random(0.3, 1.0)
      });
    }

    // Initialize earth particles
    for (let i = 0; i < 50; i++) {
      particles.push({
        x: p.random(p.width),
        y: p.random(groundLevel, p.height),
        size: p.random(2, 6),
        drift: p.random(-0.5, 0.5),
        glow: p.random(0, p.TWO_PI)
      });
    }
  };

  p.draw = function() {
    // Sky gradient
    for (let i = 0; i <= p.height; i++) {
      let inter = p.map(i, 0, p.height, 0, 1);
      let c = p.lerpColor(p.color(25, 25, 45), p.color(60, 40, 30), inter);
      p.stroke(c);
      p.line(0, i, p.width, i);
    }

    // Draw distant towers first (atmospheric perspective)
    towers.sort((a, b) => a.distance - b.distance);

    for (let tower of towers) {
      let sway = p.sin(p.millis() * tower.sway + tower.phase) * 2;
      let alpha = p.map(tower.distance, 0.3, 1.0, 80, 200);

      p.push();
      p.translate(tower.x + sway, tower.y);

      // Tower body
      p.fill(120, 130, 140, alpha);
      p.stroke(100, 110, 120, alpha);
      p.strokeWeight(1);
      p.rect(-tower.width/2, -tower.height, tower.width, tower.height);

      // Tower segments
      for (let j = 1; j < 5; j++) {
        let segY = -tower.height * (j/5);
        p.stroke(80, 90, 100, alpha * 0.6);
        p.line(-tower.width/2, segY, tower.width/2, segY);
      }

      p.pop();
    }

    // Ground layer
    p.fill(45, 35, 25);
    p.noStroke();
    p.rect(0, groundLevel, p.width, p.height - groundLevel);

    // Earth particles
    for (let particle of particles) {
      particle.x += particle.drift * 0.3;
      particle.glow += 0.02;

      if (particle.x < 0) particle.x = p.width;
      if (particle.x > p.width) particle.x = 0;

      let glowIntensity = p.sin(particle.glow) * 0.3 + 0.7;
      p.fill(80, 60, 40, 150 * glowIntensity);
      p.circle(particle.x, particle.y, particle.size);
    }

    // Mother figure
    mother.breathe += 0.02;
    let breatheOffset = p.sin(mother.breathe) * 2;

    p.push();
    p.translate(mother.x, mother.y + breatheOffset);

    // Mother's aura/grounding
    p.fill(70, 50, 30, 30);
    p.noStroke();
    p.ellipse(0, 20, 120, 40);

    // Dress/robes
    p.fill(60, 45, 35);
    p.stroke(80, 60, 45);
    p.strokeWeight(2);
    p.ellipse(0, 15, 80, 70);

    // Torso
    p.fill(85, 70, 55);
    p.ellipse(0, -15, 50, 60);

    // Arms - hands touching earth
    p.stroke(75, 60, 45);
    p.strokeWeight(8);
    p.line(-25, 0, -35, 25);
    p.line(25, 0, 35, 25);

    // Hands in earth
    p.fill(55, 45, 35);
    p.noStroke();
    p.circle(-35, 25, 12);
    p.circle(35, 25, 12);

    // Head
    p.fill(95, 80, 65);
    p.stroke(85, 70, 55);
    p.strokeWeight(2);
    p.circle(0, -40, 35);

    // Hair
    p.fill(40, 30, 25);
    p.noStroke();
    p.ellipse(0, -50, 45, 25);

    // Eyes - wisdom
    p.fill(30, 40, 50);
    p.circle(-6, -42, 4);
    p.circle(6, -42, 4);

    // Subtle glow around mother
    p.fill(90, 70, 50, 20);
    p.circle(0, -20, 100);

    p.pop();

    // Interactive element - mouse proximity affects earth glow
    let mouseNear = p.dist(p.mouseX, p.mouseY, mother.x, mother.y) < 100;
    if (mouseNear) {
      p.fill(100, 80, 60, 40);
      p.noStroke();
      for (let i = 0; i < 20; i++) {
        let angle = p.random(p.TWO_PI);
        let radius = p.random(50, 80);
        let px = mother.x + p.cos(angle) * radius;
        let py = mother.y + p.sin(angle) * radius;
        p.circle(px, py, p.random(3, 8));
      }
    }

    // Foundation lines - subtle geometric connection
    p.stroke(80, 70, 60, 100);
    p.strokeWeight(1);
    for (let tower of towers) {
      if (tower.distance > 0.7) {
        p.line(mother.x, groundLevel, tower.x, groundLevel);
      }
    }
  };
}

