function sketch(p) {
  let towers = [];
  let backgroundTowers = [];
  let particles = [];
  let time = 0;

  p.setup = function() {
    p.createCanvas(400, 600);

    // Create background towers in various states
    for (let i = 0; i < 12; i++) {
      backgroundTowers.push({
        x: p.random(50, 350),
        y: p.random(400, 550),
        height: p.random(30, 80),
        width: p.random(15, 25),
        alpha: p.random(30, 60),
        sway: p.random(0.5, 2.0)
      });
    }

    // Create main YES towers - Y, E, S
    createYESStructure();

    // Initialize affirmation particles
    for (let i = 0; i < 20; i++) {
      particles.push({
        x: p.random(400),
        y: p.random(600),
        vx: p.random(-0.5, 0.5),
        vy: p.random(-1, -0.2),
        size: p.random(2, 6),
        life: p.random(100, 255),
        maxLife: 255
      });
    }
  };

  function createYESStructure() {
    towers = [];

    // Y - made of towers
    towers.push({letter: 'Y', x: 100, y: 200, segments: [
      {x: 85, y: 200, w: 12, h: 80},
      {x: 115, y: 200, w: 12, h: 80},
      {x: 94, y: 280, w: 12, h: 60}
    ]});

    // E - made of towers
    towers.push({letter: 'E', x: 200, y: 200, segments: [
      {x: 185, y: 200, w: 12, h: 140},
      {x: 197, y: 200, w: 25, h: 12},
      {x: 197, y: 260, w: 20, h: 12},
      {x: 197, y: 328, w: 25, h: 12}
    ]});

    // S - made of towers
    towers.push({letter: 'S', x: 300, y: 200, segments: [
      {x: 285, y: 200, w: 25, h: 12},
      {x: 285, y: 212, w: 12, h: 35},
      {x: 297, y: 247, w: 20, h: 12},
      {x: 305, y: 259, w: 12, h: 35},
      {x: 285, y: 294, w: 25, h: 12}
    ]});
  }

  p.draw = function() {
    time += 0.01;

    // Dynamic gradient background - cold blues warming toward affirmation
    for (let y = 0; y < p.height; y++) {
      let inter = p.map(y, 0, p.height, 0, 1);
      let warmth = p.map(p.sin(time * 0.5), -1, 1, 0, 30);
      let c = p.lerpColor(
        p.color(40 + warmth, 60 + warmth, 120 + warmth),
        p.color(20, 40 + warmth, 80 + warmth),
        inter
      );
      p.stroke(c);
      p.line(0, y, p.width, y);
    }

    // Draw background towers - the history of tower-building
    p.noStroke();
    for (let tower of backgroundTowers) {
      let sway = p.sin(time * tower.sway) * 2;
      p.fill(80, 90, 120, tower.alpha);
      p.push();
      p.translate(tower.x + sway, tower.y);
      p.rect(-tower.width/2, 0, tower.width, -tower.height);
      // Tower cap
      p.triangle(-tower.width/2-2, -tower.height, 
                tower.width/2+2, -tower.height,
                0, -tower.height-8);
      p.pop();
    }

    // Draw YES towers with architectural detail
    p.stroke(200, 210, 240, 150);
    p.strokeWeight(1);

    for (let tower of towers) {
      for (let segment of tower.segments) {
        let pulse = p.map(p.sin(time * 2), -1, 1, 0.95, 1.05);
        let mouseInfluence = 1 + p.map(p.dist(p.mouseX, p.mouseY, segment.x, segment.y), 0, 100, 0.1, 0);

        p.push();
        p.translate(segment.x + segment.w/2, segment.y + segment.h/2);
        p.scale(pulse * mouseInfluence);

        // Main tower block - cold stone warming to yes
        let warmth = p.map(p.sin(time + segment.x * 0.01), -1, 1, 0, 40);
        p.fill(100 + warmth, 120 + warmth, 160 + warmth);
        p.rect(-segment.w/2, -segment.h/2, segment.w, segment.h);

        // Stone texture lines
        p.stroke(80 + warmth, 90 + warmth, 140 + warmth);
        for (let i = 0; i < segment.h; i += 8) {
          p.line(-segment.w/2, -segment.h/2 + i, segment.w/2, -segment.h/2 + i);
        }

        // Vertical emphasis
        p.stroke(120 + warmth, 140 + warmth, 180 + warmth);
        p.line(0, -segment.h/2, 0, segment.h/2);

        p.pop();
      }
    }

    // Affirmation particles - yes rising upward
    p.noStroke();
    for (let i = particles.length - 1; i >= 0; i--) {
      let particle = particles[i];

      particle.x += particle.vx + p.map(p.sin(time + particle.x * 0.01), -1, 1, -0.2, 0.2);
      particle.y += particle.vy;
      particle.life -= 1;

      let alpha = p.map(particle.life, 0, particle.maxLife, 0, 150);
      let warmth = p.map(particle.y, p.height, 0, 0, 60);
      p.fill(140 + warmth, 160 + warmth, 200 + warmth, alpha);

      p.ellipse(particle.x, particle.y, particle.size);

      if (particle.life <= 0 || particle.y < 0) {
        particles.splice(i, 1);
        // Respawn from bottom
        particles.push({
          x: p.random(400),
          y: p.random(580, 620),
          vx: p.random(-0.5, 0.5),
          vy: p.random(-1, -0.2),
          size: p.random(2, 6),
          life: p.random(100, 255),
          maxLife: 255
        });
      }
    }

    // Subtle figure - the affirmer
    let figureAlpha = p.map(p.sin(time * 0.7), -1, 1, 30, 80);
    p.fill(180, 200, 240, figureAlpha);
    p.noStroke();
    p.ellipse(200, 450, 30, 30); // head
    p.rect(190, 465, 20, 40); // body
    p.rect(185, 485, 8, 25); // left leg
    p.rect(207, 485, 8, 25); // right leg

    // Arms raised in affirmation
