    p.translate(200, 480);
    p.rotate(p.sin(time) * 0.1);
    p.rect(-15, -10, 8, 20); // left arm up
    p.rect(7, -10, 8, 20); // right arm up
    p.pop();

    // Vertical emphasis lines - the reach upward
    p.stroke(160, 180, 220, 60);
    p.strokeWeight(2);
    for (let x = 50; x < p.width; x += 40) {
      let wave = p.sin(time + x * 0.01) * 10;
      p.line(x + wave, p.height, x + wave/2, 0);
    }

    // Mouse interaction - tower resonance
    if (p.mouseX > 0 && p.mouseX < p.width && p.mouseY > 0 && p.mouseY < p.height) {
      p.stroke(200, 220, 250, 100);
      p.strokeWeight(1);
      p.noFill();
      let ripple = p.map(p.sin(time * 4), -1, 1, 5, 15);
      p.ellipse(p.mouseX, p.mouseY, ripple * 4, ripple * 4);
    }
  };
}

