function sketch(p) {
  let keys = [];
  let figure;
  let doors = [];
  let particles = [];
  let time = 0;

  p.setup = function() {
    p.createCanvas(400, 600);

    // Initialize keys
    keys.push({
      x: 120,
      y: 300,
      rotation: 0,
      opacity: 255,
      age: 1,
      ornate: true,
      size: 1.2
    });

    keys.push({
      x: 280,
      y: 300,
      rotation: 0,
      opacity: 100,
      age: 0,
      ornate: false,
      size: 1.0
    });

    // Initialize figure
    figure = {
      x: 200,
      y: 350,
      armLeft: 0,
      armRight: 0
    };

    // Initialize doors
    doors.push({x: 80, y: 150, alpha: 180});
    doors.push({x: 320, y: 150, alpha: 80});

    // Initialize particles
    for(let i = 0; i < 30; i++) {
      particles.push({
        x: p.random(400),
        y: p.random(600),
        vx: p.random(-0.5, 0.5),
        vy: p.random(-0.5, 0.5),
        size: p.random(2, 6),
        alpha: p.random(30, 100)
      });
    }
  };

  p.draw = function() {
    time += 0.01;

    // Gradient background
    for(let i = 0; i <= p.height; i++) {
      let inter = p.map(i, 0, p.height, 0, 1);
      let c = p.lerpColor(p.color(20, 30, 60), p.color(80, 60, 40), inter);
      p.stroke(c);
      p.line(0, i, p.width, i);
    }

    // Update and draw particles
    drawParticles();

    // Draw doors
    drawDoors();

    // Update keys based on mouse proximity
    updateKeys();

    // Draw circular flow pattern
    drawMandala();

    // Draw keys
    drawKeys();

    // Draw figure
    drawFigure();
  };

  function updateKeys() {
    let mouseInfluence = p.dist(p.mouseX, p.mouseY, 200, 300) / 200;
    let transition = p.map(p.sin(time), -1, 1, 0, 1);

    // Old key fading
    keys[0].opacity = p.lerp(255, 50, transition * (1 - mouseInfluence * 0.5));
    keys[0].rotation = time * 0.5;

    // New key brightening
    keys[1].opacity = p.lerp(100, 255, transition * (1 + mouseInfluence * 0.3));
    keys[1].rotation = -time * 0.3;

    // Figure's contemplation
    figure.armLeft = p.sin(time * 0.7) * 10;
    figure.armRight = p.cos(time * 0.8) * 8;
  }

  function drawParticles() {
    for(let particle of particles) {
      particle.x += particle.vx;
      particle.y += particle.vy;

      if(particle.x < 0 || particle.x > p.width) particle.vx *= -1;
      if(particle.y < 0 || particle.y > p.height) particle.vy *= -1;

      p.fill(255, 215, 0, particle.alpha);
      p.noStroke();
      p.ellipse(particle.x, particle.y, particle.size);
    }
  }

  function drawMandala() {
    p.push();
    p.translate(200, 300);
    p.noFill();

    for(let r = 50; r < 200; r += 30) {
      let alpha = p.map(r, 50, 200, 100, 20);
      p.stroke(255, 215, 0, alpha);
      p.strokeWeight(1);

      p.beginShape();
      for(let a = 0; a < p.TWO_PI; a += 0.1) {
        let radius = r + p.sin(a * 3 + time * 2) * 10;
        let x = p.cos(a + time * 0.5) * radius;
        let y = p.sin(a + time * 0.5) * radius;
        p.vertex(x, y);
      }
      p.endShape(p.CLOSE);
    }
    p.pop();
  }

  function drawDoors() {
    for(let i = 0; i < doors.length; i++) {
      let door = doors[i];
      p.fill(100, 80, 60, door.alpha);
      p.stroke(150, 130, 100, door.alpha);
      p.strokeWeight(2);
      p.rect(door.x - 40, door.y, 80, 120, 5);

      // Door handle
      p.fill(255, 215, 0, door.alpha);
      p.noStroke();
      p.ellipse(door.x + 25, door.y + 60, 6);
    }
  }

  function drawKeys() {
    for(let i = 0; i < keys.length; i++) {
      let key = keys[i];

      p.push();
      p.translate(key.x, key.y);
      p.rotate(key.rotation);
      p.scale(key.size);

      // Key body
      let goldColor = p.color(255, 215, 0, key.opacity);
      p.fill(goldColor);
      p.stroke(200, 170, 0, key.opacity);
      p.strokeWeight(1);

      // Key shaft
      p.rect(-30, -4, 50, 8, 4);

      // Key head
      if(key.ornate) {
        // Ornate key head
        p.ellipse(25, 0, 25, 25);
