function sketch(p) {
  let keys = [];
  let center;
  let particles = [];
  let time = 0;
  let bloomFigure = {};

  p.setup = function() {
    p.createCanvas(400, 600);
    center = p.createVector(200, 300);

    // Initialize three keys in triangular formation
    let radius = 120;
    for (let i = 0; i < 3; i++) {
      let angle = (i * p.TWO_PI / 3) - p.PI/2;
      let pos = p.createVector(
        center.x + p.cos(angle) * radius,
        center.y + p.sin(angle) * radius
      );
      keys.push({
        pos: pos,
        basePos: pos.copy(),
        type: i, // 0: intellectual, 1: embodied, 2: compassionate
        rotation: angle + p.PI/2,
        floatOffset: i * p.TWO_PI / 3,
        glowIntensity: 0
      });
    }

    // Initialize Bloom figure at center
    bloomFigure = {
      pos: center.copy(),
      alpha: 150
    };

    // Initialize flowing particles
    for (let i = 0; i < 60; i++) {
      particles.push({
        pos: p.createVector(p.random(400), p.random(600)),
        vel: p.createVector(p.random(-0.5, 0.5), p.random(-0.5, 0.5)),
        size: p.random(2, 6),
        life: p.random(1)
      });
    }
  };

  p.draw = function() {
    time += 0.02;

    // Deep blue to warm gold gradient background
    for (let y = 0; y < p.height; y++) {
      let inter = p.map(y, 0, p.height, 0, 1);
      let c = p.lerpColor(p.color(20, 40, 80), p.color(40, 60, 100), inter);
      p.stroke(c);
      p.line(0, y, p.width, y);
    }

    // Draw connecting mandala patterns
    drawMandalaConnections();

    // Update and draw flowing particles
    drawFlowingParticles();

    // Draw the three keys
    for (let i = 0; i < keys.length; i++) {
      updateKey(keys[i], i);
      drawKey(keys[i], i);
    }

    // Draw central Bloom figure
    drawBloomFigure();

    // Draw central lock/portal
    drawCentralLock();
  };

  function drawMandalaConnections() {
    p.push();
    p.translate(center.x, center.y);

    // Celtic knot-work connecting the keys
    p.noFill();
    for (let layer = 0; layer < 3; layer++) {
      let alpha = 80 - layer * 20;
      let radius = 60 + layer * 30;

      p.strokeWeight(2 - layer * 0.5);
      p.stroke(180, 140, 60, alpha + p.sin(time + layer) * 20);

      p.beginShape();
      for (let a = 0; a < p.TWO_PI; a += 0.1) {
        let r = radius + p.sin(a * 3 + time) * 15;
        let x = p.cos(a) * r;
        let y = p.sin(a) * r;
        p.vertex(x, y);
      }
      p.endShape(p.CLOSE);
    }

    // Triangular connection lines with flowing energy
    p.strokeWeight(1);
    for (let i = 0; i < 3; i++) {
      let key1 = keys[i];
      let key2 = keys[(i + 1) % 3];

      let flow = p.sin(time * 2 + i) * 0.5 + 0.5;
      p.stroke(220, 180, 80, 100 + flow * 100);

      drawFlowingLine(key1.pos, key2.pos, time + i);
    }

    p.pop();
  };

  function drawFlowingLine(pos1, pos2, timeOffset) {
    p.beginShape();
    p.noFill();
    let steps = 20;
    for (let i = 0; i <= steps; i++) {
      let t = i / steps;
      let x = p.lerp(pos1.x, pos2.x, t);
      let y = p.lerp(pos1.y, pos2.y, t);

      // Add flowing wave motion
      let perpX = -(pos2.y - pos1.y);
      let perpY = (pos2.x - pos1.x);
      let len = p.sqrt(perpX * perpX + perpY * perpY);
      perpX /= len;
      perpY /= len;

      let wave = p.sin(t * p.PI * 2 + timeOffset) * 10;
      x += perpX * wave;
      y += perpY * wave;

      p.vertex(x, y);
    }
    p.endShape();
  }

  function drawFlowingParticles() {
    for (let particle of particles) {
      // Move particles in circular flow around center
      let angleToCenter = p.atan2(particle.pos.y - center.y, particle.pos.x - center.x);
      let distToCenter = p.dist(particle.pos.x, particle.pos.y, center.x, center.y);

      let flowForce = p.createVector(-p.sin(angleToCenter), p.cos(angleToCenter));
      flowForce.mult(0.3);
      particle.vel.add(flowForce);
      particle.vel.mult(0.98);

      particle.pos.add(particle.vel);

      // Wrap around edges
      if (particle.pos.x < 0) particle.pos.x = 400;
      if (particle.pos.x > 400) particle.pos.x = 0;
      if (particle.pos.y < 0) particle.pos.y = 600;
      if (particle.pos.y > 600) particle.pos.y = 0;

      // Draw particle
      let alpha = p.map(distToCenter, 0, 200, 100, 20);
      p.fill(220, 180, 80, alpha);
      p.noStroke();
      p.ellipse(particle.pos.x, particle.pos.y, particle.size, particle.size);
    }
  }

  function updateKey(key, index) {
    // Gentle floating motion
    key.pos.y = key.basePos.y + p.sin(time + key.floatOffset) * 8;
    key.pos.x = key.basePos.x + p.cos(time * 0.7 + key.floatOffset) * 3;

    // Mouse interaction - glow when near
    let mouseDistance = p.dist(p.mouseX, p.mouseY, key.pos.x, key.pos.y);
    key.glowIntensity = p.map(mouseDistance, 0, 100, 255, 0);
    key.glowIntensity = p.constrain(key.glowIntensity, 0, 255);
  }

  function drawKey(key, index) {
    p.push();
    p.translate(key.pos.x, key.pos.y);
    p.rotate(key.rotation + p.sin(time + key.floatOffset) * 0.1);

    // Glow effect
    if (key.glowIntensity > 0) {
      p.fill(220, 180, 80, key.glowIntensity * 0.3);
      p.noStroke();
      p.ellipse(0, 0, 80, 80);
    }

    if (index === 0) {
      // Intellectual key - ornate with symbols
      drawIntellectualKey();
    } else if (index === 1) {
      // Embodied key - simple, warm
      drawEmbodiedKey();
    } else {
      // Compassionate key - heart-shaped bow
      drawCompassionateKey();
    }

    p.pop();
  }

  function drawIntellectualKey() {
    // Key shaft
    p.strokeWeight(4);
    p.stroke(60, 80, 140);
    p.fill(80, 100, 160);
    p.rect(-3, -30, 6, 40);

    // Ornate head with symbols
    p.fill(100, 120, 180);
    p.ellipse(0, -35, 25, 25);

    // Symbolic decorations
    p.strokeWeight(2);
    p.stroke(180, 200, 255);
    p.line(-8, -35, 8, -35);
    p.line(0, -43, 0, -27);

    // Key teeth - complex pattern
    p.strokeWeight(3);
    p.stroke(60, 80, 140);
    p.line(3, 5, 12, 5);
    p.line(3, 0, 8, 0);
    p.line(3, -5, 10, -5);
  }

  function drawEmbodiedKey() {
    // Simple, warm key
    p.strokeWeight(5);
    p.stroke(140, 100, 60);
    p.fill(160, 120, 80);

    // Key shaft
    p.rect(-2.5, -25, 5, 35);

    // Simple round head
    p.ellipse(0, -30, 20, 20);

    // Simple teeth
    p.strokeWeight(4);
    p.line(2.5, 5, 8, 5);
    p.line(2.5, 0, 6, 0);
  }

  function drawCompassionateKey() {
    // Heart-shaped bow
    p.fill(140, 80, 100);
    p.stroke(120, 60, 80);
    p.strokeWeight(2);

    // Heart shape
    p.push();
    p.translate(0, -30);
    p.beginShape();
    for (let a = 0; a < p.TWO_PI; a += 0.1) {
      let r = 8 * (1 - p.cos(a));
      let x = r * p.cos(a);
      let y = r * p.sin(a) - 3;
      p.vertex(x, y);
    }
    p.endShape(p.CLOSE);
    p.pop();

    // Key shaft
    p.strokeWeight(4);
    p.stroke(120, 80, 100);
    p.fill(140, 100, 120);
    p.rect(-2, -20, 4, 30);

    // Gentle curved teeth
    p.strokeWeight(3);
    p.line(2, 5, 9, 8);
    p.line(2, 0, 7, 2);
  }

  function drawBloomFigure() {
    p.push();
    p.translate(center.x, center.y);

    // Subtle figure at center
    let alpha = 80 + p.sin(time) * 20;
    p.fill(200, 180, 140, alpha);
    p.noStroke();

    // Simple abstracted figure
    p.ellipse(0, -10, 15, 20); // head
    p.ellipse(0, 5, 12, 25);   // body

    p.pop();
  }

  function drawCentralLock() {
    p.push();
    p.translate(center.x, center.y + 20);

    // Central lock that all three keys unlock
    p.strokeWeight(3);
    p.stroke(80, 60, 40);
    p.fill(100, 80, 60, 150);

    // Lock body
    p.rect(-12, -8, 24, 16, 4);

    // Keyhole - trinity symbol
    p.fill(20, 20, 40);
    p.ellipse(0, -2, 8, 8);
    p.rect(-1, 2, 2, 6);

    // Subtle glow indicating the three-key system
    let glow = p.sin(time * 1.5) * 30 + 50;
    p.fill(220, 180, 80, glow);
    p.noStroke();
    p.ellipse(0, 0, 35, 35);

    p.pop();
  }
}

