      radius: 120,
      speed: 0.005,
      keys: []
    };

    // Create floating keys around Bloom
    for (let i = 0; i < 5; i++) {
      bloom.keys.push({
        angle: i * p.TWO_PI / 5,
        distance: 25 + i * 5,
        rotation: 0
      });
    }

    // Create circular street pattern with keys
    for (let r = 80; r <= 180; r += 50) {
      let numKeys = p.floor(r / 10);
      for (let i = 0; i < numKeys; i++) {
        let angle = i * p.TWO_PI / numKeys;
        keys.push({
          x: 200 + p.cos(angle) * r,
          y: 300 + p.sin(angle) * r,
          rotation: angle + p.PI/2,
          size: p.random(8, 15),
          glow: p.random(0.5, 1)
        });
      }
    }

    // Create keyholes in buildings
    for (let i = 0; i < 20; i++) {
      let angle = p.random(p.TWO_PI);
      let radius = p.random(200, 280);
      keyholes.push({
        x: 200 + p.cos(angle) * radius,
        y: 300 + p.sin(angle) * radius,
        size: p.random(6, 12),
        pulse: p.random(p.TWO_PI)
      });
    }

    // Create building outlines in circular pattern
    for (let a = 0; a < p.TWO_PI; a += 0.3) {
      let r = p.random(220, 300);
      buildings.push({
        x: 200 + p.cos(a) * r,
        y: 300 + p.sin(a) * r,
        width: p.random(15, 25),
        height: p.random(20, 40),
        angle: a
      });
    }

    // River flow particles
    for (let i = 0; i < 30; i++) {
      riverFlow.push({
        x: p.random(50, 350),
        y: 280 + p.random(-20, 20),
        speed: p.random(0.5, 1.5),
        size: p.random(2, 4)
      });
    }

    // Golden particles
    for (let i = 0; i < 50; i++) {
      particles.push({
        x: p.random(400),
        y: p.random(600),
        vx: p.random(-0.5, 0.5),
        vy: p.random(-0.5, 0.5),
        size: p.random(1, 3),
        alpha: p.random(100, 255)
      });
