    p.strokeWeight(3);
    p.stroke(100, 150, 200, 150);
    p.beginShape();
    for (let x = 0; x < p.width; x += 5) {
      let y = 280 + 30 * p.sin(x * 0.01 + p.millis() * 0.001);
      p.vertex(x, y);
    }
    p.endShape();

    // Draw river flow particles
