    p.noStroke();
    for (let particle of riverFlow) {
      p.circle(particle.x, particle.y, particle.size);
      particle.x += particle.speed;
      if (particle.x > p.width + 10) {
        particle.x = -10;
      }
    }

    // Draw circular street pattern
    p.noFill();
    p.stroke(180, 140, 80, 100);
    p.strokeWeight(2);
    for (let r = 80; r <= 180; r += 50) {
      p.circle(200, 300, r * 2);
    }

    // Draw radiating streets
    p.strokeWeight(1);
    for (let i = 0; i < 12; i++) {
      let angle = i * p.TWO_PI / 12;
      let x1 = 200 + p.cos(angle) * 80;
      let y1 = 300 + p.sin(angle) * 80;
      let x2 = 200 + p.cos(angle) * 180;
      let y2 = 300 + p.sin(angle) * 180;
      p.line(x1, y1, x2, y2);
    }

