    // Draw keyholes with pulsing glow
    for (let keyhole of keyholes) {
      let pulse = p.sin(p.millis() * 0.003 + keyhole.pulse) * 0.5 + 0.5;
      p.fill(50, 30, 20);
      p.noStroke();
      p.circle(keyhole.x, keyhole.y, keyhole.size);
      p.fill(255, 200, 100, pulse * 100);
      p.circle(keyhole.x, keyhole.y, keyhole.size * 1.5);
    }

    // Draw keys
    p.stroke(255, 200, 50);
    p.strokeWeight(2);
    p.fill(255, 220, 100);
    for (let key of keys) {
      let glow = p.sin(p.millis() * 0.002 + key.x * 0.1) * 0.3 + 0.7;
      p.push();
      p.translate(key.x, key.y);
      p.rotate(key.rotation);
      p.scale(key.size / 10);

      // Key glow
      p.fill(255, 220, 100, glow * key.glow * 100);
      p.noStroke();
      p.circle(0, 0, 2);

      // Key shape
      p.fill(255, 200, 50);
      p.stroke(200, 160, 30);
      p.strokeWeight(0.5);
      p.circle(0, -0.7, 1.4); // key head
      p.rect(-0.1, 0, 0.2, 1.5); // key shaft
      p.rect(0.1, 1.2, 0.3, 0.2); // key teeth
      p.pop();
    }

    // Update and draw Bloom
    bloom.angle += bloom.speed;
    bloom.x = 200 + p.cos(bloom.angle) * bloom.radius;
    bloom.y = 300 + p.sin(bloom.angle) * bloom.radius;

    // Draw Bloom's keys orbiting around him
    for (let i = 0; i < bloom.keys.length; i++) {
      let key = bloom.keys[i];
      key.rotation += 0.02;
      let keyX = bloom.x + p.cos(key.angle + p.millis() * 0.001) * key.distance;
      let keyY = bloom.y + p.sin(key.angle + p.millis() * 0.001) * key.distance;

      p.push();
      p.translate(keyX, keyY);
      p.rotate(key.rotation);
      p.fill(255, 230, 120);
      p.stroke(220, 180, 60);
      p.strokeWeight(1);
      p.circle(0, -3, 6); // key head
      p.rect(-0.5, 0, 1, 8); // key shaft
      p.rect(0.5, 6, 2, 1); // key teeth
      p.pop();
    }

    // Draw Bloom figure
    p.fill(80, 60, 40);
    p.noStroke();
    p.circle(bloom.x, bloom.y, 8); // body
    p.fill(120, 90, 60);
    p.circle(bloom.x, bloom.y - 6, 5); // head

    // Mouse interaction - keys gravitate toward mouse
    let mouseForce = p.map(p.mouseX + p.mouseY, 0, p.width + p.height, 0.98, 1.02);
    for (let key of keys) {
      key.rotation += 0.01 * mouseForce;
      key.glow *= mouseForce;
    }

    // Draw golden particles
    p.noStroke();
    for (let particle of particles) {
      p.fill(255, 215, 100, particle.alpha);
      p.circle(particle.x, particle.y, particle.size);
      particle.x += particle.vx;
      particle.y += particle.vy;

      if (particle.x < 0 || particle.x > p.width) particle.vx *= -1;
      if (particle.y < 0 || particle.y > p.height) particle.vy *= -1;

      particle.alpha += p.sin(p.millis() * 0.005 + particle.x * 0.1) * 2;
      particle.alpha = p.constrain(particle.alpha, 50, 255);
    }

    // Central mandala pattern
    p.push();
    p.translate(200, 300);
    p.rotate(p.millis() * 0.0005);
    p.noFill();
    p.stroke(255, 200, 100, 80);
    p.strokeWeight(1);
    for (let i = 0; i < 8; i++) {
      let angle = i * p.PI / 4;
      p.line(0, 0, p.cos(angle) * 40, p.sin(angle) * 40);
    }
    p.circle(0, 0, 60);
    p.pop();
  };
}

