function sketch(p) {
  let particles = [];
  let doorPulse = 0;
  let keyRotation = 0;
  let bloomX = 80;
  let bloomY = 300;
  let hiddenDoorAlpha = 0;

  p.setup = function() {
    p.createCanvas(400, 600);

    // Initialize golden particles around the key
    for (let i = 0; i < 20; i++) {
      particles.push({
        x: bloomX + 40,
        y: bloomY - 20,
        vx: p.random(-0.5, 0.5),
        vy: p.random(-0.5, 0.5),
        size: p.random(2, 4),
        life: p.random(100, 200)
      });
    }
  };

  p.draw = function() {
    // Background gradient - Dublin grey stone
    for (let i = 0; i <= p.height; i++) {
      let alpha = p.map(i, 0, p.height, 0.8, 0.3);
      p.stroke(60 + i * 0.1, 65 + i * 0.08, 70 + i * 0.06, alpha * 255);
      p.line(0, i, p.width, i);
    }

    // City grid background - four-square pattern
    p.stroke(40, 45, 50, 80);
    p.strokeWeight(1);
    for (let x = 0; x < p.width; x += 40) {
      for (let y = 0; y < p.height; y += 40) {
        p.noFill();
        p.rect(x, y, 40, 40);
      }
    }

    // Regular city doors and locks (four-square)
    p.fill(45, 50, 55);
    p.noStroke();

    // Background doors that don't respond to the key
    for (let i = 0; i < 3; i++) {
      let doorX = 250 + i * 60;
      let doorY = 150 + i * 100;
      p.rect(doorX, doorY, 50, 80);

      // Four-square locks
      p.fill(30, 35, 40);
      p.rect(doorX + 35, doorY + 35, 10, 10);
      p.fill(45, 50, 55);
    }

    // Hidden door that responds to Bloom's key
    hiddenDoorAlpha = p.map(p.sin(p.frameCount * 0.02), -1, 1, 50, 150);
    let doorGlow = p.map(p.sin(p.frameCount * 0.03), -1, 1, 0, 30);

    // Hidden door outline
    p.stroke(200, 180, 100, hiddenDoorAlpha);
    p.strokeWeight(2 + doorGlow * 0.1);
    p.noFill();
    p.rect(300, 350, 60, 90);

    // Hidden door interior - only visible when key is near
    let keyDistance = p.dist(bloomX + 40, bloomY - 20, 330, 395);
    let doorVisibility = p.map(keyDistance, 50, 200, 255, 0);
    doorVisibility = p.constrain(doorVisibility, 0, 100);

    p.fill(80, 60, 40, doorVisibility);
    p.noStroke();
    p.rect(302, 352, 56, 86);

    // Bloom figure
    p.fill(60, 45, 35);
    p.noStroke();

    // Body
    p.ellipse(bloomX, bloomY, 25, 40);

    // Head
    p.fill(80, 65, 55);
    p.ellipse(bloomX, bloomY - 35, 20, 20);

    // Arms
    p.fill(60, 45, 35);
    p.ellipse(bloomX - 15, bloomY - 5, 8, 25);
    p.ellipse(bloomX + 15, bloomY - 5, 8, 25);

    // Legs
    p.ellipse(bloomX - 8, bloomY + 25, 8, 30);
    p.ellipse(bloomX + 8, bloomY + 25, 8, 30);

    // The five-pointed key - warm gold
    p.push();
    p.translate(bloomX + 40, bloomY - 20);
    p.rotate(keyRotation);

    // Key glow
    let glowIntensity = p.map(p.sin(p.frameCount * 0.05), -1, 1, 20, 40);
    for (let r = 30; r > 0; r -= 3) {
      p.fill(255, 215, 100, glowIntensity * (30 - r) / 30);
      p.noStroke();
      p.ellipse(0, 0, r, r);
    }

    // Key shaft
    p.stroke(255, 215, 0);
    p.strokeWeight(4);
    p.line(0, 0, 30, 0);

    // Five-pointed star head
    p.fill(255, 215, 0);
    p.noStroke();
    p.star(0, 0, 8, 15, 5);

    // Key teeth (irregular, unlike four-square locks)
    p.stroke(255, 215, 0);
    p.strokeWeight(2);
    p.line(25, 0, 25, -5);
    p.line(28, 0, 28, 3);
    p.line(30, 0, 30, -7);

