function sketch(p) {
  let keys = [];
  let mandalas = [];
  let connectionLines = [];
  let time = 0;
  let figure1, figure2;

  p.setup = function() {
    p.createCanvas(400, 600);

    // Initialize figures
    figure1 = { x: 100, y: 450, keyAngle: 0 };
    figure2 = { x: 300, y: 450, keyAngle: 0 };

    // Create keys for each figure
    keys.push({
      x: figure1.x,
      y: figure1.y - 50,
      angle: 0,
      glow: 0,
      size: 1
    });

    keys.push({
      x: figure2.x,
      y: figure2.y - 50,
      angle: 0,
      glow: 0,
      size: 1
    });

    // Initialize connection mandalas
    for(let i = 0; i < 8; i++) {
      mandalas.push({
        x: p.lerp(figure1.x, figure2.x, i / 7),
        y: p.lerp(figure1.y - 50, figure2.y - 50, i / 7) + p.sin(i * 0.5) * 30,
        rotation: 0,
        opacity: 0,
        size: 20 + i * 5
      });
    }
  };

  p.draw = function() {
    // Deep Dublin evening sky gradient
    for(let i = 0; i < p.height; i++) {
      let inter = p.map(i, 0, p.height, 0, 1);
      let c = p.lerpColor(p.color(25, 25, 45), p.color(65, 45, 85), inter);
      p.stroke(c);
      p.line(0, i, p.width, i);
    }

    time += 0.02;
    let recognitionStrength = (p.sin(time * 0.5) + 1) * 0.5;
    let mouseInfluence = p.map(p.mouseX, 0, p.width, 0.5, 1.5);

    // Draw connection mandalas
    for(let i = 0; i < mandalas.length; i++) {
      let mandala = mandalas[i];
      mandala.rotation += 0.01 + i * 0.002;
      mandala.opacity = recognitionStrength * 150 * mouseInfluence;

      p.push();
      p.translate(mandala.x, mandala.y);
      p.rotate(mandala.rotation);
      p.noFill();
      p.stroke(255, 200, 100, mandala.opacity);
      p.strokeWeight(2);

      // Draw circular mandala pattern
      for(let j = 0; j < 6; j++) {
        let angle = (p.TWO_PI / 6) * j;
        let x1 = p.cos(angle) * mandala.size;
        let y1 = p.sin(angle) * mandala.size;
        let x2 = p.cos(angle + p.PI) * mandala.size * 0.3;
        let y2 = p.sin(angle + p.PI) * mandala.size * 0.3;
        p.line(x1, y1, x2, y2);
        p.circle(x1, y1, 8);
      }
      p.pop();
    }

    // Draw figures as silhouettes
    p.fill(40, 40, 60, 180);
    p.noStroke();

    // Figure 1 (Bloom-like)
    p.ellipse(figure1.x, figure1.y - 80, 25, 35); // head
    p.rect(figure1.x - 15, figure1.y - 65, 30, 50, 5); // body
    p.rect(figure1.x - 8, figure1.y - 15, 16, 35, 3); // legs

    // Figure 2 (Stephen-like)
    p.ellipse(figure2.x, figure2.y - 80, 22, 32);
    p.rect(figure2.x - 12, figure2.y - 65, 24, 48, 5);
    p.rect(figure2.x - 7, figure2.y - 17, 14, 37, 3);

    // Update and draw keys
    for(let i = 0; i < keys.length; i++) {
      let key = keys[i];
      key.angle += 0.03;
      key.glow = recognitionStrength * 255 * mouseInfluence;
      key.size = 1 + recognitionStrength * 0.3;

      p.push();
      p.translate(key.x, key.y);
      p.rotate(p.sin(time + i * p.PI) * 0.2);
      p.scale(key.size);

      // Key glow
      p.fill(255, 200, 100, key.glow * 0.3);
      p.noStroke();
      p.circle(0, 0, 60);

      // Key body
      p.stroke(255, 200, 100, key.glow);
      p.strokeWeight(4);
      p.noFill();
      p.line(-15, 0, 15, 0); // shaft

      // Key head (different patterns for each)
      if(i === 0) {
        p.circle(-18, 0, 12);
        p.line(-18, -6, -18, 6);
      } else {
        p.rect(-22, -6, 8, 12, 2);
        p.line(-18, -3, -18, 3);
      }

      // Key teeth (complementary patterns)
      if(i === 0) {
        p.line(12, -4, 15, -4);
        p.line(15, -4, 15, -1);
      } else {
        p.line(12, 4, 15, 4);
        p.line(15, 1, 15, 4);
      }

      p.pop();
    }

    // Draw recognition beam between keys
    if(recognitionStrength > 0.3) {
      p.stroke(255, 200, 100, recognitionStrength * 100 * mouseInfluence);
      p.strokeWeight(3);
      let x1 = keys[0].x + p.cos(time) * 5;
      let y1 = keys[0].y + p.sin(time) * 5;
      let x2 = keys[1].x + p.cos(time + p.PI) * 5;
      let y2 = keys[1].y + p.sin(time + p.PI) * 5;

      // Curved connection line
      p.noFill();
      p.bezier(x1, y1, x1 + 50, y1 - 100, x2 - 50, y2 - 100, x2, y2);

      // Particle effects along the line
      for(let t = 0; t < 1; t += 0.1) {
        let x = p.bezierPoint(x1, x1 + 50, x2 - 50, x2, t);
        let y = p.bezierPoint(y1, y1 - 100, y2 - 100, y2, t);
        p.fill(255, 220, 150, recognitionStrength * 200);
        p.noStroke();
        p.circle(x + p.sin(time * 3 + t * 10) * 3, y, 4);
      }
    }

    // Subtle street suggestions
    p.stroke(60, 60, 80, 100);
    p.strokeWeight(1);
    p.line(0, 480, p.width, 480); // ground line
    p.line(50, 500, 350, 505); // distant street

    // Atmospheric particles
    p.fill(255, 200, 100, 50);
    p.noStroke();
    for(let i = 0; i < 20; i++) {
      let x = (p.sin(time * 0.3 + i) * 150) + p.width/2;
      let y = (p.cos(time * 0.2 + i * 0.5) * 200) + p.height/2;
      p.circle(x, y, 2 + p.sin(time + i) * 1);
    }
  };
}

