function sketch(p) {
  let keys = [];
  let bloom = {};
  let time = 0;
  let asymmetryOffset = 0;

  p.setup = function() {
    p.createCanvas(400, 600);

    // Create seven keys in asymmetric arrangement
    let centerX = p.width / 2;
    let centerY = p.height / 2;
    let radius = 120;

    // Three keys on left side, four on right - asymmetric mandala
    let leftAngles = [-p.PI * 0.6, -p.PI * 0.3, -p.PI * 0.05];
    let rightAngles = [p.PI * 0.05, p.PI * 0.3, p.PI * 0.6, p.PI * 0.85];

    for (let i = 0; i < 3; i++) {
      keys.push({
        x: centerX + p.cos(leftAngles[i]) * radius,
        y: centerY + p.sin(leftAngles[i]) * radius,
        angle: leftAngles[i],
        brightness: p.random(0.6, 1.0),
        size: p.random(25, 40),
        rotSpeed: p.random(-0.02, 0.02),
        side: 'left'
      });
    }

    for (let i = 0; i < 4; i++) {
      keys.push({
        x: centerX + p.cos(rightAngles[i]) * radius,
        y: centerY + p.sin(rightAngles[i]) * radius,
        angle: rightAngles[i],
        brightness: p.random(0.6, 1.0),
        size: p.random(25, 40),
        rotSpeed: p.random(-0.02, 0.02),
        side: 'right'
      });
    }

    // Bloom figure in center
    bloom = {
      x: centerX,
      y: centerY + 80,
      breathe: 0
    };
  };

  p.draw = function() {
    // Warm background gradient
    for (let y = 0; y < p.height; y++) {
      let alpha = p.map(y, 0, p.height, 0.3, 0.1);
      p.fill(25, 15, 5, alpha * 255);
      p.noStroke();
      p.rect(0, y, p.width, 1);
    }

    // Deep blue-brown base
    p.background(20, 15, 25);

    time += 0.01;
    asymmetryOffset += 0.005;

    // Draw flowing circular patterns that can't quite balance
    p.push();
    p.translate(p.width/2, p.height/2);
    p.noFill();

    for (let r = 50; r < 200; r += 30) {
      p.stroke(80, 60, 30, 100);
      p.strokeWeight(1);
      p.beginShape();
      for (let a = 0; a < p.TWO_PI; a += 0.1) {
        let x = p.cos(a) * r;
        let y = p.sin(a) * r;
        // Add asymmetric wobble
        x += p.sin(time + a * 3) * (r * 0.05) * (a > p.PI ? 1.2 : 0.8);
        y += p.cos(time + a * 2) * (r * 0.03) * (a > p.PI ? 0.9 : 1.1);
        p.vertex(x, y);
      }
      p.endShape(p.CLOSE);
    }
    p.pop();

    // Draw connecting lines between keys (asymmetric web)
    p.stroke(120, 90, 50, 60);
    p.strokeWeight(0.5);
    for (let i = 0; i < keys.length; i++) {
      for (let j = i + 1; j < keys.length; j++) {
        if (p.random() > 0.3) { // Not all connections - asymmetric
          p.line(keys[i].x, keys[i].y, keys[j].x, keys[j].y);
        }
      }
    }

    // Draw the seven keys
    for (let i = 0; i < keys.length; i++) {
      let key = keys[i];

      p.push();
      p.translate(key.x, key.y);
      p.rotate(key.angle + time * key.rotSpeed);

      // Key glow - uneven brightness
      let glowIntensity = key.brightness + p.sin(time * 2 + i) * 0.2;
      p.fill(255, 200, 100, glowIntensity * 100);
      p.noStroke();
      p.ellipse(0, 0, key.size * 2, key.size * 2);

      // Key body
      p.fill(255, 220, 120, 200);
      p.stroke(200, 160, 80);
      p.strokeWeight(2);
      p.rect(-key.size/4, -key.size/3, key.size/2, key.size * 0.8);

      // Key teeth - asymmetric
      p.rect(key.size/4, key.size/6, key.size/3, key.size/8);
      if (i % 3 === 0) { // Some keys have extra teeth
        p.rect(key.size/4, key.size/3, key.size/4, key.size/10);
      }

      // Key ring
      p.noFill();
      p.stroke(220, 180, 100);
      p.strokeWeight(3);
      p.ellipse(0, -key.size/3, key.size/4, key.size/4);

      p.pop();

      // Subtle floating animation with mouse interaction
      let mouseInfluence = p.dist(p.mouseX, p.mouseY, key.x, key.y) / 100;
      key.x += p.sin(time + i) * 0.5 / mouseInfluence;
      key.y += p.cos(time + i * 0.7) * 0.3 / mouseInfluence;
    }

    // Draw Bloom figure
    p.push();
    p.translate(bloom.x, bloom.y);

    bloom.breathe = p.sin(time * 2) * 3;

    // Figure shadow
    p.fill(0, 0, 0, 50);
    p.noStroke();
    p.ellipse(0, 30, 80, 20);

    // Body
    p.fill(60, 50, 70);
    p.stroke(80, 70, 90);
    p.strokeWeight(2);
    p.ellipse(0, bloom.breathe, 40, 60);

    // Head
    p.fill(120, 100, 90);
    p.ellipse(0, -30 + bloom.breathe, 25, 30);

    // Arms reaching toward keys - accepting gesture
    p.stroke(100, 80, 70);
    p.strokeWeight(4);
    p.line(-20, -5 + bloom.breathe, -35, -25 + bloom.breathe);
    p.line(20, -5 + bloom.breathe, 35, -25 + bloom.breathe);

    // Hands - open, accepting
    p.fill(120, 100, 90);
    p.noStroke();
    p.ellipse(-35, -25 + bloom.breathe, 8, 8);
    p.ellipse(35, -25 + bloom.breathe, 8, 8);

    p.pop();

    // Asymmetric light rays
    p.push();
    p.translate(p.width/2, p.height/2);
    for (let i = 0; i < 7; i++) {
      let angle = (i / 7) * p.TWO_PI + asymmetryOffset;
      let length = 150 + p.sin(time + i) * 30;
      // Make some rays longer/shorter - asymmetric
      if (i < 3) length *= 0.8;
      if (i >= 4) length *= 1.2;

      p.stroke(255, 200, 100, 30);
      p.strokeWeight(2);
      p.line(0, 0, p.cos(angle) * length, p.sin(angle) * length);
    }
    p.pop();
  };
}

