function sketch(p) {
  let keys = [];
  let bloomX, bloomY;
  let time = 0;
  let layers = [];

  p.setup = function() {
    p.createCanvas(400, 600);

    // Create key layers - ancient at bottom, modern at top
    for(let layer = 0; layer < 3; layer++) {
      layers[layer] = [];
      let keyCount = 40 - layer * 5;

      for(let i = 0; i < keyCount; i++) {
        let key = {
          x: p.random(p.width),
          y: p.random(200 + layer * 150, 350 + layer * 150),
          size: p.random(15, 35),
          rotation: p.random(p.TWO_PI),
          rotSpeed: p.random(-0.01, 0.01),
          floatOffset: p.random(p.TWO_PI),
          layer: layer,
          opacity: 180 - layer * 40
        };
        layers[layer].push(key);
      }
    }

    bloomX = p.width / 2;
    bloomY = 200;
  };

  p.draw = function() {
    // Deep ocean background
    for(let i = 0; i < p.height; i++) {
      let inter = p.map(i, 0, p.height, 0, 1);
      let c = p.lerpColor(p.color(20, 30, 60), p.color(5, 15, 40), inter);
      p.stroke(c);
      p.line(0, i, p.width, i);
    }

    time += 0.01;

    // Draw key layers from bottom to top
    for(let layer = 2; layer >= 0; layer--) {
      drawKeyLayer(layers[layer], layer);
    }

    // Draw Bloom swimming/floating
    drawBloom();

    // Subtle current effects
    drawCurrent();
  };

  function drawKeyLayer(keyLayer, layer) {
    for(let key of keyLayer) {
      p.push();

      // Flowing motion based on ocean currents
      let flowX = p.sin(time + key.floatOffset) * (5 - layer);
      let flowY = p.cos(time * 0.7 + key.floatOffset) * (3 - layer);

      p.translate(key.x + flowX, key.y + flowY);
      p.rotate(key.rotation + time * key.rotSpeed);

      // Color based on historical period
      let keyColor;
      if(layer == 2) { // Ancient - bronze
        keyColor = p.color(139, 90, 43, key.opacity);
      } else if(layer == 1) { // Medieval - iron
        keyColor = p.color(70, 70, 80, key.opacity);
      } else { // Modern - brass
        keyColor = p.color(181, 166, 66, key.opacity);
      }

      p.fill(keyColor);
      p.stroke(p.red(keyColor) + 30, p.green(keyColor) + 30, p.blue(keyColor) + 30, key.opacity * 0.7);
      p.strokeWeight(1);

      drawKey(key.size, layer);

      p.pop();

      // Gentle drift
      key.x += p.sin(time + key.floatOffset * 2) * 0.1;
      if(key.x > p.width + 50) key.x = -50;
      if(key.x < -50) key.x = p.width + 50;
    }
  }

  function drawKey(size, layer) {
    // Key shaft
    p.rect(-size/2, -size/8, size * 0.7, size/4);

    // Key head (bow)
    if(layer == 2) { // Ancient - simple circle
      p.ellipse(-size/2, 0, size/3, size/3);
    } else if(layer == 1) { // Medieval - ornate
      p.ellipse(-size/2, 0, size/2.5, size/2.5);
      // Decorative elements
      p.rect(-size/2 - size/8, -size/16, size/4, size/8);
    } else { // Modern - functional
      p.rect(-size/2 - size/6, -size/6, size/3, size/3);
    }

    // Key teeth
    let teeth = layer == 1 ? 3 : 2;
    for(let i = 0; i < teeth; i++) {
      p.rect(size/4 + i * size/8, -size/16, size/12, size/8);
    }
  }

  function drawBloom() {
    // Bloom's position follows mouse subtly but stays near center
    let targetX = p.lerp(p.width/2, p.mouseX, 0.1);
    let targetY = p.lerp(200, p.mouseY, 0.05);

    bloomX = p.lerp(bloomX, targetX, 0.02);
    bloomY = p.lerp(bloomY, targetY, 0.02);

    // Bloom floating/swimming
    let bobY = bloomY + p.sin(time * 2) * 8;

    p.push();
    p.translate(bloomX, bobY);

    // Body - simple figure
    p.fill(180, 140, 100, 200);
    p.stroke(160, 120, 80, 150);
    p.strokeWeight(2);
    p.ellipse(0, 0, 25, 35); // torso
    p.ellipse(0, -20, 18, 18); // head

    // Arms in swimming motion
    let armAngle = p.sin(time * 3) * 0.3;
    p.line(0, -5, 15 * p.cos(armAngle), 15 * p.sin(armAngle));
    p.line(0, -5, -15 * p.cos(armAngle), -15 * p.sin(armAngle));

    p.pop();

    // Ripples around Bloom
    for(let r = 0; r < 3; r++) {
      p.stroke(100, 150, 200, 100 - r * 30);
      p.strokeWeight(2 - r * 0.5);
      p.noFill();
      let rippleSize = 40 + r * 20 + p.sin(time * 2 + r) * 10;
      p.ellipse(bloomX, bobY, rippleSize, rippleSize * 0.6);
    }
  }

  function drawCurrent() {
    // Subtle current lines showing the flow of history/keys
    p.stroke(80, 120, 160, 60);
    p.strokeWeight(1);

    for(let y = 150; y < p.height - 50; y += 30) {
      let currentFlow = p.sin(time + y * 0.01) * 50;
      p.line(0, y, p.width/3 + currentFlow, y);
      p.line(2*p.width/3 + currentFlow, y, p.width, y);
    }
  }
}

