function sketch(p) {
  let keys = [];
  let doors = [];
  let centerX, centerY;
  let bloomFigure;
  let time = 0;
  let spiralRadius = 120;
  let numKeys = 10;

  p.setup = function() {
    p.createCanvas(400, 600);
    centerX = p.width / 2;
    centerY = p.height / 2;

    // Initialize keys and doors in spiral arrangement
    for (let i = 0; i < numKeys; i++) {
      let angle = (i / numKeys) * p.TWO_PI;
      let spiralOffset = i * 8;
      let radius = spiralRadius + spiralOffset;

      let x = centerX + p.cos(angle) * radius;
      let y = centerY + p.sin(angle) * radius;

      keys.push({
        x: x,
        y: y,
        angle: angle,
        rotation: 0,
        spiralOffset: spiralOffset,
        index: i,
        unlocking: false,
        unlockProgress: 0
      });

      doors.push({
        x: x,
        y: y,
        angle: angle,
        spiralOffset: spiralOffset,
        index: i,
        openness: 0,
        revealed: false
      });
    }

    bloomFigure = {
      x: centerX,
      y: centerY,
      understanding: 0
    };
  };

  p.draw = function() {
    time += 0.01;

    // Deep blue-purple gradient background
    for (let y = 0; y < p.height; y++) {
      let inter = p.map(y, 0, p.height, 0, 1);
      let c = p.lerpColor(p.color(15, 20, 45), p.color(45, 25, 80), inter);
      p.stroke(c);
      p.line(0, y, p.width, y);
    }

    // Draw the eternal spiral connection
    p.push();
    p.translate(centerX, centerY);
    p.noFill();
    p.stroke(180, 140, 100, 120);
    p.strokeWeight(2);

    for (let r = 20; r < 250; r += 15) {
      p.beginShape();
      for (let a = 0; a < p.TWO_PI * 3; a += 0.1) {
        let x = p.cos(a + time * 0.5) * (r + p.sin(a * 3 + time) * 8);
        let y = p.sin(a + time * 0.5) * (r + p.sin(a * 3 + time) * 8);
        p.vertex(x, y);
      }
      p.endShape(p.CLOSE);
    }
    p.pop();

    // Update and draw keys and doors
    for (let i = 0; i < numKeys; i++) {
      let key = keys[i];
      let door = doors[i];

      // Animate the cycle
      let cyclePhase = (time + i * 0.3) % (p.TWO_PI * 2);

      // Key unlocking animation
      if (cyclePhase > p.PI && cyclePhase < p.PI * 1.5) {
        key.unlocking = true;
        key.unlockProgress = p.map(cyclePhase, p.PI, p.PI * 1.5, 0, 1);
        key.rotation = key.unlockProgress * p.PI * 2;
      } else {
        key.unlocking = false;
        key.unlockProgress = 0;
        key.rotation = 0;
      }

      // Door opening animation
      if (cyclePhase > p.PI * 1.5 && cyclePhase < p.PI * 2) {
        door.openness = p.map(cyclePhase, p.PI * 1.5, p.PI * 2, 0, 1);
        door.revealed = true;
      } else if (cyclePhase > p.PI * 2 && cyclePhase < p.PI * 2.5) {
        door.openness = p.map(cyclePhase, p.PI * 2, p.PI * 2.5, 1, 0);
      } else {
        door.openness = 0;
        door.revealed = false;
      }

      // Draw door
      p.push();
      p.translate(door.x, door.y);
      p.rotate(door.angle + p.PI/2);

      // Door frame
      p.fill(100, 80, 60);
      p.noStroke();
      p.rect(-15, -20, 30, 40, 3);

      // Door panels
      p.fill(60, 40, 30);
      p.rect(-12 + door.openness * 12, -17, 10, 15, 2);
      p.rect(-12 + door.openness * 12, -2, 10, 15, 2);

      // Revealed lock behind door
      if (door.revealed) {
        p.fill(150, 120, 80, 150);
        p.ellipse(0, 0, 8, 8);
        p.fill(80, 60, 40);
        p.ellipse(0, 0, 4, 4);
      }

      p.pop();

      // Draw key
      p.push();
      p.translate(key.x, key.y);
      p.rotate(key.angle + key.rotation);

      // Key glow when unlocking
      if (key.unlocking) {
        p.fill(255, 215, 100, 100);
        p.noStroke();
        p.ellipse(0, 0, 30, 30);
      }

      // Key body
      p.fill(200, 170, 120);
      p.stroke(150, 120, 80);
      p.strokeWeight(1);
      p.ellipse(0, 0, 8, 8);
      p.rect(-2, 0, 4, 15);

      // Key teeth
      p.rect(-2, 12, 6, 2);
      p.rect(-2, 15, 4, 2);

      p.pop();

      // Draw connection line to next key (showing the cycle)
      let nextIndex = (i + 1) % numKeys;
      let nextKey = keys[nextIndex];

      p.stroke(180, 140, 100, 80);
      p.strokeWeight(1);
      p.line(key.x, key.y, nextKey.x, nextKey.y);
    }

    // Draw Bloom figure at center
    p.push();
    p.translate(bloomFigure.x, bloomFigure.y);

    // Figure understanding pulse
    bloomFigure.understanding = (p.sin(time * 2) + 1) * 0.5;

    // Aura of understanding
    p.fill(255, 215, 100, bloomFigure.understanding * 30);
    p.noStroke();
    p.ellipse(0, 0, 60, 60);

    // Simple figure
    p.fill(80, 60, 100);
    p.stroke(120, 100, 140);
    p.strokeWeight(2);
    p.ellipse(0, -10, 12, 12); // head
    p.line(0, -4, 0, 15); // body
    p.line(-8, 5, 8, 5); // arms
    p.line(0, 15, -5, 25); // legs
    p.line(0, 15, 5, 25);

    p.pop();

    // Draw central mandala pattern
    p.push();
    p.translate(centerX, centerY);
    p.noFill();
    p.stroke(200, 170, 120, 100);
    p.strokeWeight(1);

    for (let r = 10; r < 80; r += 10) {
      p.beginShape();
      for (let a = 0; a < p.TWO_PI; a += p.PI/12) {
        let x = p.cos(a + time * 0.3) * r;
        let y = p.sin(a + time * 0.3) * r;
        p.vertex(x, y);
      }
      p.endShape(p.CLOSE);
    }

    p.pop();

    // Mouse interaction - gentle disturbance of the pattern
    if (p.mouseX > 0 && p.mouseX < p.width && p.mouseY > 0 && p.mouseY < p.height) {
      let mouseInfluence = p.map(p.dist(p.mouseX, p.mouseY, centerX, centerY), 0, 200, 1, 0);
      mouseInfluence = p.constrain(mouseInfluence, 0, 1);

      if (mouseInfluence > 0) {
        p.push();
        p.translate(p.mouseX, p.mouseY);
        p.fill(255, 215, 100, mouseInfluence * 50);
        p.noStroke();
        p.ellipse(0, 0, 40, 40);

        // Ripple effect
        for (let r = 10; r < 60; r += 10) {
          p.noFill();
          p.stroke(255, 215, 100, mouseInfluence * 100);
          p.strokeWeight(1);
          p.ellipse(0, 0, r + p.sin(time * 5) * 3, r + p.sin(time * 5) * 3);
        }
        p.pop();
      }
    }
  };
}

