function sketch(p) {
  let doors = [];
  let keys = [];
  let openBooks = [];
  let childX, childY;
  let armAngle = 0;
  let currentKey = 0;
  let keyTryTime = 0;
  let mandalas = [];
  let particles = [];

  p.setup = function() {
    p.createCanvas(400, 600);

    // Initialize child position
    childX = 200;
    childY = 400;

    // Create doors at different positions
    for (let i = 0; i < 6; i++) {
      doors.push({
        x: 80 + (i % 3) * 120,
        y: 150 + Math.floor(i / 3) * 140,
        isOpen: false,
        keyhole: p.random(0, 5),
        openProgress: 0,
        glowIntensity: 0
      });
    }

    // Create keys
    for (let i = 0; i < 5; i++) {
      keys.push({
        type: i,
        x: childX + p.random(-30, 30),
        y: childY + p.random(-20, 20),
        glow: p.random(0.3, 0.7),
        bobOffset: p.random(0, p.TWO_PI)
      });
    }

    // Create floating mandala patterns
    for (let i = 0; i < 8; i++) {
      mandalas.push({
        x: p.random(50, 350),
        y: p.random(50, 200),
        size: p.random(15, 35),
        rotation: 0,
        opacity: p.random(0.1, 0.3),
        speed: p.random(0.005, 0.02)
      });
    }

    // Create scattered books
    for (let i = 0; i < 4; i++) {
      openBooks.push({
        x: p.random(50, 350),
        y: p.random(480, 550),
        angle: p.random(-0.3, 0.3),
        pages: p.random(0.3, 0.8)
      });
    }
  };

  p.draw = function() {
    // Gradient background
    for (let y = 0; y < p.height; y++) {
      let inter = p.map(y, 0, p.height, 0, 1);
      let c = p.lerpColor(p.color(25, 35, 55), p.color(15, 25, 45), inter);
      p.stroke(c);
      p.line(0, y, p.width, y);
    }

    // Draw floating mandala patterns (uncertain, forming)
    for (let mandala of mandalas) {
      p.push();
      p.translate(mandala.x, mandala.y);
      p.rotate(mandala.rotation);
      p.stroke(255, 215, 100, mandala.opacity * 255);
      p.strokeWeight(1);
      p.noFill();

      // Loose circular patterns
      for (let r = 5; r < mandala.size; r += 8) {
        let points = Math.max(6, Math.floor(r / 3));
        p.beginShape();
        for (let i = 0; i <= points; i++) {
          let angle = (i / points) * p.TWO_PI;
          let x = r * p.cos(angle) + p.random(-2, 2);
          let y = r * p.sin(angle) + p.random(-2, 2);
          p.vertex(x, y);
        }
        p.endShape(p.CLOSE);
      }
      p.pop();

      mandala.rotation += mandala.speed;
    }

    // Draw scattered books
    for (let book of openBooks) {
      p.push();
      p.translate(book.x, book.y);
      p.rotate(book.angle);

      // Book cover
      p.fill(101, 67, 33);
      p.stroke(80, 50, 20);
      p.strokeWeight(2);
      p.rect(-15, -8, 30, 16);

      // Open pages
      p.fill(240, 230, 200, 200);
      p.noStroke();
      p.rect(-12, -6, 24 * book.pages, 12);

      // Text lines
      p.stroke(60, 40, 20, 150);
      p.strokeWeight(0.5);
      for (let i = 0; i < 4; i++) {
        p.line(-10, -4 + i * 2, -10 + 18 * book.pages, -4 + i * 2);
      }
      p.pop();
    }

    // Draw doors
    for (let i = 0; i < doors.length; i++) {
      let door = doors[i];

      p.push();
      p.translate(door.x, door.y);

      // Door frame
      p.fill(101, 67, 33);
      p.stroke(80, 50, 20);
      p.strokeWeight(3);
      p.rect(-25, -40, 50, 80);

      // Door itself
      if (door.isOpen) {
        p.push();
        p.translate(-25, 0);
        p.rotate(-door.openProgress * p.PI/2);
        p.fill(139, 119, 101);
        p.rect(0, -35, 45, 70);
        p.pop();

        // Glow from open door
        p.fill(255, 215, 100, door.glowIntensity);
        p.noStroke();
        p.ellipse(0, 0, 80, 60);
      } else {
        p.fill(139, 119, 101);
        p.rect(-22, -37, 44, 74);

        // Keyhole
        p.fill(30, 20, 10);
        p.noStroke();
        p.ellipse(10, 10, 6, 6);
        p.rect(7, 13, 6, 8);
      }

      p.pop();
    }

    // Draw child figure
    p.push();
    p.translate(childX, childY);

    // Body
    p.fill(100, 150, 200);
    p.stroke(80, 120, 180);
    p.strokeWeight(2);
    p.ellipse(0, -20, 30, 40);

    // Head
    p.fill(255, 220, 177);
    p.stroke(200, 180, 140);
    p.ellipse(0, -50, 25, 25);

    // Eyes (curious, patient)
    p.fill(50, 80, 120);
    p.noStroke();
    p.ellipse(-5, -52, 3, 4);
    p.ellipse(5, -52, 3, 4);

    // Arms reaching toward doors
    p.stroke(255, 220, 177);
    p.strokeWeight(8);
    p.strokeCap(p.ROUND);

    let targetDoor = doors[currentKey % doors.length];
    let armReachX = (targetDoor.x - childX) * 0.3;
    let armReachY = (targetDoor.y - childY) * 0.3;

    p.line(0, -30, armReachX, -30 + armReachY);

    p.pop();

    // Draw keys floating around child
    for (let i = 0; i < keys.length; i++) {
      let key = keys[i];
      let bobY = p.sin(p.frameCount * 0.05 + key.bobOffset) * 3;

      p.push();
      p.translate(key.x, key.y + bobY);

      // Key glow
      p.fill(255, 215, 100, key.glow * 100);
      p.noStroke();
      p.ellipse(0, 0, 20, 20);

      // Key body
      p.fill(255, 215, 100, key.glow * 255);
      p.stroke(200, 170, 50);
      p.strokeWeight(1);
      p.rect(-8, -2, 16, 4);
      p.ellipse(-8, 0, 8, 8);

      // Key teeth (different for each key)
      for (let j = 0; j < 3; j++) {
        if ((key.type + j) % 2 === 0) {
          p.rect(8 - j * 3, -2, 2, 6);
        }
      }

      p.pop();
    }

    // Animation logic
    keyTryTime += 0.02;
    if (keyTryTime > 3) {
      keyTryTime = 0;
      currentKey = (currentKey + 1) % doors.length;

      let door = doors[currentKey];
      if (p.random() > 0.3) { // Sometimes keys work!
        door.isOpen = true;
        door.openProgress = 0;
        door.glowIntensity = 0;

        // Add success particles
        for (let i = 0; i < 10; i++) {
          particles.push({
            x: door.x,
            y: door.y,
            vx: p.random(-2, 2),
            vy: p.random(-3, -1),
            life: 60,
            maxLife: 60
          });
        }
      }
    }

    // Update door animations
    for (let door of doors) {
      if (door.isOpen && door.openProgress < 1) {
        door.openProgress += 0.03;
        door.glowIntensity = p.min(150, door.glowIntensity + 5);
      }
    }

    // Draw and update particles
    for (let i = particles.length - 1; i >= 0; i--) {
      let particle = particles[i];

      p.push();
      p.translate(particle.x, particle.y);
      p.fill(255, 215, 100, (particle.life / particle.maxLife) * 200);
      p.noStroke();
      p.ellipse(0, 0, 4, 4);
      p.pop();

      particle.x += particle.vx;
      particle.y += particle.vy;
      particle.vy += 0.1; // gravity
      particle.life--;

      if (particle.life <= 0) {
        particles.splice(i, 1);
      }
    }

    // Interactive glow on mouse hover
    let mouseDistance = p.dist(p.mouseX, p.mouseY, childX, childY);
    if (mouseDistance < 50) {
      p.fill(255, 215, 100, 30);
      p.noStroke();
      p.ellipse(childX, childY, 100, 100);
    }
  };
}

