function sketch(p) {
  let keys = [];
  let doors = [];
  let mandalaRotation = 0;
  let bloomPos;
  let offeredKey;
  let keyRing = [];
  let particles = [];

  p.setup = function() {
    p.createCanvas(400, 600);

    bloomPos = p.createVector(200, 350);

    // Create doors at various positions
    doors.push({x: 80, y: 150, width: 60, height: 90, openness: 0.8, targetOpen: 0.8});
    doors.push({x: 260, y: 120, width: 50, height: 80, openness: 0, targetOpen: 0});
    doors.push({x: 320, y: 200, width: 55, height: 85, openness: 0.3, targetOpen: 0.3});
    doors.push({x: 50, y: 280, width: 45, height: 75, openness: 1, targetOpen: 1});
    doors.push({x: 300, y: 320, width: 48, height: 78, openness: 0, targetOpen: 0});

    // Create key ring
    for(let i = 0; i < 8; i++) {
      keyRing.push({
        angle: (i * p.TWO_PI) / 8,
        size: 12 + p.random(-2, 2)
      });
    }

    // Offered key
    offeredKey = {
      x: bloomPos.x + 60,
      y: bloomPos.y - 40,
      glow: 0,
      float: 0
    };

    // Golden particles
    for(let i = 0; i < 30; i++) {
      particles.push({
        x: p.random(p.width),
        y: p.random(p.height),
        size: p.random(2, 4),
        speed: p.random(0.3, 0.8),
        alpha: p.random(50, 150)
      });
    }
  };

  p.draw = function() {
    // Gradient background - warm browns to golds
    for(let y = 0; y < p.height; y++) {
      let inter = p.map(y, 0, p.height, 0, 1);
      let c = p.lerpColor(p.color(40, 35, 25), p.color(80, 60, 35), inter);
      p.stroke(c);
      p.line(0, y, p.width, y);
    }

    // Floating golden particles
    p.noStroke();
    for(let particle of particles) {
      particle.y -= particle.speed;
      if(particle.y < 0) particle.y = p.height;

      p.fill(255, 215, 0, particle.alpha);
      p.ellipse(particle.x, particle.y, particle.size);
    }

    // Mandala patterns - earned wisdom circles
    p.push();
    p.translate(200, 100);
    p.rotate(mandalaRotation * 0.3);
    p.noFill();
    p.strokeWeight(2);

    // Outer ring - bright and clear
    p.stroke(255, 215, 0, 180);
    p.ellipse(0, 0, 120);

    // Inner patterns
    for(let i = 0; i < 8; i++) {
      p.push();
      p.rotate((i * p.TWO_PI) / 8);
      p.stroke(255, 235, 120, 150);
      p.line(0, 0, 40, 0);
      p.ellipse(30, 0, 8);
      p.pop();
    }
    p.pop();

    // Draw doors with varying states
    for(let door of doors) {
      // Door frame
      p.fill(60, 45, 30);
      p.rect(door.x, door.y, door.width, door.height);

      // Door itself
      let doorColor = p.lerpColor(p.color(80, 60, 40), p.color(120, 100, 60), door.openness);
      p.fill(doorColor);

      p.push();
      p.translate(door.x, door.y + door.height/2);
      p.rotate(-door.openness * p.PI/3);
      p.rect(0, -door.height/2, door.width * 0.8, door.height);

      // Door handle
      p.fill(180, 160, 100);
      p.ellipse(door.width * 0.6, 0, 4);
      p.pop();

      // Light through open doors
      if(door.openness > 0.1) {
        p.fill(255, 235, 150, door.openness * 60);
        p.triangle(door.x + door.width, door.y + 20, 
                  door.x + door.width + door.openness * 40, door.y + 10,
                  door.x + door.width + door.openness * 40, door.y + door.height - 10);
      }

      // Animate door openness slightly
      door.openness = p.lerp(door.openness, door.targetOpen + p.sin(p.frameCount * 0.02) * 0.05, 0.02);
    }

    // Draw Bloom - father figure
    p.push();
    p.translate(bloomPos.x, bloomPos.y);

    // Body
    p.fill(60, 50, 40);
    p.ellipse(0, 20, 45, 80);

    // Head
    p.fill(200, 170, 140);
    p.ellipse(0, -20, 35, 40);

