function sketch(p) {
  let molly;
  let keys = [];
  let doors = [];
  let mandalaPoints = [];
  let time = 0;

  p.setup = function() {
    p.createCanvas(400, 600);

    // Create Molly's position (center)
    molly = {
      x: 200,
      y: 300,
      radius: 80
    };

    // Create keys around the edges
    for (let i = 0; i < 12; i++) {
      keys.push({
        x: 50 + (i % 4) * 100,
        y: 50 + Math.floor(i / 4) * 250,
        angle: p.random(p.TWO_PI),
        size: p.random(15, 25),
        rotSpeed: p.random(-0.02, 0.02),
        alpha: p.random(0.4, 0.8)
      });
    }

    // Create door suggestions
    for (let i = 0; i < 8; i++) {
      doors.push({
        x: p.random(50, 350),
        y: p.random(50, 550),
        width: p.random(20, 40),
        height: p.random(40, 80),
        alpha: p.random(0.2, 0.4),
        pulse: p.random(p.TWO_PI)
      });
    }

    // Create mandala points
    for (let i = 0; i < 60; i++) {
      let angle = (i / 60) * p.TWO_PI;
      let radius = 120 + p.sin(angle * 3) * 20;
      mandalaPoints.push({
        angle: angle,
        baseRadius: radius,
        offset: p.random(-10, 10)
      });
    }
  };

  p.draw = function() {
    time += 0.01;

    // Background - warm earth tones
    p.background(45, 35, 25);

    // Subtle room texture
    p.fill(55, 45, 35, 30);
    p.noStroke();
    for (let i = 0; i < 20; i++) {
      p.circle(p.random(400), p.random(600), p.random(100, 200));
    }

    // Draw doors (background layer)
    for (let door of doors) {
      door.pulse += 0.03;
      let doorAlpha = door.alpha + p.sin(door.pulse) * 0.1;
      p.fill(80, 60, 40, doorAlpha * 255);
      p.stroke(100, 80, 60, doorAlpha * 255);
      p.strokeWeight(2);
      p.rect(door.x, door.y, door.width, door.height);

      // Door handle
      p.fill(120, 100, 70, doorAlpha * 255);
      p.noStroke();
      p.circle(door.x + door.width * 0.8, door.y + door.height * 0.5, 4);
    }

    // Draw mandala pattern around Molly
    p.push();
    p.translate(molly.x, molly.y);
    p.rotate(time * 0.2);

