    for (let ring = 0; ring < 3; ring++) {
      p.stroke(200, 150, 80, 60 - ring * 15);
      p.strokeWeight(2 - ring * 0.5);
      p.noFill();

      p.beginShape();
      for (let point of mandalaPoints) {
        let r = point.baseRadius + ring * 30 + p.sin(time * 2 + point.angle) * point.offset;
        let x = p.cos(point.angle) * r;
        let y = p.sin(point.angle) * r;
        p.vertex(x, y);
      }
      p.endShape(p.CLOSE);
    }
    p.pop();

    // Draw keys floating around
    for (let key of keys) {
      key.angle += key.rotSpeed;

      // Make keys drift slowly toward center but maintain distance
      let centerDist = p.dist(key.x, key.y, molly.x, molly.y);
      if (centerDist > 120) {
        let moveX = (molly.x - key.x) * 0.002;
        let moveY = (molly.y - key.y) * 0.002;
        key.x += moveX;
        key.y += moveY;
      }

