    p.translate(molly.x, molly.y);

    // Bed/resting space
    p.fill(60, 45, 35, 180);
    p.noStroke();
    p.ellipse(0, 20, 160, 80);

    // Molly's form - maternal, powerful, at rest
    p.fill(220, 180, 140);
    p.stroke(180, 140, 100);
    p.strokeWeight(1);

    // Body
    p.ellipse(0, 10, 80, 60);

    // Head
    p.circle(0, -30, 50);

    // Hair
    p.fill(80, 40, 20);
    p.noStroke();
    for (let i = 0; i < 8; i++) {
      let hairX = p.sin(i + time) * 25;
      let hairY = -35 + p.cos(i + time) * 5;
      p.circle(hairX, hairY, 15);
    }

    // Eyes - wise, knowing
    p.fill(40, 30, 20);
    p.circle(-8, -35, 4);
    p.circle(8, -35, 4);

    // Peaceful expression
    p.stroke(180, 140, 100);
    p.strokeWeight(2);
    p.noFill();
    p.arc(0, -25, 12, 8, 0, p.PI);

    p.pop();

    // Central glow - the space beyond locks
    p.push();
    p.translate(molly.x, molly.y);
    for (let i = 0; i < 5; i++) {
      p.fill(255, 220, 150, 15 - i * 3);
      p.noStroke();
      p.circle(0, 0, 200 + i * 40 + p.sin(time) * 20);
    }
    p.pop();

    // Interactive element - mouse proximity affects key behavior
    let mouseInfluence = p.dist(p.mouseX, p.mouseY, molly.x, molly.y) / 200;
    for (let key of keys) {
      key.rotSpeed = p.lerp(key.rotSpeed, (1 - mouseInfluence) * 0.02, 0.1);
      key.alpha = p.lerp(key.alpha, 0.3 + mouseInfluence * 0.5, 0.05);
    }
  };
}

