function sketch(p) {
  let keys = [];
  let yesParticles = [];
  let time = 0;
  let figure = { x: 200, y: 450, breathe: 0 };

  p.setup = function() {
    p.createCanvas(400, 600);

    // Create key shapes for the Y-E-S letters
    createYESKeys();

    // Create flowing particles
    for (let i = 0; i < 150; i++) {
      yesParticles.push({
        x: p.random(400),
        y: p.random(600),
        size: p.random(2, 6),
        speed: p.random(0.5, 2),
        angle: p.random(p.TWO_PI),
        orbit: p.random(20, 80),
        phase: p.random(p.TWO_PI)
      });
    }
  };

  function createYESKeys() {
    // Y - made of keys
    keys.push(...createLetterY(80, 120));
    // E - made of keys  
    keys.push(...createLetterE(160, 120));
    // S - made of keys
    keys.push(...createLetterS(240, 120));
  }

  function createLetterY(centerX, centerY) {
    let letterKeys = [];
    // Left diagonal of Y
    for (let i = 0; i < 8; i++) {
      letterKeys.push({
        x: centerX - 30 + i * 4,
        y: centerY - 40 + i * 8,
        rotation: p.PI / 4,
        size: 15,
        type: 'letter'
      });
    }
    // Right diagonal of Y
    for (let i = 0; i < 8; i++) {
      letterKeys.push({
        x: centerX + 30 - i * 4,
        y: centerY - 40 + i * 8,
        rotation: -p.PI / 4,
        size: 15,
        type: 'letter'
      });
    }
    // Stem of Y
    for (let i = 0; i < 6; i++) {
      letterKeys.push({
        x: centerX,
        y: centerY + 20 + i * 8,
        rotation: 0,
        size: 15,
        type: 'letter'
      });
    }
    return letterKeys;
  }

  function createLetterE(centerX, centerY) {
    let letterKeys = [];
    // Vertical line
    for (let i = 0; i < 12; i++) {
      letterKeys.push({
        x: centerX - 25,
        y: centerY - 40 + i * 7,
        rotation: p.PI / 2,
        size: 15,
        type: 'letter'
      });
    }
    // Top horizontal
    for (let i = 0; i < 6; i++) {
      letterKeys.push({
        x: centerX - 25 + i * 8,
        y: centerY - 40,
        rotation: 0,
        size: 15,
        type: 'letter'
      });
    }
    // Middle horizontal
    for (let i = 0; i < 5; i++) {
      letterKeys.push({
        x: centerX - 25 + i * 8,
        y: centerY,
        rotation: 0,
        size: 15,
        type: 'letter'
      });
    }
    // Bottom horizontal
    for (let i = 0; i < 6; i++) {
      letterKeys.push({
        x: centerX - 25 + i * 8,
        y: centerY + 38,
        rotation: 0,
        size: 15,
        type: 'letter'
      });
    }
    return letterKeys;
  }

  function createLetterS(centerX, centerY) {
    let letterKeys = [];
    // Top curve
    for (let i = 0; i < 8; i++) {
      let angle = p.map(i, 0, 7, p.PI, 0);
      letterKeys.push({
        x: centerX + p.cos(angle) * 25,
        y: centerY - 25 + p.sin(angle) * 15,
        rotation: angle + p.PI / 2,
        size: 15,
        type: 'letter'
      });
    }
    // Bottom curve
    for (let i = 0; i < 8; i++) {
      let angle = p.map(i, 0, 7, 0, p.PI);
      letterKeys.push({
        x: centerX + p.cos(angle) * 25,
        y: centerY + 25 + p.sin(angle) * 15,
        rotation: angle + p.PI / 2,
        size: 15,
        type: 'letter'
      });
    }
    return letterKeys;
  }

  function drawKey(x, y, size, rotation, alpha = 255) {
    p.push();
    p.translate(x, y);
    p.rotate(rotation);

    // Key shaft
    p.stroke(255, 215, 0, alpha);
    p.strokeWeight(3);
    p.line(-size/2, 0, size/3, 0);

    // Key head (circle)
    p.fill(255, 215, 0, alpha * 0.3);
    p.stroke(255, 215, 0, alpha);
    p.strokeWeight(2);
    p.circle(-size/2, 0, size/3);

    // Key teeth
    p.line(size/3, 0, size/3, -size/4);
    p.line(size/3, 0, size/3, size/6);

    p.pop();
  }

  p.draw = function() {
    // Deep blue to gold gradient background
    for (let i = 0; i < p.height; i++) {
      let inter = p.map(i, 0, p.height, 0, 1);
      let c = p.lerpColor(p.color(20, 20, 60), p.color(40, 30, 20), inter);
      p.stroke(c);
      p.line(0, i, p.width, i);
    }

    time += 0.02;

    // Draw flowing mandala particles
    for (let particle of yesParticles) {
      let centerX = 200 + p.cos(time + particle.phase) * 30;
      let centerY = 200 + p.sin(time * 0.7 + particle.phase) * 20;

      particle.angle += particle.speed * 0.01;
      let x = centerX + p.cos(particle.angle) * particle.orbit;
      let y = centerY + p.sin(particle.angle) * particle.orbit;

      let alpha = p.map(p.sin(time + particle.phase), -1, 1, 50, 150);
      p.fill(255, 215, 0, alpha);
      p.noStroke();
      p.circle(x, y, particle.size);
    }

    // Draw the YES made of keys
    for (let key of keys) {
      let breathe = p.sin(time * 2 + key.x * 0.01) * 0.1 + 1;
      let x = key.x + p.cos(time + key.y * 0.01) * 2;
      let y = key.y + p.sin(time * 0.8 + key.x * 0.01) * 1;

      let alpha = p.map(p.sin(time + key.x * 0.02), -1, 1, 180, 255);
      drawKey(x, y, key.size * breathe, key.rotation + p.sin(time) * 0.1, alpha);
    }

    // Central figure - synthesis of all key holders
    figure.breathe = p.sin(time * 1.5) * 0.1 + 1;

    p.push();
    p.translate(figure.x, figure.y);

    // Figure body - golden silhouette
    p.fill(255, 215, 0, 120);
    p.noStroke();
    p.ellipse(0, -20, 30 * figure.breathe, 40 * figure.breathe);
    p.ellipse(0, 10, 25 * figure.breathe, 60 * figure.breathe);

    // Arms holding keys
    p.stroke(255, 215, 0, 150);
    p.strokeWeight(4);
    let armSway = p.sin(time * 2) * 0.2;
    p.line(-15, -10, -30 + armSway * 10, -20);
    p.line(15, -10, 30 - armSway * 10, -20);

    // Keys in hands
    drawKey(-35 + armSway * 10, -25, 12, time, 200);
    drawKey(35 - armSway * 10, -25, 12, -time, 200);

    p.pop();

    // Interactive glow effect
    let mouseDistance = p.dist(p.mouseX, p.mouseY, 200, 300);
    if (mouseDistance < 100) {
      let glowStrength = p.map(mouseDistance, 0, 100, 100, 0);

      p.push();
      p.blendMode(p.SCREEN);
      p.fill(255, 215, 0, glowStrength * 0.3);
      p.noStroke();

      // Glow around the YES
      for (let key of keys) {
        p.circle(key.x, key.y, 40);
      }
      p.pop();
    }

    // Subtle mandala rings expanding from center
    p.noFill();
    p.stroke(255, 215, 0, 30);
    p.strokeWeight(1);
    for (let i = 1; i <= 5; i++) {
      let radius = (time * 50 + i * 30) % 300;
      p.circle(200, 200, radius);
    }
  };
}

