function sketch(p) {
  let nets = [];
  let doorNets = [];
  let keyNets = [];
  let figure;
  let tower;
  let waveOffset = 0;
  let breatheOffset = 0;
  let keyX, keyY;
  let mouseInfluence = 0;

  p.setup = function() {
    p.createCanvas(400, 600);

    // Initialize figure position
    figure = { x: 200, y: 450, sway: 0 };

    // Key position (in figure's hand)
    keyX = figure.x + 30;
    keyY = figure.y - 20;

    // Create background nets - irregular overlapping mesh
    for (let i = 0; i < 8; i++) {
      nets.push(createNet(p.random(50, 350), p.random(100, 500), p.random(80, 150), p.random(60, 120)));
    }

    // Create door nets - specifically in threshold
    for (let i = 0; i < 3; i++) {
      doorNets.push(createDoorNet());
    }

    // Create nets tangled around the key
    for (let i = 0; i < 4; i++) {
      keyNets.push(createKeyNet());
    }

    tower = {
      x: 200,
      y: 150,
      width: 180,
      height: 200
    };
  };

  p.draw = function() {
    // Muddy, hung-over morning palette
    p.background(p.color(85, 90, 75)); // muddy green-grey

    waveOffset += 0.02;
    breatheOffset += 0.015;
    mouseInfluence = p.lerp(mouseInfluence, p.dist(p.mouseX, p.mouseY, 200, 300) / 300, 0.05);

    // Draw distant sea (escape behind)
    drawSea();

    // Draw the tower with nets webbed across stones
    drawTower();

    // Draw background nets - overlapping, compressing space
    p.push();
    p.blendMode(p.MULTIPLY);
    for (let net of nets) {
      drawNet(net);
    }
    p.pop();

    // Draw figure (Stephen-like, disheveled)
    drawFigure();

    // Draw key with nets tangled around it
    drawKey();

    // Draw door nets - in the threshold/doorway
    p.push();
    for (let doorNet of doorNets) {
      drawDoorNet(doorNet);
    }
    p.pop();

    // Overlay nets that compress the entire space
    p.push();
    p.blendMode(p.MULTIPLY);
    p.fill(0, 20);
    for (let i = 0; i < 3; i++) {
      let netOpacity = 15 + mouseInfluence * 10;
      drawCompressingNet(netOpacity);
    }
    p.pop();
  };

  function createNet(x, y, w, h) {
    return {
      x: x,
      y: y,
      width: w,
      height: h,
      cellSize: p.random(15, 25),
      distortion: p.random(0.5, 2),
      phase: p.random(0, p.TWO_PI)
    };
  }

  function createDoorNet() {
    return {
      x: 160 + p.random(-20, 20),
      y: 200 + p.random(-30, 30),
      width: 80 + p.random(-20, 40),
      height: 120 + p.random(-20, 40),
      phase: p.random(0, p.TWO_PI)
    };
  }

  function createKeyNet() {
    return {
      offsetX: p.random(-15, 15),
      offsetY: p.random(-15, 15),
      size: p.random(20, 35),
      phase: p.random(0, p.TWO_PI)
    };
  }

  function drawSea() {
    // Distant sea - muted blue-grey, escape that's unreachable
    p.fill(p.color(70, 85, 95));
    p.noStroke();
    for (let y = 50; y < 150; y += 8) {
      let wave = p.sin(waveOffset + y * 0.05) * 3;
      p.rect(0, y, 400, 8);
      p.fill(p.color(75, 90, 100, 150));
    }
  }

  function drawTower() {
    // Martello tower - dingy brown stone
    p.fill(p.color(95, 85, 70)); // dingy brown
    p.stroke(p.color(60, 55, 45));
    p.strokeWeight(2);

    // Main tower body
    p.rect(tower.x - tower.width/2, tower.y, tower.width, tower.height, 5);

    // Tower details - stones with nets webbed between
    p.strokeWeight(1);
    for (let y = tower.y + 20; y < tower.y + tower.height; y += 25) {
      for (let x = tower.x - tower.width/2 + 15; x < tower.x + tower.width/2; x += 30) {
        p.stroke(p.color(50, 45, 35, 100));
        p.line(x, y, x + 20, y + p.sin(waveOffset + x * 0.1) * 2);
        p.line(x, y, x + 10, y + 15);
      }
    }

    // Doorway - the threshold of entanglement
    p.fill(p.color(30, 25, 20));
    p.rect(tower.x - 30, tower.y + tower.height - 80, 60, 80, 5, 5, 0, 0);
  }

  function drawFigure() {
    figure.sway = p.sin(breatheOffset) * 2;

    // Disheveled, hung-over figure
    p.push();
    p.translate(figure.x + figure.sway, figure.y);

    // Body - slouched posture
    p.fill(p.color(45, 50, 40)); // dark clothes
    p.stroke(p.color(30, 35, 25));
    p.strokeWeight(2);
    p.ellipse(0, -40, 25, 45); // head
    p.rect(-12, -20, 24, 40, 3); // torso
    p.rect(-8, 15, 16, 30, 3); // legs

    // Arms reaching toward key/door
    p.line(-10, -10, 20, -25); // reaching arm
    p.line(10, -5, -5, 10); // other arm

    // Disheveled hair
    p.stroke(p.color(40, 35, 30));
    p.strokeWeight(2);
    for (let i = 0; i < 8; i++) {
      let hairX = p.random(-12, 12);
      let hairY = -50 + p.random(-5, 5);
      p.line(hairX, hairY, hairX + p.random(-8, 8), hairY - p.random(5, 12));
    }

    p.pop();
  }

  function drawKey() {
    // Key wrapped in nets
    p.push();
    p.translate(keyX + p.sin(breatheOffset * 1.2) * 2, keyY + p.sin(breatheOffset * 0.8) * 1);

    // Key itself - tarnished metal
    p.fill(p.color(80, 75, 60));
    p.stroke(p.color(60, 55, 45));
    p.strokeWeight(2);
    p.rect(-3, -8, 6, 16, 1); // key shaft
    p.circle(0, -15, 8); // key head
    p.rect(3, -3, 6, 3); // key teeth

    // Nets tangled around key
    p.stroke(p.color(40, 45, 35, 180));
    p.strokeWeight(1.5);
    p.noFill();
    for (let keyNet of keyNets) {
      let netX = keyNet.offsetX + p.sin(waveOffset + keyNet.phase) * 3;
      let netY = keyNet.offsetY + p.cos(waveOffset + keyNet.phase) * 2;

      // Irregular net pattern wrapped around key
      for (let i = 0; i < 6; i++) {
        let angle = (i / 6) * p.TWO_PI + waveOffset;
        let x1 = netX + p.cos(angle) * keyNet.size * 0.3;
        let y1 = netY + p.sin(angle) * keyNet.size * 0.2;
        let x2 = netX + p.cos(angle + p.PI/3) * keyNet.size * 0.4;
        let y2 = netY + p.sin(angle + p.PI/3) * keyNet.size * 0.3;
        p.line(x1, y1, x2, y2);
      }
    }

    p.pop();
  }

  function drawNet(net) {
    p.stroke(p.color(35, 40, 30, 120 + mouseInfluence * 50));
    p.strokeWeight(1 + mouseInfluence * 0.5);
    p.noFill();

    // Irregular, overlapping mesh
    for (let x = 0; x < net.width; x += net.cellSize) {
      for (let y = 0; y < net.height; y += net.cellSize) {
        let distortion = p.sin(waveOffset + net.phase + x * 0.05 + y * 0.03) * net.distortion;
        let netX = net.x + x + distortion;
        let netY = net.y + y + distortion * 0.7;

        // Horizontal lines
        if (x < net.width - net.cellSize) {
          p.line(netX, netY, netX + net.cellSize + distortion, netY + p.sin(waveOffset + x * 0.1) * 2);
        }
        // Vertical lines
        if (y < net.height - net.cellSize) {
          p.line(netX, netY, netX + p.cos(waveOffset + y * 0.1) * 2, netY + net.cellSize + distortion);
        }
        // Diagonal entanglements
        if (p.random() < 0.3) {
          p.line(netX, netY, netX + net.cellSize * 0.7, netY + net.cellSize * 0.7);
        }
      }
    }
  }

  function drawDoorNet(doorNet) {
    p.stroke(p.color(25, 30, 20, 200));
    p.strokeWeight(2);
    p.noFill();

    // Nets specifically webbing the doorway
    let baseX = doorNet.x + p.sin(waveOffset + doorNet.phase) * 5;
    let baseY = doorNet.y + p.cos(waveOffset + doorNet.phase) * 3;

    // Web pattern across threshold
    for (let i = 0; i < 8; i++) {
      for (let j = 0; j < 6; j++) {
        let x1 = baseX + (i / 7) * doorNet.width;
        let y1 = baseY + (j / 5) * doorNet.height;
        let x2 = baseX + ((i + 1) / 7) * doorNet.width + p.sin(waveOffset + i) * 3;
        let y2 = baseY + (j / 5) * doorNet.height + p.cos(waveOffset + j) * 2;

        if (i < 7) p.line(x1, y1, x2, y1); // horizontal
        if (j < 5) p.line(x1, y1, x1, y2); // vertical
        if (p.random() < 0.4) p.line(x1, y1, x2, y2); // diagonal tangles
      }
    }
  }

  function drawCompressingNet(opacity) {
    p.stroke(p.color(20, 25, 15, opacity));
    p.strokeWeight(0.8);
    p.noFill();

    // Nets that compress the entire space
    let spacing = 35 + p.sin(waveOffset) * 5;
    for (let x = 0; x < 400; x += spacing) {
      for (let y = 0; y < 600; y += spacing * 0.8) {
        let distort = p.sin(waveOffset + x * 0.02 + y * 0.02) * 8;
        let netX = x + distort;
        let netY = y + distort * 0.5;

        // Irregular mesh that gets tighter toward the center
        let centerPull = p.map(p.dist(netX, netY, 200, 300), 0, 300, 2, 0.5);

        if (x < 400 - spacing) {
          p.line(netX, netY, netX + spacing * centerPull, netY + p.sin(waveOffset + x * 0.05) * 3);
        }
        if (y < 600 - spacing) {
          p.line(netX, netY, netX + p.cos(waveOffset + y * 0.05) * 2, netY + spacing * centerPull * 0.8);
        }
      }
    }
  }
}

