function sketch(p) {
  let stephen;
  let towerNets = [];
  let classroomNets = [];
  let connectingNets = [];
  let coins = [];
  let students = [];
  let time = 0;
  let transitionProgress = 0;

  p.setup = function() {
    p.createCanvas(400, 600);

    // Stephen figure
    stephen = {
      x: 120,
      y: 300,
      targetX: 280,
      moveSpeed: 0.003
    };

    // Initialize tower nets (left side - fading)
    for(let i = 0; i < 25; i++) {
      towerNets.push({
        x1: p.random(20, 180),
        y1: p.random(50, 550),
        x2: p.random(20, 180),
        y2: p.random(50, 550),
        opacity: p.random(0.3, 0.8),
        fadeRate: p.random(0.001, 0.003)
      });
    }

    // Initialize classroom nets (right side - tightening)
    for(let i = 0; i < 30; i++) {
      classroomNets.push({
        x1: p.random(220, 380),
        y1: p.random(50, 550),
        x2: p.random(220, 380),
        y2: p.random(50, 550),
        opacity: p.random(0.2, 0.4),
        tightenRate: p.random(0.002, 0.005),
        wobble: p.random(0.02, 0.05)
      });
    }

    // Connecting nets between spaces
    for(let i = 0; i < 15; i++) {
      connectingNets.push({
        x1: p.random(160, 200),
        y1: p.random(100, 500),
        x2: p.random(200, 240),
        y2: p.random(100, 500),
        phase: p.random(0, p.TWO_PI),
        frequency: p.random(0.01, 0.03)
      });
    }

    // Deasy's coins caught in nets
    for(let i = 0; i < 8; i++) {
      coins.push({
        x: p.random(250, 350),
        y: p.random(150, 450),
        size: p.random(4, 8),
        netted: true,
        bobSpeed: p.random(0.02, 0.04)
      });
    }

    // Student figures (indifferent)
    for(let i = 0; i < 6; i++) {
      students.push({
        x: p.random(240, 360),
        y: p.random(200, 500),
        size: p.random(3, 6),
        opacity: p.random(0.3, 0.6)
      });
    }
  };

  p.draw = function() {
    // Muddy background palette
    p.background(45, 52, 38);
    time += 0.01;

    // Calculate transition progress
    transitionProgress = p.map(p.sin(time * 0.5), -1, 1, 0, 1);

    // Tower nets (fading)
    p.stroke(78, 89, 65, 150);
    p.strokeWeight(1);
    for(let net of towerNets) {
      let alpha = net.opacity * (0.7 - transitionProgress * 0.4);
      p.stroke(78, 89, 65, alpha * 255);

      // Irregular, overlapping lines
      let wobbleX1 = net.x1 + p.sin(time * 2 + net.x1 * 0.1) * 2;
      let wobbleY1 = net.y1 + p.cos(time * 1.5 + net.y1 * 0.1) * 1.5;
      let wobbleX2 = net.x2 + p.sin(time * 1.8 + net.x2 * 0.1) * 2;
      let wobbleY2 = net.y2 + p.cos(time * 2.2 + net.y2 * 0.1) * 1.5;

      p.line(wobbleX1, wobbleY1, wobbleX2, wobbleY2);

      // Add crossing lines for net effect
      if(p.random() < 0.3) {
        let midX = (wobbleX1 + wobbleX2) / 2 + p.random(-10, 10);
        let midY = (wobbleY1 + wobbleY2) / 2 + p.random(-10, 10);
        p.line(wobbleX1, wobbleY1, midX, midY);
        p.line(midX, midY, wobbleX2, wobbleY2);
      }
    }

    // Classroom nets (tightening)
    for(let net of classroomNets) {
      let alpha = net.opacity * (0.4 + transitionProgress * 0.6);
      p.stroke(89, 78, 52, alpha * 255);
      p.strokeWeight(1 + transitionProgress * 0.5);

      // Tightening effect with more erratic movement
      let tighten = 1 - transitionProgress * 0.3;
      let wobbleX1 = net.x1 + p.sin(time * 3 + net.x1 * 0.15) * 3 * tighten;
      let wobbleY1 = net.y1 + p.cos(time * 2.5 + net.y1 * 0.15) * 2 * tighten;
      let wobbleX2 = net.x2 + p.sin(time * 2.7 + net.x2 * 0.15) * 3 * tighten;
      let wobbleY2 = net.y2 + p.cos(time * 3.1 + net.y2 * 0.15) * 2 * tighten;

      p.line(wobbleX1, wobbleY1, wobbleX2, wobbleY2);

      // Dense crossing pattern
      if(p.random() < 0.4) {
        let cross1X = wobbleX1 + p.random(-15, 15);
        let cross1Y = wobbleY1 + p.random(-15, 15);
        let cross2X = wobbleX2 + p.random(-15, 15);
        let cross2Y = wobbleY2 + p.random(-15, 15);
        p.line(cross1X, cross1Y, cross2X, cross2Y);
      }
    }

    // Connecting nets (threads of nationality, language, religion)
    p.stroke(67, 72, 58, 180);
    p.strokeWeight(2);
    for(let net of connectingNets) {
      let wave1 = p.sin(time * net.frequency + net.phase) * 8;
      let wave2 = p.cos(time * net.frequency * 1.3 + net.phase) * 6;

      p.line(net.x1, net.y1 + wave1, net.x2, net.y2 + wave2);

      // Multiple overlapping connection lines
      p.strokeWeight(1);
      p.line(net.x1 + 5, net.y1 + wave2, net.x2 - 5, net.y2 + wave1);
      p.line(net.x1 - 3, net.y1 - wave1, net.x2 + 3, net.y2 - wave2);
    }

    // Stephen figure - thin, black, caught between
    stephen.x = p.lerp(stephen.x, stephen.targetX + p.sin(time) * 10, stephen.moveSpeed);

    p.fill(20, 25, 18);
    p.noStroke();
    p.ellipse(stephen.x, stephen.y, 8, 12); // body
    p.ellipse(stephen.x, stephen.y - 8, 5, 5); // head

    // Show Stephen caught in nets
    p.stroke(89, 78, 52, 120);
    p.strokeWeight(1);
    for(let i = 0; i < 5; i++) {
      let netX = stephen.x + p.sin(time * 2 + i) * 15;
      let netY = stephen.y + p.cos(time * 1.8 + i) * 12;
      p.line(stephen.x, stephen.y, netX, netY);
    }

    // Coins caught in classroom nets
    p.fill(120, 108, 78);
    p.noStroke();
    for(let coin of coins) {
      let bobY = coin.y + p.sin(time * coin.bobSpeed + coin.x * 0.1) * 3;
      p.ellipse(coin.x, bobY, coin.size, coin.size);

      // Net lines catching coins
      p.stroke(89, 78, 52, 100);
      p.strokeWeight(1);
      p.line(coin.x - 10, bobY - 5, coin.x + 10, bobY + 5);
      p.line(coin.x - 8, bobY + 7, coin.x + 12, bobY - 8);
    }

    // Student figures (indifferent, netted)
    p.fill(60, 65, 52);
    p.noStroke();
    for(let student of students) {
      p.ellipse(student.x, student.y, student.size, student.size);

      // Indifference nets
      p.stroke(78, 72, 58, student.opacity * 100);
      p.strokeWeight(1);
      let netSpread = 8;
      p.line(student.x - netSpread, student.y - netSpread, 
             student.x + netSpread, student.y + netSpread);
      p.line(student.x - netSpread, student.y + netSpread, 
             student.x + netSpread, student.y - netSpread);
    }

    // Interactive mouse effect - disturb the nets
    if(p.mouseX > 0 && p.mouseX < 400 && p.mouseY > 0 && p.mouseY < 600) {
      p.stroke(100, 85, 65, 150);
      p.strokeWeight(1);
      let disturbance = p.map(p.mouseX, 0, 400, 0, 20);
      for(let i = 0; i < 8; i++) {
        let angle = (i / 8) * p.TWO_PI;
        let x1 = p.mouseX + p.cos(angle + time) * disturbance;
        let y1 = p.mouseY + p.sin(angle + time) * disturbance;
        let x2 = p.mouseX + p.cos(angle + time + p.PI) * disturbance;
        let y2 = p.mouseY + p.sin(angle + time + p.PI) * disturbance;
        p.line(x1, y1, x2, y2);
      }
    }

    // Crushing weight overlay - subtle darkening at edges
    p.fill(25, 30, 22, 30);
    p.noStroke();
    p.rect(0, 0, 400, 50); // top
    p.rect(0, 550, 400, 50); // bottom
    p.rect(0, 0, 30, 600); // left
    p.rect(370, 0, 30, 600); // right
  };
}

