function sketch(p) {
  let nets = [];
  let figure;
  let time = 0;
  let particles = [];

  p.setup = function() {
    p.createCanvas(400, 600);

    // Initialize the three nets
    nets.push(new Net(p, 'nationality', p.color(34, 139, 34, 180))); // Green
    nets.push(new Net(p, 'language', p.color(120, 120, 120, 180))); // Grey
    nets.push(new Net(p, 'religion', p.color(20, 20, 20, 200))); // Black

    // Central figure position
    figure = {
      x: 200,
      y: 300,
      pullX: 0,
      pullY: 0
    };

    // Initialize particles for atmospheric effect
    for (let i = 0; i < 50; i++) {
      particles.push({
        x: p.random(400),
        y: p.random(600),
        vx: p.random(-0.5, 0.5),
        vy: p.random(-0.5, 0.5),
        alpha: p.random(20, 60)
      });
    }
  };

  p.draw = function() {
    p.background(15, 15, 25);
    time += 0.02;

    // Update particles
    particles.forEach(particle => {
      particle.x += particle.vx;
      particle.y += particle.vy;
      if (particle.x < 0 || particle.x > 400) particle.vx *= -1;
      if (particle.y < 0 || particle.y > 600) particle.vy *= -1;

      p.fill(200, 200, 200, particle.alpha);
      p.noStroke();
      p.circle(particle.x, particle.y, 2);
    });

    // Calculate figure struggle motion
    let mouseInfluence = p.dist(p.mouseX, p.mouseY, figure.x, figure.y) / 100;
    figure.pullX = p.cos(time * 2) * 15 + p.sin(time * 3) * 8;
    figure.pullY = p.sin(time * 1.5) * 12 + p.cos(time * 2.5) * 6;

    if (mouseInfluence < 2) {
      figure.pullX += (p.mouseX - figure.x) * 0.1;
      figure.pullY += (p.mouseY - figure.y) * 0.1;
    }

    // Draw the three nets in triangular formation
    p.push();
    p.translate(200, 300);

    // Nationality net (top)
    p.push();
    p.rotate(-p.PI / 6);
    p.translate(0, -120);
    nets[0].draw(time);
    p.pop();

    // Language net (bottom right)
    p.push();
    p.rotate(p.PI / 2);
    p.translate(0, -120);
    nets[1].draw(time + p.PI / 3);
    p.pop();

    // Religion net (bottom left)
    p.push();
    p.rotate(p.PI + p.PI / 6);
    p.translate(0, -120);
    nets[2].draw(time + 2 * p.PI / 3);
    p.pop();

    p.pop();

    // Draw connecting strands between nets
    p.stroke(100, 100, 100, 150);
    p.strokeWeight(2);
    for (let i = 0; i < 15; i++) {
      let angle1 = (i / 15) * p.TWO_PI;
      let angle2 = ((i + 5) / 15) * p.TWO_PI;
      let r1 = 80 + p.sin(time + i) * 20;
      let r2 = 80 + p.cos(time + i + 1) * 20;

      p.line(
        200 + p.cos(angle1) * r1,
        300 + p.sin(angle1) * r1,
        200 + p.cos(angle2) * r2,
        300 + p.sin(angle2) * r2
      );
    }

    // Draw central figure
    p.push();
    p.translate(figure.x + figure.pullX, figure.y + figure.pullY);

    // Figure shadow
    p.fill(0, 0, 0, 100);
    p.noStroke();
    p.ellipse(2, 2, 40, 60);

    // Figure body
    p.stroke(200, 200, 180);
    p.strokeWeight(3);
    p.noFill();

    // Head
    p.circle(0, -20, 16);

    // Body
    p.line(0, -12, 0, 20);

    // Arms showing struggle
    let armAngle = p.sin(time * 4) * 0.3;
    p.line(0, -5, -15 + p.cos(armAngle) * 5, 5 + p.sin(armAngle) * 3);
    p.line(0, -5, 15 - p.cos(armAngle) * 5, 5 - p.sin(armAngle) * 3);

    // Legs
    p.line(0, 20, -8, 35);
    p.line(0, 20, 8, 35);

    p.pop();

    // Draw net binding effects on figure
    p.stroke(34, 139, 34, 100);
    p.strokeWeight(2);
    for (let i = 0; i < 5; i++) {
      let angle = (i / 5) * p.TWO_PI + time;
      p.line(
        figure.x + figure.pullX,
        figure.y + figure.pullY,
        figure.x + figure.pullX + p.cos(angle) * 25,
        figure.y + figure.pullY + p.sin(angle) * 25
      );
    }

    p.stroke(120, 120, 120, 100);
    for (let i = 0; i < 5; i++) {
      let angle = (i / 5) * p.TWO_PI + time + p.PI / 3;
      p.line(
        figure.x + figure.pullX,
        figure.y + figure.pullY,
        figure.x + figure.pullX + p.cos(angle) * 20,
        figure.y + figure.pullY + p.sin(angle) * 20
      );
    }

    p.stroke(20, 20, 20, 150);
    for (let i = 0; i < 5; i++) {
      let angle = (i / 5) * p.TWO_PI + time + 2 * p.PI / 3;
      p.line(
        figure.x + figure.pullX,
        figure.y + figure.pullY,
        figure.x + figure.pullX + p.cos(angle) * 30,
        figure.y + figure.pullY + p.sin(angle) * 30
      );
    }
  };

  class Net {
    constructor(p, type, color) {
      this.p = p;
      this.type = type;
      this.color = color;
      this.nodes = [];
      this.connections = [];

      // Create net structure
      for (let i = 0; i < 8; i++) {
        for (let j = 0; j < 6; j++) {
          this.nodes.push({
            x: (i - 3.5) * 25,
            y: (j - 2.5) * 20,
            originalX: (i - 3.5) * 25,
            originalY: (j - 2.5) * 20
          });
        }
      }

      // Create connections
      for (let i = 0; i < 8; i++) {
        for (let j = 0; j < 6; j++) {
          let index = i * 6 + j;
          if (i < 7) this.connections.push([index, index + 6]);
          if (j < 5) this.connections.push([index, index + 1]);
        }
      }
    }

    draw(t) {
      // Animate nodes
      this.nodes.forEach((node, i) => {
        let wave = this.p.sin(t + i * 0.1) * 3;
        node.x = node.originalX + wave;
        node.y = node.originalY + this.p.cos(t + i * 0.15) * 2;
      });

      // Draw net
      this.p.stroke(this.color);
      this.p.strokeWeight(1.5);

      this.connections.forEach(conn => {
        let n1 = this.nodes[conn[0]];
        let n2 = this.nodes[conn[1]];
        this.p.line(n1.x, n1.y, n2.x, n2.y);
      });

      // Draw characteristic symbols
      this.p.fill(this.color);
      this.p.noStroke();

      if (this.type === 'nationality') {
        // Irish symbolism
        for (let i = 0; i < 3; i++) {
          this.p.rect(-30 + i * 20, -40, 4, 8);
        }
      } else if (this.type === 'language') {
        // Text/grammar symbols
        this.p.textAlign(this.p.CENTER);
        this.p.textSize(8);
        this.p.fill(120, 120, 120, 200);
        this.p.text("VERBA", 0, -35);
      } else if (this.type === 'religion') {
        // Cross symbol
        this.p.rect(-2, -45, 4, 12);
        this.p.rect(-6, -41, 12, 4);
      }
    }
  }
}

