function sketch(p) {
  let nets = [];
  let figure;
  let buildings = [];
  let river;
  let time = 0;
  let spires = [];

  p.setup = function() {
    p.createCanvas(400, 600);

    // Create net grid overlaying streets
    for(let x = 50; x < 350; x += 80) {
      for(let y = 100; y < 500; y += 60) {
        nets.push(new NetSection(x, y, 80, 60));
      }
    }

    // Create cage-like buildings
    for(let i = 0; i < 12; i++) {
      buildings.push(new CageBuilding(
        p.random(40, 360),
        p.random(120, 480),
        p.random(30, 60),
        p.random(40, 80)
      ));
    }

    // River as thick net-rope
    river = new NetRiver();

    // Wandering figure
    figure = new TrappedFigure();

    // Church spires as net-posts
    spires.push(new NetSpire(100, 150));
    spires.push(new NetSpire(300, 180));
    spires.push(new NetSpire(200, 320));
  };

  p.draw = function() {
    time += 0.02;

    // Muddy green-brown background with pressure gradient
    for(let i = 0; i < p.height; i++) {
      let alpha = p.map(i, 0, p.height, 0.3, 0.8);
      p.stroke(p.lerpColor(p.color(60, 80, 40), p.color(80, 60, 30), alpha));
      p.line(0, i, p.width, i);
    }

    // Draw river as binding net-rope
    river.display();

    // Draw cage buildings
    for(let building of buildings) {
      building.display();
    }

    // Draw net overlay on streets
    for(let net of nets) {
      net.display();
      net.tighten();
    }

    // Draw spires as net-posts
    for(let spire of spires) {
      spire.display();
    }

    // Draw trapped figure
    figure.update();
    figure.display();

    // Prison bars effect - the city's bounds
    p.stroke(40, 50, 20, 150);
    p.strokeWeight(8);
    for(let i = 0; i < 4; i++) {
      let x = p.map(i, 0, 3, 30, 370);
      p.line(x, 0, x, p.height);
    }
    for(let i = 0; i < 6; i++) {
      let y = p.map(i, 0, 5, 80, 520);
      p.line(0, y, p.width, y);
    }
  };

  class NetSection {
    constructor(x, y, w, h) {
      this.x = x;
      this.y = y;
      this.w = w;
      this.h = h;
      this.tension = 0;
    }

    display() {
      p.stroke(70, 90, 50, 180);
      p.strokeWeight(2);
      p.noFill();

      // Net mesh pattern
      let spacing = 15;
      for(let i = 0; i <= this.w; i += spacing) {
        let wave = p.sin(time + i * 0.1) * this.tension;
        p.line(this.x + i, this.y + wave, this.x + i, this.y + this.h + wave);
      }
      for(let j = 0; j <= this.h; j += spacing) {
        let wave = p.cos(time + j * 0.1) * this.tension;
        p.line(this.x + wave, this.y + j, this.x + this.w + wave, this.y + j);
      }

      // Intersection knots
      p.fill(50, 70, 30);
      for(let i = 0; i <= this.w; i += spacing) {
        for(let j = 0; j <= this.h; j += spacing) {
          p.ellipse(this.x + i, this.y + j, 4, 4);
        }
      }
    }

    tighten() {
      this.tension = p.sin(time * 0.5) * 3;
    }
  }

  class CageBuilding {
    constructor(x, y, w, h) {
      this.x = x;
      this.y = y;
      this.w = w;
      this.h = h;
    }

    display() {
      p.stroke(80, 70, 40, 200);
      p.strokeWeight(1.5);
      p.noFill();

      // Cage frame
      p.rect(this.x, this.y, this.w, this.h);

      // Vertical bars
      for(let i = 0; i < this.w; i += 8) {
        p.line(this.x + i, this.y, this.x + i, this.y + this.h);
      }

      // Horizontal bars
      for(let j = 0; j < this.h; j += 10) {
        p.line(this.x, this.y + j, this.x + this.w, this.y + j);
      }

      // Net-hole windows
      p.fill(40, 60, 30, 100);
      for(let i = 5; i < this.w - 5; i += 15) {
        for(let j = 8; j < this.h - 8; j += 18) {
          let size = p.sin(time + i + j) * 2 + 6;
          p.ellipse(this.x + i, this.y + j, size, size);
        }
      }
    }
  }

  class NetRiver {
    constructor() {
      this.points = [];
      for(let i = 0; i < 40; i++) {
        this.points.push({
          x: p.map(i, 0, 39, 0, p.width),
          y: p.height * 0.6 + p.sin(i * 0.3) * 20
        });
      }
    }

    display() {
      p.stroke(90, 80, 50, 200);
      p.strokeWeight(8);
      p.noFill();

      // Main rope
      p.beginShape();
      for(let point of this.points) {
        let wave = p.sin(time + point.x * 0.01) * 5;
        p.vertex(point.x, point.y + wave);
      }
      p.endShape();

      // Binding strands
      p.strokeWeight(3);
      for(let i = 0; i < this.points.length - 1; i += 3) {
        let p1 = this.points[i];
        let p2 = this.points[i + 1];
        let twist = p.sin(time + i) * 10;
        p.line(p1.x, p1.y + twist, p2.x, p2.y - twist);
      }
    }
  }

  class TrappedFigure {
    constructor() {
      this.x = 200;
      this.y = 300;
      this.targetX = 200;
      this.targetY = 300;
      this.entanglement = 0;
    }

    update() {
      // Try to move toward mouse but get increasingly tangled
      let mouseInfluence = p.dist(p.mouseX, p.mouseY, this.x, this.y);
      if(mouseInfluence < 100) {
        this.targetX = p.lerp(this.targetX, p.mouseX, 0.05);
        this.targetY = p.lerp(this.targetY, p.mouseY, 0.05);
        this.entanglement += 0.1;
      }

      // Movement becomes more restricted
      let restriction = p.constrain(this.entanglement, 0, 5);
      this.x = p.lerp(this.x, this.targetX, 0.1 / (1 + restriction));
      this.y = p.lerp(this.y, this.targetY, 0.1 / (1 + restriction));

      this.entanglement *= 0.98;
    }

    display() {
      p.pushMatrix();
      p.translate(this.x, this.y);

      // Figure body
      p.fill(100, 80, 60);
      p.noStroke();
      p.ellipse(0, -10, 8, 12);
      p.rect(-2, -5, 4, 15);

      // Net entanglements
      p.stroke(70, 90, 50, 150);
      p.strokeWeight(1);
      for(let i = 0; i < this.entanglement * 3; i++) {
        let angle = i * 0.8 + time;
        let len = 15 + i * 5;
        p.line(0, 0, p.cos(angle) * len, p.sin(angle) * len);
      }

      p.popMatrix();
    }
  }

  class NetSpire {
    constructor(x, y) {
      this.x = x;
      this.y = y;
      this.height = 60;
    }

    display() {
      // Spire as net-post
      p.stroke(60, 80, 40, 220);
      p.strokeWeight(4);
      p.line(this.x, this.y, this.x, this.y - this.height);

      // Net cables radiating from spire
      p.strokeWeight(2);
      for(let angle = 0; angle < p.TWO_PI; angle += p.PI/4) {
        let len = 40 + p.sin(time + angle) * 10;
        let endX = this.x + p.cos(angle) * len;
        let endY = this.y + p.sin(angle) * len;
        p.line(this.x, this.y - this.height/2, endX, endY);
      }
    }
  }
}

