function sketch(p) {
  let stephen;
  let backgroundFigures = [];
  let nets = [];
  let stephenNets = [];
  let time = 0;

  p.setup = function() {
    p.createCanvas(400, 600);

    // Initialize Stephen (the outsider)
    stephen = {
      x: 200,
      y: 300,
      angle: 0,
      breathe: 0
    };

    // Create background figures
    for (let i = 0; i < 4; i++) {
      backgroundFigures.push({
        x: 80 + i * 80,
        y: 150 + p.random(-30, 30),
        drift: p.random(0.01, 0.03),
        phase: p.random(p.TWO_PI)
      });
    }

    // Create city nets (regular mesh)
    for (let x = 0; x < p.width + 100; x += 40) {
      for (let y = 0; y < p.height + 100; y += 40) {
        nets.push({
          x: x,
          y: y,
          opacity: p.random(0.2, 0.6),
          drift: p.random(-0.5, 0.5)
        });
      }
    }

    // Create Stephen's extra nets (irregular, denser)
    for (let i = 0; i < 25; i++) {
      stephenNets.push({
        x: stephen.x + p.random(-80, 80),
        y: stephen.y + p.random(-80, 80),
        angle: p.random(p.TWO_PI),
        length: p.random(30, 120),
        tangle: p.random(0.1, 0.3),
        crush: p.random(0.02, 0.05)
      });
    }
  };

  p.draw = function() {
    time += 0.01;

    // Dark, oppressive background
    p.background(25, 30, 20);

    // Draw city nets (regular mesh)
    p.stroke(60, 80, 40, 150);
    p.strokeWeight(1);
    p.noFill();

    for (let net of nets) {
      let offsetX = p.sin(time + net.drift) * 2;
      let offsetY = p.cos(time * 0.7 + net.drift) * 1;

      p.stroke(60, 80, 40, net.opacity * 255);
      p.rect(net.x + offsetX, net.y + offsetY, 40, 40);
    }

    // Draw background figures (moving more freely)
    p.fill(80, 100, 60, 180);
    p.noStroke();

    for (let figure of backgroundFigures) {
      let x = figure.x + p.sin(time * figure.drift + figure.phase) * 15;
      let y = figure.y + p.cos(time * figure.drift * 0.8 + figure.phase) * 8;

      p.ellipse(x, y, 20, 35);
      p.ellipse(x, y - 25, 15, 15); // head
    }

    // Draw Stephen's extra nets (dense, tangled, crushing)
    stephen.breathe = p.sin(time * 2) * 3;
    stephen.angle = p.sin(time * 0.5) * 0.1;

    p.strokeWeight(2);

    for (let net of stephenNets) {
      let crush = p.sin(time * net.crush + net.tangle) * 10;
      let x1 = stephen.x + p.cos(net.angle) * net.length * 0.3 + crush;
      let y1 = stephen.y + p.sin(net.angle) * net.length * 0.3 + crush;
      let x2 = stephen.x + p.cos(net.angle + p.PI) * net.length * 0.7 + crush;
      let y2 = stephen.y + p.sin(net.angle + p.PI) * net.length * 0.7 + crush;

      // Muddy, dense colors for Stephen's nets
      p.stroke(90, 70, 40, 200);
      p.line(x1, y1, x2, y2);

      // Cross-nets creating mesh
      let perpX1 = x1 + p.cos(net.angle + p.HALF_PI) * 20;
      let perpY1 = y1 + p.sin(net.angle + p.HALF_PI) * 20;
      let perpX2 = x2 + p.cos(net.angle - p.HALF_PI) * 20;
      let perpY2 = y2 + p.sin(net.angle - p.HALF_PI) * 20;

      p.stroke(70, 60, 30, 150);
      p.line(perpX1, perpY1, perpX2, perpY2);
    }

    // Draw additional tangled nets around Stephen
    p.strokeWeight(3);
    p.stroke(100, 80, 50, 180);
    p.noFill();

    for (let i = 0; i < 8; i++) {
      let radius = 40 + i * 8;
      let segments = 5; // five-pointed irregularity

      p.beginShape();
      for (let j = 0; j <= segments; j++) {
        let angle = (j / segments) * p.TWO_PI + time * 0.3;
        let r = radius + p.sin(time * 2 + i * 0.5) * 8;
        let x = stephen.x + p.cos(angle) * r;
        let y = stephen.y + p.sin(angle) * r;
        p.vertex(x, y);
      }
      p.endShape(p.CLOSE);
    }

    // Draw Stephen (compressed, struggling)
    p.push();
    p.translate(stephen.x, stephen.y + stephen.breathe);
    p.rotate(stephen.angle);

    // Body compressed by nets
    p.fill(120, 100, 80);
    p.noStroke();
    p.ellipse(0, 0, 25 - stephen.breathe * 0.5, 40 + stephen.breathe);

    // Head
    p.fill(140, 120, 100);
    p.ellipse(0, -30, 18, 20);

    // Arms pressed against body
    p.fill(110, 90, 70);
    p.ellipse(-8, -5, 6, 20);
    p.ellipse(8, -5, 6, 20);

    p.pop();

    // Draw pentagram geometry suggestion (five-pointed nature)
    p.stroke(150, 120, 80, 100);
    p.strokeWeight(1);
    p.noFill();

    for (let i = 0; i < 5; i++) {
      let angle = (i / 5) * p.TWO_PI - p.HALF_PI + time * 0.1;
      let x = stephen.x + p.cos(angle) * 60;
      let y = stephen.y + p.sin(angle) * 60;
      p.line(stephen.x, stephen.y, x, y);
    }

    // Interactive mouse effect - more nets appear near cursor
    if (p.mouseX > 0 && p.mouseX < p.width && p.mouseY > 0 && p.mouseY < p.height) {
      let distToStephen = p.dist(p.mouseX, p.mouseY, stephen.x, stephen.y);
      if (distToStephen < 100) {
        p.stroke(120, 90, 60, 150);
        p.strokeWeight(2);

        for (let i = 0; i < 6; i++) {
          let angle = (i / 6) * p.TWO_PI + time;
          let x1 = p.mouseX + p.cos(angle) * 30;
          let y1 = p.mouseY + p.sin(angle) * 30;
          let x2 = stephen.x + p.cos(angle + p.PI) * 20;
          let y2 = stephen.y + p.sin(angle + p.PI) * 20;

          p.line(x1, y1, x2, y2);
        }
      }
    }
  };
}

