function sketch(p) {
  let figure1, figure2;
  let nets1 = [];
  let nets2 = [];
  let connectionNets = [];
  let time = 0;
  let recognitionPulse = 0;
  let mudColors = [];

  p.setup = function() {
    p.createCanvas(400, 600);

    // Muddy palette colors
    mudColors = [
      p.color(89, 67, 52),    // muddy brown
      p.color(67, 89, 72),    // muddy green
      p.color(78, 73, 89),    // muddy purple
      p.color(89, 78, 67),    // muddy ochre
      p.color(72, 78, 89),    // muddy blue
      p.color(89, 72, 67)     // muddy rust
    ];

    // Position figures
    figure1 = { x: 120, y: 320, nets: [] };
    figure2 = { x: 280, y: 380, nets: [] };

    // Create irregular nets for each figure
    for (let i = 0; i < 8; i++) {
      nets1.push({
        points: generateIrregularNet(figure1.x, figure1.y, 80),
        color: p.random(mudColors),
        intensity: p.random(0.3, 0.8),
        type: p.random(['guilt', 'obligation', 'language'])
      });
    }

    for (let i = 0; i < 8; i++) {
      nets2.push({
        points: generateIrregularNet(figure2.x, figure2.y, 75),
        color: p.random(mudColors),
        intensity: p.random(0.3, 0.8),
        type: p.random(['guilt', 'obligation', 'language'])
      });
    }

    // Create connection nets between figures
    for (let i = 0; i < 12; i++) {
      connectionNets.push({
        start: { x: figure1.x + p.random(-40, 40), y: figure1.y + p.random(-40, 40) },
        end: { x: figure2.x + p.random(-40, 40), y: figure2.y + p.random(-40, 40) },
        controlPoints: [],
        color: p.random(mudColors),
        recognition: 0
      });
    }

    // Add control points for irregular paths
    connectionNets.forEach(net => {
      let numPoints = p.random(3, 6);
      for (let i = 0; i < numPoints; i++) {
        net.controlPoints.push({
          x: p.lerp(net.start.x, net.end.x, i / (numPoints - 1)) + p.random(-30, 30),
          y: p.lerp(net.start.y, net.end.y, i / (numPoints - 1)) + p.random(-20, 20)
        });
      }
    });
  };

  p.draw = function() {
    // Dark muddy background
    p.background(42, 38, 35);

    time += 0.02;

    // Mouse interaction affects recognition intensity
    let mouseInfluence = 1 - p.dist(p.mouseX, p.mouseY, 200, 350) / 300;
    recognitionPulse = p.sin(time * 2) * 0.3 + 0.7 + mouseInfluence * 0.5;

    // Draw compressed Dublin space suggestion
    drawCompressedSpace();

    // Draw figure nets with pulsing entanglement
    drawFigureNets(nets1, figure1, recognitionPulse);
    drawFigureNets(nets2, figure2, recognitionPulse);

    // Draw connection nets - the moment of recognition
    drawConnectionNets();

    // Draw the figures as silhouettes caught in nets
    drawFigure(figure1.x, figure1.y, 1);
    drawFigure(figure2.x, figure2.y, 0.9);

    // Subtle recognition glow
    if (recognitionPulse > 1.2) {
      p.push();
      p.blendMode(p.SCREEN);
      p.fill(89, 78, 67, 20);
      p.noStroke();
      p.ellipse(200, 350, 200 * recognitionPulse, 150 * recognitionPulse);
      p.pop();
    }
  };

  function generateIrregularNet(centerX, centerY, size) {
    let points = [];
    let numStrands = p.random(5, 9);

    for (let i = 0; i < numStrands; i++) {
      let strand = [];
      let angle = p.random(p.TWO_PI);
      let length = p.random(size * 0.3, size);

      // Create irregular strand
      for (let j = 0; j < p.random(4, 8); j++) {
        let t = j / 7;
        let x = centerX + p.cos(angle + p.sin(t * 3) * 0.5) * length * t;
        let y = centerY + p.sin(angle + p.cos(t * 4) * 0.3) * length * t;
        x += p.random(-15, 15);
        y += p.random(-10, 10);
        strand.push({ x, y });
      }
      points.push(strand);
    }
    return points;
  }

  function drawCompressedSpace() {
    p.push();
    p.stroke(65, 58, 52, 100);
    p.strokeWeight(1);

    // Compressed perspective lines suggesting Dublin streets
    for (let i = 0; i < 8; i++) {
      let y = 50 + i * 70;
      p.line(0, y, 400, y + p.sin(time + i) * 20);
    }

    // Vertical compression
    for (let i = 0; i < 6; i++) {
      let x = 60 + i * 60;
      p.line(x, 0, x + p.cos(time + i) * 15, 600);
    }
    p.pop();
  }

  function drawFigureNets(nets, figure, pulse) {
    p.push();

    nets.forEach((net, netIndex) => {
      let alpha = net.intensity * pulse * 255;
      let col = p.color(p.red(net.color), p.green(net.color), p.blue(net.color), alpha);
      p.stroke(col);
      p.strokeWeight(p.random(1, 3));
      p.noFill();

      // Draw irregular net strands
      net.points.forEach(strand => {
        p.beginShape();
        p.noFill();
        strand.forEach((point, i) => {
          let wobble = p.sin(time * 3 + netIndex + i) * 2;
          p.curveVertex(point.x + wobble, point.y + wobble);
        });
        p.endShape();
      });

      // Draw connecting threads within net
      for (let i = 0; i < net.points.length - 1; i++) {
        if (p.random() < 0.3) {
          let strand1 = net.points[i];
          let strand2 = net.points[i + 1];
          if (strand1.length > 0 && strand2.length > 0) {
            let p1 = strand1[p.floor(p.random(strand1.length))];
            let p2 = strand2[p.floor(p.random(strand2.length))];
            p.line(p1.x, p1.y, p2.x, p2.y);
          }
        }
      }
    });

    p.pop();
  }

  function drawConnectionNets() {
    p.push();

    connectionNets.forEach((net, index) => {
      let recognitionLevel = recognitionPulse * (0.7 + p.sin(time + index) * 0.3);
      let alpha = recognitionLevel * 180;

      let col = p.color(p.red(net.color), p.green(net.color), p.blue(net.color), alpha);
      p.stroke(col);
      p.strokeWeight(2 + recognitionLevel);
      p.noFill();

      // Draw irregular connection path
      p.beginShape();
      p.noFill();
      p.curveVertex(net.start.x, net.start.y);

      net.controlPoints.forEach((point, i) => {
        let tremor = p.sin(time * 4 + index + i) * 3;
        p.curveVertex(point.x + tremor, point.y + tremor);
      });

      p.curveVertex(net.end.x, net.end.y);
      p.endShape();

      // Add connection nodes where nets intersect
      if (recognitionLevel > 1.0) {
        net.controlPoints.forEach(point => {
          p.fill(col);
          p.noStroke();
          p.ellipse(point.x, point.y, 3, 3);
        });
      }
    });

    p.pop();
  }

  function drawFigure(x, y, scale) {
    p.push();
    p.translate(x, y);
    p.scale(scale);

    // Draw figure as shadowy silhouette caught in nets
    p.fill(28, 25, 22);
    p.noStroke();

    // Body
    p.ellipse(0, 0, 25, 45);

    // Head
    p.ellipse(0, -30, 20, 20);

    // Arms reaching out, entangled
    p.push();
    p.rotate(p.sin(time) * 0.1);
    p.ellipse(-15, -5, 6, 25);
    p.ellipse(15, -5, 6, 25);
    p.pop();

    // Legs
    p.ellipse(-8, 25, 8, 20);
    p.ellipse(8, 25, 8, 20);

    // Eyes - recognition
    p.fill(89, 78, 67, 150);
    p.ellipse(-4, -30, 2, 2);
    p.ellipse(4, -30, 2, 2);

    p.pop();
  }
}

