function sketch(p) {
  let nets = [];
  let figure;
  let time = 0;

  p.setup = function() {
    p.createCanvas(400, 600);

    // Initialize figure position
    figure = {
      x: 200,
      y: 300,
      offsetX: 0,
      offsetY: 0
    };

    // Create seven nets with asymmetric properties
    nets = [
      // Three tight nets (left side)
      { x: 120, y: 180, size: 60, tightness: 0.8, weight: 1.2, side: 'left', pull: 0.6 },
      { x: 80, y: 280, size: 70, tightness: 0.9, weight: 1.4, side: 'left', pull: 0.8 },
      { x: 100, y: 380, size: 55, tightness: 0.85, weight: 1.3, side: 'left', pull: 0.7 },

      // Four looser nets (right side)
      { x: 280, y: 150, size: 85, tightness: 0.3, weight: 0.7, side: 'right', pull: 0.3 },
      { x: 320, y: 250, size: 90, tightness: 0.25, weight: 0.6, side: 'right', pull: 0.35 },
      { x: 290, y: 350, size: 80, tightness: 0.4, weight: 0.8, side: 'right', pull: 0.4 },
      { x: 310, y: 450, size: 75, tightness: 0.35, weight: 0.75, side: 'right', pull: 0.38 }
    ];
  };

  p.draw = function() {
    // Muddy, compressed palette
    p.background(45, 38, 35);
    time += 0.02;

    // Calculate asymmetric pull on figure
    let leftPull = 0;
    let rightPull = 0;

    nets.forEach(net => {
      if (net.side === 'left') {
        leftPull += net.pull * net.weight;
      } else {
        rightPull += net.pull * net.weight;
      }
    });

    // Apply asymmetric offset to figure
    figure.offsetX = p.lerp(figure.offsetX, (rightPull - leftPull) * 15, 0.05);
    figure.offsetY = p.sin(time * 0.5) * 3 + p.cos(time * 0.3) * 2;

    // Draw connecting strands first (behind everything)
    p.stroke(60, 55, 45, 120);
    p.strokeWeight(1);
    nets.forEach(net => {
      let pull = p.sin(time + net.x * 0.01) * net.tightness * 5;
      p.line(net.x + pull, net.y + pull, 
             figure.x + figure.offsetX, figure.y + figure.offsetY);
    });

    // Draw nets with asymmetric behavior
    nets.forEach((net, i) => {
      p.push();

      let pulse = p.sin(time * 2 + i * 0.5) * net.tightness * 3;
      let drift = p.cos(time * 0.8 + i * 0.3) * (1 - net.tightness) * 8;

      p.translate(net.x + drift, net.y + pulse);
      p.rotate(time * 0.1 * net.tightness + i * 0.2);

      // Net color varies by tightness and weight
      let netAlpha = 80 + net.tightness * 100;
      if (net.side === 'left') {
        p.stroke(120, 80, 60, netAlpha); // Tighter, more reddish
        p.fill(80, 50, 40, 30 + net.tightness * 40);
      } else {
        p.stroke(80, 90, 70, netAlpha); // Looser, more greenish
        p.fill(60, 70, 55, 20 + net.tightness * 30);
      }

      p.strokeWeight(0.5 + net.tightness * 1.5);

      // Draw irregular net pattern
      let gridSize = 8 + net.tightness * 4;
      for (let x = -net.size/2; x < net.size/2; x += gridSize) {
        for (let y = -net.size/2; y < net.size/2; y += gridSize) {
          let distortion = p.sin(time + x * 0.1 + y * 0.1) * (1 - net.tightness) * 3;
          p.line(x, y + distortion, x + gridSize, y + distortion);
          p.line(x + distortion, y, x + distortion, y + gridSize);
        }
      }

      p.pop();
    });

    // Draw the figure (Stephen) showing asymmetric strain
    p.push();
    p.translate(figure.x + figure.offsetX, figure.y + figure.offsetY);

    // Body tilted by asymmetric pull
    let bodyTilt = figure.offsetX * 0.05;
    p.rotate(bodyTilt);

    // Figure colors - muted, strained
    p.fill(100, 85, 75, 180);
    p.stroke(70, 60, 55);
    p.strokeWeight(2);

    // Head
    p.ellipse(0, -40, 25, 30);

    // Body showing strain
    p.fill(80, 70, 65, 160);
    p.rect(-8, -20, 16, 35);

    // Arms pulled asymmetrically
    p.stroke(90, 75, 65);
    p.strokeWeight(4);
    p.line(-8, -10, -15 - figure.offsetX * 0.3, 5); // Left arm pulled
    p.line(8, -10, 15 + figure.offsetX * 0.2, 5);   // Right arm

    // Legs showing uneven stance
    p.line(-4, 15, -8 - figure.offsetX * 0.1, 35);
    p.line(4, 15, 8 + figure.offsetX * 0.1, 35);

    p.pop();

    // Subtle interactive element - mouse proximity affects net tension
    let mouseInfluence = p.map(p.dist(p.mouseX, p.mouseY, 200, 300), 0, 200, 1.2, 0.8);
    nets.forEach(net => {
      net.tightness *= mouseInfluence;
      net.tightness = p.constrain(net.tightness, 0.1, 1.0);
    });

    // Restore net tightness gradually
    nets.forEach(net => {
      if (net.side === 'left') {
        net.tightness = p.lerp(net.tightness, 0.8, 0.02);
      } else {
        net.tightness = p.lerp(net.tightness, 0.3, 0.02);
      }
    });

    // Overlay texture for compressed, oppressive feeling
    p.fill(30, 25, 20, 15);
    p.noStroke();
    for (let i = 0; i < 50; i++) {
      let x = p.random(400);
      let y = p.random(600);
      let size = p.random(2, 8);
      p.ellipse(x, y, size, size);
    }
  };
}

