        y: p.map(i, 0, 7, 550, 100),
        age: i,
        meshSize: p.map(i, 0, 7, 40, 15),
        opacity: p.map(i, 0, 7, 80, 140),
        color: p.lerpColor(p.color(40, 60, 30), p.color(80, 100, 50), i / 7),
        offset: p.random(p.TWO_PI),
        weight: p.map(i, 0, 7, 1, 4)
      });
    }

    // Figure drowning in nets
    figure = {
      x: 200,
      y: 350,
      struggle: 0
    };

    // Drowning bubbles
    for (let i = 0; i < 20; i++) {
      bubbles.push({
        x: p.random(150, 250),
        y: p.random(300, 500),
        size: p.random(3, 8),
        speed: p.random(0.5, 2),
        life: p.random(255)
      });
    }
  };

  p.draw = function() {
    // Deep muddy water background
    p.background(25, 35, 20);

    // Add depth gradient
    for (let y = 0; y < p.height; y++) {
      let alpha = p.map(y, 0, p.height, 0, 150);
      p.stroke(15, 25, 10, alpha);
      p.line(0, y, p.width, y);
    }

    // Draw accumulated nets from bottom to top
    for (let netLayer of nets) {
      drawNetLayer(netLayer);
    }

    // Draw drowning figure
    drawFigure();

    // Draw drowning bubbles
    updateBubbles();

    // Add crushing pressure effect
    drawPressureWaves();
  };

  function drawNetLayer(net) {
    p.push();
    p.translate(0, net.y + p.sin(p.millis() * 0.001 + net.offset) * 3);

    p.stroke(p.red(net.color), p.green(net.color), p.blue(net.color), net.opacity);
    p.strokeWeight(net.weight);
    p.noFill();

    // Draw mesh pattern
    let meshSize = net.meshSize + p.sin(p.millis() * 0.002) * 2;

    for (let x = 0; x <= p.width; x += meshSize) {
      for (let y = -50; y <= 100; y += meshSize) {
        let waveOffset = p.sin(p.millis() * 0.003 + x * 0.01 + net.age * 0.5) * 5;

        // Horizontal lines
        p.line(x, y + waveOffset, x + meshSize, y + waveOffset);
        // Vertical lines  
        p.line(x + waveOffset * 0.5, y, x + waveOffset * 0.5, y + meshSize);

        // Add entanglement knots
        if (p.random() < 0.1) {
          p.circle(x + meshSize/2, y + meshSize/2 + waveOffset, 3);
        }
      }
    }

    // Add historical weight visualization
    let compression = p.map(net.age, 0, 7, 0, 30);
    p.stroke(net.color, net.opacity * 0.3);
    p.strokeWeight(net.weight * 2);
    for (let i = 0; i < 3; i++) {
      p.line(50, -compression + i*2, p.width-50, -compression + i*2);
    }

    p.pop();
  }

  function drawFigure() {
    figure.struggle = p.sin(p.millis() * 0.005) * 20 + p.cos(p.millis() * 0.007) * 15;

    p.push();
    p.translate(figure.x + figure.struggle * 0.3, figure.y + figure.struggle * 0.5);

    // Figure silhouette struggling
    p.fill(60, 40, 30, 180);
    p.noStroke();

    // Body
    p.ellipse(0, 0, 30, 60);

    // Head
    p.ellipse(0, -35, 25, 25);

    // Arms reaching up desperately
    let armReach = p.sin(p.millis() * 0.01) * 30;
    p.strokeWeight(8);
    p.stroke(60, 40, 30, 150);
    p.line(-10, -10, -20 + armReach, -50);
    p.line(10, -10, 20 - armReach, -50);

    // Legs tangled in nets
    p.line(-8, 25, -15 + p.sin(p.millis() * 0.008) * 10, 50);
    p.line(8, 25, 15 + p.cos(p.millis() * 0.008) * 10, 50);

    // Net fragments clinging to figure
    p.stroke(100, 120, 60, 120);
    p.strokeWeight(2);
    for (let i = 0; i < 5; i++) {
      let angle = p.millis() * 0.005 + i;
      let x1 = p.cos(angle) * 20;
      let y1 = p.sin(angle) * 30;
      let x2 = p.cos(angle + 1) * 25;
      let y2 = p.sin(angle + 1) * 35;
      p.line(x1, y1, x2, y2);
    }

    p.pop();
  }

  function updateBubbles() {
    for (let i = bubbles.length - 1; i >= 0; i--) {
      let bubble = bubbles[i];

      bubble.y -= bubble.speed;
      bubble.x += p.sin(p.millis() * 0.01 + i) * 0.5;
      bubble.life -= 2;

      p.fill(200, 220, 180, bubble.life);
      p.noStroke();
      p.circle(bubble.x, bubble.y, bubble.size);

      if (bubble.y < 0 || bubble.life <= 0) {
        bubbles[i] = {
          x: p.random(150, 250),
          y: p.random(400, 500),
          size: p.random(3, 8),
          speed: p.random(0.5, 2),
          life: p.random(200, 255)
        };
      }
    }
  }

  function drawPressureWaves() {
    // Crushing pressure from accumulated history
    for (let i = 0; i < 5; i++) {
      let wave = p.millis() * 0.002 + i * 0.8;
      let y = p.map(i, 0, 4, 50, 200);
      let compression = p.sin(wave) * 30 + 40;

      p.stroke(40, 20, 10, 60);
      p.strokeWeight(8);
      p.noFill();

      p.beginShape();
      for (let x = 0; x <= p.width; x += 20) {
        let waveY = y + p.sin(x * 0.05 + wave) * compression;
        p.vertex(x, waveY);
      }
      p.endShape();
    }

    // Mouse interaction - disturb the crushing weight
    if (p.mouseX > 0 && p.mouseX < p.width && p.mouseY > 0 && p.mouseY < p.height) {
      let disturbance = p.map(p.mouseY, 0, p.height, 10, 2);
      figure.x = p.lerp(figure.x, 200 + (p.mouseX - 200) * 0.1, 0.05);
      figure.y = p.lerp(figure.y, 350 + (p.mouseY - 300) * 0.05, 0.03);

      // Nets react to disturbance
      for (let net of nets) {
        net.offset += 0.01 * disturbance;
      }
    }
  }
}

