function sketch(p) {
  let nets = [];
  let figure;
  let centerX, centerY;
  let outerRadius, innerRadius;
  let timeOffset = 0;

  p.setup = function() {
    p.createCanvas(400, 600);
    centerX = p.width / 2;
    centerY = p.height / 2;
    outerRadius = 180;
    innerRadius = 60;

    // Create 10 nets in a spiral
    for (let i = 0; i < 10; i++) {
      let angle = (i / 10) * p.TWO_PI;
      let spiralRadius = p.map(i, 0, 9, innerRadius, outerRadius);
      let x = centerX + p.cos(angle) * spiralRadius;
      let y = centerY + p.sin(angle) * spiralRadius;
      nets.push({
        x: x,
        y: y,
        angle: angle,
        radius: spiralRadius,
        index: i,
        netPoints: generateNetPoints(x, y, 40 + i * 2),
        opacity: 1
      });
    }

    figure = {
      angle: 0,
      radius: innerRadius,
      trail: []
    };
  };

  p.draw = function() {
    // Muddy palette background
    p.background(45, 40, 35);

    timeOffset += 0.02;

    // Draw connecting spiral line
    p.stroke(80, 70, 60, 150);
    p.strokeWeight(2);
    p.noFill();
    p.beginShape();
    for (let t = 0; t < p.TWO_PI * 2.5; t += 0.1) {
      let spiralR = p.map(t, 0, p.TWO_PI * 2.5, innerRadius, outerRadius);
      let x = centerX + p.cos(t) * spiralR;
      let y = centerY + p.sin(t) * spiralR;
      p.vertex(x, y);
    }
    p.endShape();

    // Draw nets
    for (let i = 0; i < nets.length; i++) {
      let net = nets[i];

      // Pulsing effect based on figure proximity
      let figX = centerX + p.cos(figure.angle) * figure.radius;
      let figY = centerY + p.sin(figure.angle) * figure.radius;
      let dist = p.dist(net.x, net.y, figX, figY);
      let pulse = p.map(dist, 0, 200, 2, 0.5);
      pulse = p.max(0.5, pulse);

      drawNet(net.x, net.y, net.netPoints, pulse, net.index);
    }

    // Update and draw figure
    figure.angle += 0.015;
    figure.radius = innerRadius + (outerRadius - innerRadius) * 
      ((p.sin(figure.angle * 2.5) + 1) / 2);

    let figX = centerX + p.cos(figure.angle) * figure.radius;
    let figY = centerY + p.sin(figure.angle) * figure.radius;

    // Add to trail
    figure.trail.push({x: figX, y: figY, life: 60});
    if (figure.trail.length > 100) {
      figure.trail.shift();
    }

    // Draw trail
    for (let i = 0; i < figure.trail.length; i++) {
      let point = figure.trail[i];
      point.life--;
      let alpha = p.map(point.life, 0, 60, 0, 100);
      p.fill(140, 120, 90, alpha);
      p.noStroke();
      let size = p.map(i, 0, figure.trail.length - 1, 1, 4);
      p.ellipse(point.x, point.y, size);
    }

    // Draw figure
    p.fill(160, 140, 110);
    p.stroke(120, 100, 80);
    p.strokeWeight(1);
    p.ellipse(figX, figY, 8);

    // Draw connecting lines between nets to show cycle
    p.stroke(100, 90, 70, 100);
    p.strokeWeight(1);
    for (let i = 0; i < nets.length; i++) {
      let next = (i + 1) % nets.length;
      let wave = p.sin(timeOffset + i) * 5;
      p.line(nets[i].x + wave, nets[i].y + wave, 
             nets[next].x - wave, nets[next].y - wave);
    }

    // Mouse interaction - distort nearby nets
    for (let net of nets) {
      let mouseDist = p.dist(p.mouseX, p.mouseY, net.x, net.y);
      if (mouseDist < 80) {
        let distortion = p.map(mouseDist, 0, 80, 20, 0);
        net.x += (p.mouseX - net.x) * 0.02;
        net.y += (p.mouseY - net.y) * 0.02;
      } else {
        // Return to original position
        let originalX = centerX + p.cos(net.angle) * net.radius;
        let originalY = centerY + p.sin(net.angle) * net.radius;
        net.x = p.lerp(net.x, originalX, 0.05);
        net.y = p.lerp(net.y, originalY, 0.05);
      }
    }
  };

  function generateNetPoints(centerX, centerY, size) {
    let points = [];
    let gridSize = 6;
    for (let i = 0; i < gridSize; i++) {
      for (let j = 0; j < gridSize; j++) {
        let x = centerX - size/2 + (i / (gridSize-1)) * size;
        let y = centerY - size/2 + (j / (gridSize-1)) * size;
        points.push({x: x, y: y, originalX: x, originalY: y});
      }
    }
    return points;
  }

  function drawNet(x, y, netPoints, scale, index) {
    let time = timeOffset + index * 0.5;

    // Update net point positions with subtle animation
    for (let point of netPoints) {
      let noise = p.noise(point.originalX * 0.01, point.originalY * 0.01, time);
      point.x = point.originalX + (noise - 0.5) * 8 * scale;
      point.y = point.originalY + (noise - 0.5) * 8 * scale;
    }

    // Draw net mesh
    p.stroke(120 - index * 5, 100 - index * 4, 80 - index * 3, 180);
    p.strokeWeight(1 + scale * 0.5);
    p.noFill();

    let gridSize = 6;
    // Horizontal lines
    for (let i = 0; i < gridSize; i++) {
      p.beginShape();
      for (let j = 0; j < gridSize; j++) {
        let point = netPoints[i * gridSize + j];
        p.vertex(point.x, point.y);
      }
      p.endShape();
    }

    // Vertical lines
    for (let j = 0; j < gridSize; j++) {
      p.beginShape();
      for (let i = 0; i < gridSize; i++) {
        let point = netPoints[i * gridSize + j];
        p.vertex(point.x, point.y);
      }
      p.endShape();
    }

    // Net boundary
    p.stroke(140 - index * 3, 120 - index * 3, 90 - index * 2, 120);
    p.strokeWeight(2 * scale);
    p.noFill();
    p.ellipse(x, y, 80 * scale);
  }
}

