function sketch(p) {
  let nets = [];
  let books = [];
  let figure = {};
  let time = 0;
  let netTightness = 0;

  p.setup = function() {
    p.createCanvas(400, 600);

    // Initialize figure
    figure.x = 200;
    figure.y = 300;
    figure.breatheOffset = 0;
    figure.strugglingOffset = 0;

    // Create multiple net systems
    for (let i = 0; i < 80; i++) {
      nets.push({
        x: p.random(50, 350),
        y: p.random(150, 500),
        targetX: 150 + p.random(100),
        targetY: 200 + p.random(200),
        type: p.floor(p.random(3)), // 0: family, 1: religious, 2: national
        tightness: p.random(0.5, 1.5),
        opacity: p.random(80, 180),
        weight: p.random(1, 3)
      });
    }

    // Books scattered nearby
    for (let i = 0; i < 5; i++) {
      books.push({
        x: p.random(100, 300),
        y: p.random(400, 550),
        w: p.random(15, 25),
        h: p.random(8, 12),
        angle: p.random(-0.3, 0.3)
      });
    }
  };

  p.draw = function() {
    // Muddy palette background
    let bgGrad = p.map(p.sin(time * 0.01), -1, 1, 60, 40);
    p.background(bgGrad, bgGrad - 10, bgGrad - 5);

    time++;
    netTightness = p.map(p.sin(time * 0.005), -1, 1, 0.8, 1.3);

    // Mouse interaction affects net tightness
    let mouseInfluence = p.dist(p.mouseX, p.mouseY, figure.x, figure.y);
    let tightnessBoost = p.map(mouseInfluence, 0, 200, 1.5, 1.0);

    figure.breatheOffset = p.sin(time * 0.03) * 3;
    figure.strugglingOffset = p.sin(time * 0.07) * 2;

    // Draw books first (behind figure)
    p.push();
    for (let book of books) {
      p.push();
      p.translate(book.x, book.y);
      p.rotate(book.angle);
      p.fill(80, 60, 50, 200);
      p.stroke(60, 45, 35);
      p.strokeWeight(1);
      p.rect(-book.w/2, -book.h/2, book.w, book.h);
      p.fill(100, 80, 60, 150);
      p.rect(-book.w/2 + 2, -book.h/2 + 1, book.w - 4, 2);
      p.pop();
    }
    p.pop();

    // Draw figure (young Stephen)
    p.push();
    p.translate(figure.x + figure.strugglingOffset, figure.y + figure.breatheOffset);

    // Head
    p.fill(120, 100, 85, 220);
    p.stroke(80, 70, 60);
    p.strokeWeight(2);
    p.ellipse(0, -60, 35, 40);

    // Face details showing pain/shock
    p.fill(60, 50, 45);
    p.noStroke();
    p.ellipse(-6, -65, 3, 3); // eyes
    p.ellipse(6, -65, 3, 3);
    p.arc(0, -55, 8, 6, 0, p.PI); // mouth showing distress

    // Body
    p.fill(100, 85, 75, 200);
    p.stroke(70, 60, 55);
    p.strokeWeight(2);
    p.ellipse(0, -20, 45, 60); // torso
    p.ellipse(-15, 10, 20, 50); // left arm
    p.ellipse(15, 10, 20, 50); // right arm
    p.ellipse(-12, 40, 18, 60); // left leg
    p.ellipse(12, 40, 18, 60); // right leg

    p.pop();

    // Draw nets with different colors for different types
    for (let net of nets) {
      let adjustedTightness = net.tightness * netTightness * tightnessBoost;

      // Calculate positions moving toward figure
      net.x = p.lerp(net.x, net.targetX, 0.002 * adjustedTightness);
      net.y = p.lerp(net.y, net.targetY, 0.002 * adjustedTightness);

      // Different colors for different net types
      if (net.type === 0) { // Family nets - warmer, suffocating
        p.stroke(140, 80, 60, net.opacity);
      } else if (net.type === 1) { // Religious nets - darker, heavier
        p.stroke(60, 40, 80, net.opacity);
      } else { // National nets - green-tinged, constraining
        p.stroke(80, 100, 60, net.opacity);
      }

      p.strokeWeight(net.weight * adjustedTightness);

      // Draw net lines connecting to figure and other nets
      let figX = figure.x + figure.strugglingOffset;
      let figY = figure.y + figure.breatheOffset;

      p.line(net.x, net.y, figX, figY);

      // Connect to nearby nets to create web effect
      for (let other of nets) {
        let dist = p.dist(net.x, net.y, other.x, other.y);
        if (dist < 60 && p.random() < 0.3) {
          p.strokeWeight(1);
          p.line(net.x, net.y, other.x, other.y);
        }
      }

      // Small net nodes
      p.fill(net.type === 0 ? 140 : net.type === 1 ? 80 : 100, 
             net.type === 0 ? 80 : net.type === 1 ? 40 : 100, 
             net.type === 0 ? 60 : net.type === 1 ? 80 : 60, 
             net.opacity);
      p.noStroke();
      p.ellipse(net.x, net.y, 3 * adjustedTightness, 3 * adjustedTightness);
    }

    // Overlay effect showing compression of space
    p.fill(40, 35, 30, 20);
    p.noStroke();
    p.rect(0, 0, 400, 600);

    // Vignette effect
    for (let i = 0; i < 20; i++) {
      p.fill(30, 25, 20, i);
      p.strokeWeight(0);
      p.rect(i, i, 400 - i*2, 600 - i*2);
    }
  };
}

