        endY: mother.y + p.sin(angle) * 180,
        nodes: [],
        angle: angle,
        type: i % 3
      });

      for(let j = 0; j < 12; j++) {
        let t = j / 11;
        let x = p.lerp(mother.x, mother.x + p.cos(angle) * 180, t);
        let y = p.lerp(mother.y, mother.y + p.sin(angle) * 180, t);
        nets[i].nodes.push({x: x, y: y, wave: p.random(0, p.TWO_PI)});
      }
    }

