    p.strokeWeight(2);

    p.ellipse(mother.x, mother.y - 20 + mother.breathe, 60, 80);

    p.fill(60, 50, 40, mother.alpha + 20);
    p.ellipse(mother.x, mother.y + 10 + mother.breathe * 0.5, 80, 40);

    p.fill(40, 30, 25, mother.alpha + 40);
    p.rect(mother.x - 50, mother.y + 20, 100, 60, 10);

