      let baseColor = netType === 0 ? [150, 100, 70] : netType === 1 ? [120, 140, 80] : [140, 90, 120];

      for(let i = 0; i < net.nodes.length - 1; i++) {
        let node1 = net.nodes[i];
        let node2 = net.nodes[i + 1];

        let wave1 = p.sin(time + node1.wave) * 3;
        let wave2 = p.sin(time + node2.wave) * 3;

        let alpha = 80 + 40 * p.sin(time * 0.7 + i * 0.3);
        p.stroke(baseColor[0], baseColor[1], baseColor[2], alpha);
        p.strokeWeight(2 + p.sin(time + i * 0.1));

        p.line(node1.x + wave1, node1.y + wave1 * 0.5, 
               node2.x + wave2, node2.y + wave2 * 0.5);
      }

      for(let i = 1; i < net.nodes.length - 1; i++) {
        let node = net.nodes[i];
        let wave = p.sin(time + node.wave) * 3;

        p.fill(baseColor[0] + 20, baseColor[1] + 20, baseColor[2] + 20, 60);
        p.noStroke();
        p.ellipse(node.x + wave, node.y + wave * 0.5, 4, 4);
      }
    }

    for(let i = 0; i < nets.length; i++) {
      for(let j = i + 1; j < nets.length; j++) {
        if(p.abs(nets[i].angle - nets[j].angle) < p.PI / 2) {
          let midI = p.floor(nets[i].nodes.length / 2);
          let midJ = p.floor(nets[j].nodes.length / 2);

          let nodeI = nets[i].nodes[midI];
          let nodeJ = nets[j].nodes[midJ];

          p.stroke(100, 80, 60, 40);
          p.strokeWeight(1);
          p.line(nodeI.x, nodeI.y, nodeJ.x, nodeJ.y);
        }
      }
    }
