    stephen.trapped = p.sin(time * 0.4) * 5;

    p.push();

    p.fill(60, 80, 100, 180);
    p.stroke(80, 100, 120, 200);
    p.strokeWeight(2);

    p.ellipse(stephen.x, stephen.y - 30 + stephen.trapped, 40, 50);

    p.fill(40, 60, 80, 180);
    p.rect(stephen.x - 15, stephen.y - 5 + stephen.trapped, 30, 40, 5);

    p.stroke(120, 100, 80, 150 + 50 * p.sin(time * 0.6));
    p.strokeWeight(3);
    p.line(stephen.x - 10, stephen.y - 20 + stephen.trapped, mother.x + 20, mother.y - 10);
    p.line(stephen.x + 10, stephen.y - 10 + stephen.trapped, mother.x - 15, mother.y + 5);
    p.line(stephen.x, stephen.y + 10 + stephen.trapped, mother.x, mother.y + 20);

    p.fill(200, 180, 160, 150);
    p.noStroke();
    p.ellipse(stephen.x - 5, stephen.y - 40 + stephen.trapped, 3, 4);
    p.ellipse(stephen.x + 5, stephen.y - 40 + stephen.trapped, 3, 4);

    p.pop();
  }

  function drawVignette() {
    p.push();
    p.drawingContext.save();

    let gradient = p.drawingContext.createRadialGradient(200, 300, 0, 200, 300, 300);
    gradient.addColorStop(0, 'rgba(0,0,0,0)');
    gradient.addColorStop(0.7, 'rgba(15,10,8,0.3)');
    gradient.addColorStop(1, 'rgba(10,5,3,0.8)');

    p.drawingContext.fillStyle = gradient;
    p.drawingContext.fillRect(0, 0, 400, 600);

    p.drawingContext.restore();
    p.pop();
  }
}

