function sketch(p) {
  let netParticles = [];
  let yesParticles = [];
  let figure;
  let time = 0;

  p.setup = function() {
    p.createCanvas(400, 600);

    // Initialize net particles that form tangled mesh
    for(let i = 0; i < 200; i++) {
      netParticles.push({
        x: p.random(p.width),
        y: p.random(p.height),
        vx: p.random(-0.5, 0.5),
        vy: p.random(-0.5, 0.5),
        connections: []
      });
    }

    // Initialize particles that will form the YES
    for(let i = 0; i < 300; i++) {
      yesParticles.push({
        x: p.random(p.width),
        y: p.random(p.height),
        targetX: 0,
        targetY: 0,
        isActive: false,
        letterIndex: -1
      });
    }

    // Figure in the center
    figure = {
      x: p.width/2,
      y: p.height * 0.6,
      oscillation: 0
    };

    assignYesTargets();
  };

  p.draw = function() {
    time += 0.02;

    // Muddy background with slight variation
    let bgNoise = p.noise(time * 0.1) * 20;
    p.background(40 + bgNoise, 35 + bgNoise, 25 + bgNoise);

    // Draw the crushing nets first
    drawNets();

    // Draw the YES trying to emerge
    drawYes();

    // Draw the figure
    drawFigure();

    // Update positions
    updateNetParticles();
    updateYesParticles();
  };

  function drawNets() {
    p.stroke(60, 50, 40, 120);
    p.strokeWeight(1);

    // Create tangled connections between net particles
    for(let i = 0; i < netParticles.length; i++) {
      let particle = netParticles[i];

      // Find nearby particles to connect
      for(let j = i + 1; j < netParticles.length; j++) {
        let other = netParticles[j];
        let dist = p.dist(particle.x, particle.y, other.x, other.y);

        if(dist < 80 && p.random() < 0.3) {
          let alpha = p.map(dist, 0, 80, 100, 20);
          p.stroke(50, 45, 35, alpha);

          // Curved tangled lines
          let midX = (particle.x + other.x) / 2 + p.sin(time + i) * 20;
          let midY = (particle.y + other.y) / 2 + p.cos(time + j) * 15;

          p.noFill();
          p.beginShape();
          p.vertex(particle.x, particle.y);
          p.quadraticVertex(midX, midY, other.x, other.y);
          p.endShape();
        }
      }
    }
  }

  function drawYes() {
    // YES trying to glow through the muddy palette
    let glowIntensity = p.sin(time * 2) * 0.3 + 0.7;

    for(let particle of yesParticles) {
      if(particle.isActive) {
        let distance = p.dist(particle.x, particle.y, particle.targetX, particle.targetY);
        let alpha = p.map(distance, 0, 50, 180, 80) * glowIntensity;

        // Muddy glow trying to be visible
        p.fill(80 + glowIntensity * 40, 70 + glowIntensity * 30, 50 + glowIntensity * 20, alpha);
        p.noStroke();
        p.circle(particle.x, particle.y, 3);

        // Connecting lines forming net-like letters
        if(p.random() < 0.1) {
          p.stroke(70, 60, 45, alpha * 0.5);
          p.strokeWeight(0.5);
          p.line(particle.x, particle.y, particle.targetX, particle.targetY);
        }
      }
    }
  }

  function drawFigure() {
    figure.oscillation += 0.03;
    let sway = p.sin(figure.oscillation) * 5;

    p.push();
    p.translate(figure.x + sway, figure.y);

    // Figure caught in nets but standing
    p.stroke(90, 80, 70, 150);
    p.strokeWeight(2);
    p.noFill();

    // Body with net-like texture
    for(let i = 0; i < 5; i++) {
      let offset = i * 8;
      p.line(-15, -offset, 15, -offset);
      p.line(-10 + i * 5, -40, -10 + i * 5, 10);
    }

    // Head
    p.circle(0, -50, 20);

    // Arms reaching toward the YES
    p.line(0, -30, -20 + sway * 2, -20);
    p.line(0, -30, 20 - sway * 2, -20);

    p.pop();
  }

  function updateNetParticles() {
    for(let particle of netParticles) {
      particle.x += particle.vx;
      particle.y += particle.vy;

      // Wrap around edges
      if(particle.x < 0) particle.x = p.width;
      if(particle.x > p.width) particle.x = 0;
      if(particle.y < 0) particle.y = p.height;
      if(particle.y > p.height) particle.y = 0;

      // Add slight random movement
      particle.vx += p.random(-0.05, 0.05);
      particle.vy += p.random(-0.05, 0.05);

      // Constrain velocity
      particle.vx = p.constrain(particle.vx, -1, 1);
      particle.vy = p.constrain(particle.vy, -1, 1);
    }
  }

  function updateYesParticles() {
    for(let particle of yesParticles) {
      if(particle.isActive) {
        // Move toward target position slowly
        particle.x += (particle.targetX - particle.x) * 0.02;
        particle.y += (particle.targetY - particle.y) * 0.02;

        // Add slight noise to show struggle
        particle.x += p.sin(time * 3 + particle.targetX) * 0.5;
        particle.y += p.cos(time * 2 + particle.targetY) * 0.3;
      }
    }
  }

  function assignYesTargets() {
    let letterSpacing = 80;
    let startX = p.width/2 - letterSpacing;
    let baseY = p.height * 0.3;

    let particleIndex = 0;

    // Y
    for(let i = 0; i < 50; i++) {
      if(particleIndex >= yesParticles.length) break;
      let t = i / 49;

      if(t < 0.5) {
        yesParticles[particleIndex].targetX = startX + t * 30;
        yesParticles[particleIndex].targetY = baseY + t * 60;
      } else {
        yesParticles[particleIndex].targetX = startX + 15 + (t - 0.5) * 30;
        yesParticles[particleIndex].targetY = baseY + (1 - (t - 0.5)) * 60;
      }

      yesParticles[particleIndex].isActive = true;
      yesParticles[particleIndex].letterIndex = 0;
      particleIndex++;
    }

    // E
    for(let i = 0; i < 80; i++) {
      if(particleIndex >= yesParticles.length) break;
      let particle = yesParticles[particleIndex];

      if(i < 20) {
        // Vertical line
        particle.targetX = startX + letterSpacing;
        particle.targetY = baseY + (i / 19) * 60;
      } else if(i < 35) {
        // Top horizontal
        particle.targetX = startX + letterSpacing + ((i - 20) / 14) * 25;
        particle.targetY = baseY;
      } else if(i < 50) {
        // Middle horizontal
        particle.targetX = startX + letterSpacing + ((i - 35) / 14) * 20;
        particle.targetY = baseY + 30;
      } else {
        // Bottom horizontal
        particle.targetX = startX + letterSpacing + ((i - 50) / 29) * 25;
        particle.targetY = baseY + 60;
      }

      particle.isActive = true;
      particle.letterIndex = 1;
      particleIndex++;
    }

    // S
    for(let i = 0; i < 60; i++) {
      if(particleIndex >= yesParticles.length) break;
      let particle = yesParticles[particleIndex];
      let t = i / 59;

      // S curve
      particle.targetX = startX + letterSpacing * 2 + p.sin(t * p.PI * 2) * 15;
      particle.targetY = baseY + t * 60;

      particle.isActive = true;
      particle.letterIndex = 2;
      particleIndex++;
    }
  }

  p.mouseMoved = function() {
    // Mouse movement affects the struggle - nets respond
    let influence = p.dist(p.mouseX, p.mouseY, p.width/2, p.height/2) / 100;

    for(let particle of netParticles) {
      let dist = p.dist(p.mouseX, p.mouseY, particle.x, particle.y);
      if(dist < 100) {
        particle.vx += (p.mouseX - particle.x) * 0.001;
        particle.vy += (p.mouseY - particle.y) * 0.001;
      }
    }
  };
}

