function sketch(p) {
  let time = 0;
  let flowOffset = 0;
  let particles = [];

  p.setup = function() {
    p.createCanvas(400, 600);
    p.colorMode(p.HSB, 360, 100, 100, 100);

    // Initialize flowing particles
    for(let i = 0; i < 20; i++) {
      particles.push({
        x: p.random(180, 220),
        y: p.random(200, 400),
        size: p.random(2, 6),
        speed: p.random(0.5, 2),
        hue: p.random(35, 50)
      });
    }
  };

  p.draw = function() {
    time += 0.01;
    flowOffset += 0.005;

    // Gradient background - dawn to afternoon
    for(let y = 0; y < p.height; y++) {
      let inter = p.map(y, 0, p.height, 0, 1);
      let c = p.lerpColor(
        p.color(50, 30, 95), // warm morning
        p.color(25, 40, 85)  // afternoon amber
      );
      p.stroke(c);
      p.line(0, y, p.width, y);
    }

    // Left side - Morning kitchen comfort
    p.push();
    p.translate(100, 150);

    // Kitchen table surface
    p.fill(45, 20, 80);
    p.noStroke();
    p.ellipse(0, 0, 160, 80);

    // Kidney on plate - warm and sizzling
    p.fill(15, 60, 70);
    p.ellipse(-20, -10, 40, 25);

    // Steam from kidney
    for(let i = 0; i < 5; i++) {
      let steamX = -20 + p.sin(time * 3 + i) * 3;
      let steamY = -25 - i * 8 - p.sin(time * 2) * 2;
      p.fill(0, 0, 100, 30 - i * 5);
      p.ellipse(steamX, steamY, 6 - i, 6 - i);
    }

    // Coffee cup
    p.fill(30, 40, 40);
    p.ellipse(25, 5, 25, 30);
    p.fill(25, 80, 30);
    p.ellipse(25, 0, 20, 15);

    // Butter warmth
    p.fill(55, 80, 90, 60);
    p.ellipse(-10, 10, 15, 8);

    p.pop();

    // Right side - Afternoon pub comfort
    p.push();
    p.translate(300, 350);

    // Bar surface
    p.fill(25, 30, 60);
    p.noStroke();
    p.ellipse(0, 0, 160, 80);

    // Sandwich
    p.fill(35, 40, 75);
    p.rect(-25, -15, 50, 20, 5);
    p.fill(45, 60, 70);
    p.rect(-22, -12, 44, 5);

    // Wine glass with burgundy
    p.fill(0, 60, 30);
    p.ellipse(20, -5, 20, 35);
    p.fill(350, 70, 60);
    p.ellipse(20, -8, 18, 20);

    // Wine warmth glow
    p.fill(350, 50, 80, 40);
    p.ellipse(20, -5, 35, 35);

    p.pop();

    // Flowing connection between comforts
    p.noFill();
    p.strokeWeight(3);

    for(let i = 0; i < 3; i++) {
      let alpha = 40 - i * 10;
      p.stroke(40, 60, 80, alpha);

      p.beginShape();
      p.noFill();

      for(let t = 0; t <= 1; t += 0.02) {
        let x = p.lerp(180, 220, t);
        let y = p.lerp(200, 400, t);

        // Add organic wave motion
        x += p.sin(t * p.PI * 2 + time + i * 0.5) * 20;
        y += p.cos(t * p.PI * 3 + flowOffset + i * 0.3) * 15;

        p.vertex(x, y);
      }
      p.endShape();
    }

    // Animated flow particles
    for(let particle of particles) {
      particle.y += particle.speed;

      if(particle.y > 420) {
        particle.y = 180;
        particle.x = p.random(180, 220);
      }

      // Particle flow along the curve
      let waveX = p.sin(particle.y * 0.02 + time) * 15;

      p.fill(particle.hue, 70, 90, 60);
      p.noStroke();
      p.ellipse(particle.x + waveX, particle.y, particle.size, particle.size);
    }

    // Bloom's presence - subtle figure suggestions
    // Morning Bloom
    p.fill(25, 40, 60, 40);
    p.ellipse(85, 120, 30, 40);

    // Afternoon Bloom
    p.fill(25, 40, 60, 40);
    p.ellipse(315, 320, 30, 40);

    // Interactive mouse influence on flow
    if(p.mouseX > 0 && p.mouseX < p.width && p.mouseY > 0 && p.mouseY < p.height) {
      let influence = p.map(p.mouseX, 0, p.width, -0.01, 0.01);
      flowOffset += influence;
    }

    // Gentle pulsing warmth around comfort zones
    let pulse = p.sin(time * 2) * 0.3 + 0.7;

    // Morning warmth
    p.fill(50, 60, 90, 15 * pulse);
    p.ellipse(100, 150, 200, 120);

    // Afternoon warmth
    p.fill(25, 70, 80, 15 * pulse);
    p.ellipse(300, 350, 200, 120);
  };
}

