function sketch(p) {
  let particles = [];
  let time = 0;

  p.setup = function() {
    p.createCanvas(400, 600);
    p.colorMode(p.HSB, 360, 100, 100, 100);

    // Initialize steam/breath particles
    for (let i = 0; i < 30; i++) {
      particles.push({
        x: p.random(p.width),
        y: p.random(p.height),
        vx: p.random(-0.5, 0.5),
        vy: p.random(-1, -0.5),
        life: p.random(100, 200),
        maxLife: p.random(100, 200),
        type: p.floor(p.random(3))
      });
    }
  };

  p.draw = function() {
    time += 0.02;

    // Background gradient - dawn to dusk
    for (let i = 0; i <= p.height; i++) {
      let inter = p.map(i, 0, p.height, 0, 1);
      let c = p.lerpColor(
        p.color(45, 60, 95), // warm morning yellow
        p.color(320, 40, 60) // evening pink
      );
      p.stroke(c);
      p.line(0, i, p.width, i);
    }

    p.noStroke();

    // Morning scene (top triangle point) - Nourishment
    let morningY = 80 + p.sin(time * 0.5) * 3;

    // Kidney shape
    p.fill(25, 80, 85); // warm brown-orange
    p.push();
    p.translate(200, morningY);
    p.rotate(p.sin(time) * 0.1);
    p.beginShape();
    for (let a = 0; a < p.TWO_PI; a += 0.1) {
      let r = 20 + p.sin(a * 3) * 8;
      let x = r * p.cos(a);
      let y = r * p.sin(a) * 0.8;
      p.vertex(x, y);
    }
    p.endShape(p.CLOSE);
    p.pop();

    // Breakfast glow
    p.fill(45, 70, 90, 30);
    p.ellipse(200, morningY, 120 + p.sin(time * 2) * 10, 80);

    // Butter yellow accents
    p.fill(50, 85, 95);
    p.ellipse(185 + p.cos(time * 1.2) * 5, morningY - 15, 12, 8);
    p.ellipse(215 + p.sin(time * 0.8) * 4, morningY + 10, 8, 6);

    // Afternoon scene (bottom left) - Rest
    let restX = 120;
    let restY = 420;

    // Resting body (horizontal oval)
    p.fill(35, 60, 75, 80);
    p.push();
    p.translate(restX, restY);
    p.rotate(p.sin(time * 0.3) * 0.05);
    p.ellipse(0, 0, 100 + p.sin(time * 0.7) * 8, 40);
    p.pop();

    // Bath/rest glow
    p.fill(40, 50, 85, 25);
    p.ellipse(restX, restY, 140 + p.cos(time * 1.5) * 12, 90);

    // Water ripples
    for (let i = 0; i < 3; i++) {
      p.noFill();
      p.stroke(180, 60, 90, 40 - i * 10);
      p.strokeWeight(2);
      p.ellipse(restX, restY, 80 + i * 20 + p.sin(time * 2 + i) * 10, 60 + i * 15);
    }
    p.noStroke();

    // Evening scene (bottom right) - Pleasure
    let pleasureX = 280;
    let pleasureY = 420;

    // Two intertwining forms
    p.fill(320, 50, 85, 70);
    p.push();
    p.translate(pleasureX, pleasureY);
    p.rotate(p.sin(time * 0.4) * 0.08);
    p.ellipse(-15, 0, 35 + p.sin(time * 1.1) * 4, 60);
    p.ellipse(15, 0, 35 + p.cos(time * 1.3) * 4, 60);
    p.pop();

    // Pleasure glow
    p.fill(330, 60, 90, 30);
    p.ellipse(pleasureX, pleasureY, 120 + p.sin(time * 1.8) * 15, 100);

    // Soft pink accents
    p.fill(340, 70, 95);
    p.ellipse(pleasureX - 20 + p.sin(time * 2.1) * 3, pleasureY - 25, 10, 8);
    p.ellipse(pleasureX + 25 + p.cos(time * 1.7) * 4, pleasureY + 20, 8, 12);

    // Connecting curves - organic steam/breath
    p.noFill();
    p.strokeWeight(3);

    // Morning to afternoon connection
    p.stroke(45, 40, 80, 60);
    p.bezier(200, morningY + 30, 
             150 + p.sin(time) * 10, 200 + p.cos(time * 0.8) * 15,
             140 + p.cos(time * 0.6) * 12, 320 + p.sin(time * 1.2) * 10,
             restX, restY - 30);

    // Afternoon to evening connection
    p.stroke(40, 45, 75, 60);
    p.bezier(restX + 50, restY,
             220 + p.sin(time * 1.4) * 8, 380 + p.cos(time) * 12,
             240 + p.cos(time * 0.9) * 10, 400 + p.sin(time * 1.1) * 8,
             pleasureX - 30, pleasureY);

    // Evening to morning connection (completing the trinity)
    p.stroke(330, 35, 85, 50);
    p.bezier(pleasureX, pleasureY - 40,
             320 + p.cos(time * 0.7) * 12, 300 + p.sin(time * 1.5) * 15,
             280 + p.sin(time * 0.5) * 10, 180 + p.cos(time * 1.3) * 12,
             220, morningY + 20);

    // Floating particles (steam, breath, essence)
    for (let i = particles.length - 1; i >= 0; i--) {
      let part = particles[i];

      // Different colors based on type (morning/afternoon/evening)
      let hue = part.type === 0 ? 45 : (part.type === 1 ? 35 : 330);
      let alpha = p.map(part.life, 0, part.maxLife, 0, 60);

      p.fill(hue, 40, 90, alpha);
      p.noStroke();
      p.ellipse(part.x, part.y, 6 + p.sin(time + part.x * 0.01) * 2, 4);

      // Move particle
      part.x += part.vx + p.sin(time + part.y * 0.01) * 0.2;
      part.y += part.vy;
      part.life -= 1;

      // Reset particle when it dies
      if (part.life <= 0) {
        part.x = p.random(p.width);
        part.y = p.height + 20;
        part.life = part.maxLife;
        part.vx = p.random(-0.5, 0.5);
        part.vy = p.random(-1, -0.5);
      }

      // Wrap around edges
      if (part.x < -10) part.x = p.width + 10;
      if (part.x > p.width + 10) part.x = -10;
    }

    // Interactive glow on mouse proximity
    let mouseInfluence = p.map(p.dist(p.mouseX, p.mouseY, 200, 300), 0, 200, 100, 20);
    p.fill(60, 30, 95, mouseInfluence * 0.3);
    p.ellipse(200, 300, mouseInfluence * 2, mouseInfluence * 1.5);
  };
}

