function sketch(p) {
  let buildings = [];
  let bloomPath = [];
  let bloomPos = 0;
  let kidneyShapes = [];
  let liffeyWaves = [];
  let timeOffset = 0;

  p.setup = function() {
    p.createCanvas(400, 600);

    // Create organic Dublin street layout
    for(let i = 0; i < 12; i++) {
      buildings.push({
        x: p.random(50, 350),
        y: p.random(150, 550),
        w: p.random(40, 80),
        h: p.random(30, 60),
        type: p.random(['pub', 'butcher', 'bath', 'home']),
        pulse: p.random(p.TWO_PI)
      });
    }

    // Bloom's circular walking path
    for(let i = 0; i < 100; i++) {
      let angle = p.map(i, 0, 100, 0, p.TWO_PI * 1.2);
      bloomPath.push({
        x: 200 + p.cos(angle) * 120 + p.random(-20, 20),
        y: 300 + p.sin(angle) * 100 + p.random(-15, 15)
      });
    }

    // Kidney-bean shapes scattered throughout
    for(let i = 0; i < 8; i++) {
      kidneyShapes.push({
        x: p.random(60, 340),
        y: p.random(100, 500),
        size: p.random(20, 40),
        rotation: p.random(p.TWO_PI),
        bob: p.random(p.TWO_PI)
      });
    }

    // Liffey river waves
    for(let i = 0; i < p.width + 20; i += 8) {
      liffeyWaves.push({
        x: i,
        baseY: 120,
        amplitude: p.random(3, 8),
        frequency: p.random(0.02, 0.05)
      });
    }
  };

  p.draw = function() {
    // Warm butter yellow to brown gradient background
    for(let i = 0; i <= p.height; i++) {
      let inter = p.map(i, 0, p.height, 0, 1);
      let c = p.lerpColor(p.color(255, 243, 184), p.color(139, 90, 43), inter);
      p.stroke(c);
      p.line(0, i, p.width, i);
    }

    timeOffset += 0.01;

    // Draw Liffey as flowing artery
    p.stroke(72, 133, 156, 150);
    p.strokeWeight(8);
    p.noFill();
    p.beginShape();
    for(let wave of liffeyWaves) {
      let y = wave.baseY + p.sin(timeOffset + wave.x * wave.frequency) * wave.amplitude;
      p.vertex(wave.x, y);
    }
    p.endShape();

    // Flowing particles in river
    p.fill(72, 133, 156, 80);
    p.noStroke();
    for(let i = 0; i < 5; i++) {
      let x = (timeOffset * 100 + i * 80) % (p.width + 40) - 20;
      let y = 120 + p.sin(timeOffset + x * 0.03) * 6;
      p.ellipse(x, y, 4, 4);
    }

    // Draw kidney-bean architectural elements
    p.stroke(101, 67, 33, 120);
    p.strokeWeight(2);
    p.fill(205, 133, 63, 60);
    for(let kidney of kidneyShapes) {
      p.push();
      p.translate(kidney.x, kidney.y + p.sin(timeOffset + kidney.bob) * 3);
      p.rotate(kidney.rotation);
      p.beginShape();
      for(let a = 0; a < p.TWO_PI; a += 0.1) {
        let r = kidney.size * (0.8 + 0.3 * p.sin(a * 2));
        let x = r * p.cos(a);
        let y = r * p.sin(a) * 0.7;
        if(a > p.PI * 0.3 && a < p.PI * 0.7) {
          x *= 0.6;
        }
        p.vertex(x, y);
      }
      p.endShape(p.CLOSE);
      p.pop();
    }

    // Draw buildings as organs of care
    p.strokeWeight(1);
    for(let building of buildings) {
      let glow = p.sin(timeOffset + building.pulse) * 0.3 + 0.7;

      // Different colors for different types of care
      switch(building.type) {
        case 'pub':
          p.fill(139, 69, 19, 200 * glow);
          p.stroke(160, 82, 45);
          break;
        case 'butcher':
          p.fill(178, 34, 34, 200 * glow);
          p.stroke(220, 20, 60);
          break;
        case 'bath':
          p.fill(72, 133, 156, 200 * glow);
          p.stroke(100, 149, 237);
          break;
        case 'home':
          p.fill(218, 165, 32, 200 * glow);
          p.stroke(255, 215, 0);
          break;
      }

      // Organic building shapes
      let wobble = p.sin(timeOffset * 2 + building.x * 0.01) * 2;
      p.rect(building.x, building.y, building.w + wobble, building.h);

      // Small windows that breathe
      p.fill(255, 253, 127, 150 + 100 * glow);
      p.noStroke();
      for(let i = 0; i < 3; i++) {
        p.rect(building.x + 10 + i * 15, building.y + 10, 8, 8);
      }
    }

    // Draw Bloom's path as caring circuit
    p.stroke(101, 67, 33, 100);
    p.strokeWeight(2);
    p.noFill();
    p.beginShape();
    for(let point of bloomPath) {
      p.vertex(point.x, point.y);
    }
    p.endShape();

    // Bloom as moving dot on the path
    bloomPos = (bloomPos + 0.005) % 1;
    let currentIndex = p.floor(bloomPos * (bloomPath.length - 1));
    let nextIndex = (currentIndex + 1) % bloomPath.length;
    let t = (bloomPos * (bloomPath.length - 1)) - currentIndex;

    let bloomX = p.lerp(bloomPath[currentIndex].x, bloomPath[nextIndex].x, t);
    let bloomY = p.lerp(bloomPath[currentIndex].y, bloomPath[nextIndex].y, t);

    // Bloom's gentle glow
    p.fill(255, 253, 127, 150);
    p.noStroke();
    p.ellipse(bloomX, bloomY, 12 + p.sin(timeOffset * 3) * 2, 12 + p.sin(timeOffset * 3) * 2);
    p.fill(218, 165, 32);
    p.ellipse(bloomX, bloomY, 6, 6);

    // Floating comfort particles near mouse
    if(p.mouseX > 0 && p.mouseX < p.width && p.mouseY > 0 && p.mouseY < p.height) {
      p.fill(255, 253, 127, 80);
      p.noStroke();
      for(let i = 0; i < 6; i++) {
        let angle = timeOffset + i * p.PI / 3;
        let x = p.mouseX + p.cos(angle) * 20;
        let y = p.mouseY + p.sin(angle) * 15;
        p.ellipse(x, y, 4 + p.sin(timeOffset * 2 + i) * 2, 4);
      }
    }

    // Subtle street grid emerging from organic flow
    p.stroke(139, 90, 43, 30);
    p.strokeWeight(1);
    for(let i = 0; i < 5; i++) {
      let x = p.map(i, 0, 4, 80, 320);
      let curve = p.sin(timeOffset + i * 0.5) * 10;
      p.line(x + curve, 150, x - curve, 550);
    }
    for(let i = 0; i < 6; i++) {
      let y = p.map(i, 0, 5, 180, 520);
      let curve = p.cos(timeOffset + i * 0.7) * 8;
      p.line(60, y + curve, 340, y - curve);
    }
  };
}

