function sketch(p) {
  let breakfast = [];
  let steam = [];
  let starPoints = [];
  let bodyGlow = 0;
  let nourishmentPulse = 0;
  let backgroundFigures = [];
  let warmPalette;

  p.setup = function() {
    p.createCanvas(400, 600);

    // Warm, nourishing palette
    warmPalette = {
      kidney: p.color(139, 69, 19),
      flesh: p.color(255, 218, 185),
      steam: p.color(255, 255, 255, 100),
      gold: p.color(218, 165, 32),
      cream: p.color(255, 248, 220),
      shadow: p.color(101, 67, 33),
      star: p.color(0, 102, 204, 150)
    };

    // Initialize breakfast elements
    for (let i = 0; i < 8; i++) {
      breakfast.push({
        x: 180 + p.random(-20, 20),
        y: 300 + p.random(-15, 15),
        size: p.random(8, 15),
        angle: p.random(p.TWO_PI)
      });
    }

    // Steam particles
    for (let i = 0; i < 15; i++) {
      steam.push({
        x: 180 + p.random(-30, 30),
        y: 280,
        vy: -p.random(1, 3),
        life: p.random(100, 200),
        maxLife: p.random(100, 200)
      });
    }

    // Star of David points (subtle geometry)
    for (let i = 0; i < 6; i++) {
      starPoints.push({
        angle: i * p.PI / 3,
        radius: 40,
        x: 200,
        y: 150
      });
    }

    // Background figures (subtle othering)
    for (let i = 0; i < 3; i++) {
      backgroundFigures.push({
        x: p.random(50, 350),
        y: p.random(450, 550),
        size: p.random(30, 50),
        sway: p.random(-0.02, 0.02)
      });
    }
  };

  p.draw = function() {
    // Warm background gradient
    for (let i = 0; i <= p.height; i++) {
      let alpha = p.map(i, 0, p.height, 0, 1);
      let c = p.lerpColor(warmPalette.cream, warmPalette.gold, alpha * 0.3);
      p.stroke(c);
      p.line(0, i, p.width, i);
    }

    bodyGlow = p.sin(p.millis() * 0.003) * 30 + 50;
    nourishmentPulse = p.sin(p.millis() * 0.005) * 10 + 20;

    // Background figures (those who mark as other)
    p.fill(warmPalette.shadow);
    p.noStroke();
    for (let fig of backgroundFigures) {
      p.push();
      p.translate(fig.x, fig.y + p.sin(p.millis() * 0.002 + fig.x) * 5);
      p.ellipse(0, 0, fig.size, fig.size * 1.2);
      // Subtle gestures of exclusion
      p.strokeWeight(2);
      p.stroke(warmPalette.shadow);
      p.line(-fig.size/3, -fig.size/4, fig.size/3, fig.size/4);
      p.pop();
    }

    // Bloom's body - central figure
    p.push();
    p.translate(200, 200);

    // Body glow (warmth despite otherness)
    p.fill(warmPalette.flesh.levels[0], warmPalette.flesh.levels[1], warmPalette.flesh.levels[2], bodyGlow);
    p.noStroke();
    p.ellipse(0, 80, 120 + p.sin(p.millis() * 0.004) * 5, 160);

    // Head
    p.fill(warmPalette.flesh);
    p.ellipse(0, -20, 80, 90);

