function sketch(p) {
  let figures = [];
  let steamParticles = [];
  let warmthWaves = [];
  let time = 0;

  p.setup = function() {
    p.createCanvas(400, 600);

    // Create two figures sharing space
    figures.push({
      x: 150,
      y: 250,
      breathe: 0,
      eyeGlow: 0
    });

    figures.push({
      x: 250,
      y: 280,
      breathe: p.PI/3,
      eyeGlow: p.PI/4
    });

    // Initialize steam particles
    for(let i = 0; i < 20; i++) {
      steamParticles.push({
        x: 200 + p.random(-30, 30),
        y: 350,
        vy: -1 - p.random(0.5),
        life: p.random(100, 200),
        maxLife: p.random(100, 200)
      });
    }

    // Initialize warmth waves
    for(let i = 0; i < 8; i++) {
      warmthWaves.push({
        radius: i * 15,
        alpha: 255 - i * 30,
        speed: 0.02 + i * 0.005
      });
    }
  };

  p.draw = function() {
    // Warm background gradient
    for(let y = 0; y < p.height; y++) {
      let inter = p.map(y, 0, p.height, 0, 1);
      let c1 = p.color(20, 15, 25);
      let c2 = p.color(60, 35, 25);
      let gradColor = p.lerpColor(c1, c2, inter);
      p.stroke(gradColor);
      p.line(0, y, p.width, y);
    }

    time += 0.01;

    // Draw warmth waves emanating from shared space
    p.push();
    p.translate(200, 320);
    for(let wave of warmthWaves) {
      p.noFill();
      p.stroke(180, 100, 60, wave.alpha * (0.3 + 0.2 * p.sin(time + wave.speed * 100)));
      p.strokeWeight(2);
      let radius = wave.radius + 20 * p.sin(time * wave.speed);
      p.ellipse(0, 0, radius * 2);
    }
    p.pop();

    // Draw shared food/table
    p.fill(80, 45, 25);
    p.noStroke();
    p.ellipse(200, 350, 120, 60);

    // Shared bowl with warm glow
    p.fill(120, 80, 40);
    p.ellipse(200, 340, 60, 30);

    // Food glow
    p.fill(200, 150, 80, 50);
    p.ellipse(200, 340, 80, 40);

    // Update and draw steam particles
    for(let i = steamParticles.length - 1; i >= 0; i--) {
      let steam = steamParticles[i];
      steam.y += steam.vy;
      steam.life--;
      steam.x += p.sin(steam.y * 0.01 + time) * 0.5;

      if(steam.life <= 0) {
        steamParticles[i] = {
          x: 200 + p.random(-30, 30),
          y: 350,
          vy: -1 - p.random(0.5),
          life: p.random(100, 200),
          maxLife: p.random(100, 200)
        };
      }

      let alpha = p.map(steam.life, 0, steam.maxLife, 0, 100);
      p.fill(255, 255, 255, alpha);
      p.noStroke();
      p.ellipse(steam.x, steam.y, 3);
    }

    // Draw connecting curves between figures
    p.noFill();
    p.stroke(150, 100, 70, 80);
    p.strokeWeight(3);
    let curve1Y = 240 + 10 * p.sin(time * 2);
    let curve2Y = 270 + 8 * p.sin(time * 1.5 + 1);
    p.bezier(figures[0].x, figures[0].y, 180, curve1Y, 220, curve2Y, figures[1].x, figures[1].y);

    // Draw figures
    for(let fig of figures) {
      p.push();
      p.translate(fig.x, fig.y + 3 * p.sin(time * 1.5 + fig.breathe));

      // Body warmth aura
      p.fill(180, 120, 80, 30);
      p.noStroke();
      p.ellipse(0, 20, 80 + 5 * p.sin(time + fig.breathe), 100);

      // Body
      p.fill(140, 90, 70);
      p.ellipse(0, 20, 50, 70);

      // Head
      p.fill(160, 110, 85);
      p.ellipse(0, -20, 40, 45);

      // Eyes with recognition glow
      p.fill(50, 30, 20);
      p.ellipse(-8, -25, 4, 6);
      p.ellipse(8, -25, 4, 6);

      // Eye glow
      let glowIntensity = 0.5 + 0.3 * p.sin(time * 2 + fig.eyeGlow);
      p.fill(200, 150, 100, 100 * glowIntensity);
      p.ellipse(-8, -25, 8, 8);
      p.ellipse(8, -25, 8, 8);

      // Hands reaching toward shared space
      p.fill(160, 110, 85);
      let handReach = 5 * p.sin(time * 1.2 + fig.breathe);
      p.ellipse(15, 40 + handReach, 12, 15);
      p.ellipse(-15, 35 + handReach, 12, 15);

      p.pop();
    }

    // Interactive element - mouse proximity increases warmth
    let mouseDistance = p.dist(p.mouseX, p.mouseY, 200, 320);
    let proximityEffect = p.map(p.constrain(mouseDistance, 0, 150), 0, 150, 1.5, 0.5);

    // Enhanced glow based on mouse proximity
    p.fill(255, 180, 100, 30 * proximityEffect);
    p.noStroke();
    p.ellipse(200, 320, 200 * proximityEffect, 150 * proximityEffect);

    // Floating recognition symbols
    for(let i = 0; i < 3; i++) {
      let angle = time + i * p.TWO_PI / 3;
      let x = 200 + 60 * p.cos(angle);
      let y = 200 + 30 * p.sin(angle);
      let alpha = 100 + 50 * p.sin(time * 2 + i);

      p.fill(200, 150, 100, alpha);
      p.ellipse(x, y, 4, 4);
    }
  };
}

