function sketch(p) {
  let kidneyShapes = [];
  let bloomBody;
  let time = 0;

  p.setup = function() {
    p.createCanvas(400, 600);

    // Initialize Bloom's body position
    bloomBody = {
      x: p.width / 2,
      y: p.height / 2,
      radius: 80
    };

    // Create seven kidney-bean shapes with different sizes and purposes
    let angles = [0, 0.9, 1.8, 2.7, 3.6, 4.5, 5.4];
    let distances = [120, 100, 140, 90, 160, 110, 130];
    let sizes = [40, 25, 45, 20, 30, 35, 15]; // Three large, four smaller
    let types = ['meal', 'snack', 'meal', 'rest', 'snack', 'meal', 'rest'];

    for (let i = 0; i < 7; i++) {
      kidneyShapes.push({
        baseAngle: angles[i],
        distance: distances[i],
        size: sizes[i],
        type: types[i],
        phase: p.random(p.TWO_PI),
        pulseSpeed: p.random(0.02, 0.05),
        satisfaction: p.random(0.7, 1.0)
      });
    }
  };

  p.draw = function() {
    // Warm background gradient
    for (let i = 0; i <= p.height; i++) {
      let inter = p.map(i, 0, p.height, 0, 1);
      let c = p.lerpColor(p.color(255, 220, 180), p.color(240, 180, 140), inter);
      p.stroke(c);
      p.line(0, i, p.width, i);
    }

    time += 0.02;

    // Draw connection lines showing the organic flow
    p.stroke(200, 150, 100, 100);
    p.strokeWeight(1);
    p.noFill();
    p.beginShape();
    for (let kidney of kidneyShapes) {
      let angle = kidney.baseAngle + p.sin(time + kidney.phase) * 0.3;
      let distance = kidney.distance + p.sin(time * 0.5 + kidney.phase) * 15;
      let x = bloomBody.x + p.cos(angle) * distance;
      let y = bloomBody.y + p.sin(angle) * distance * 0.8;
      p.curveVertex(x, y);
    }
    p.endShape();

    // Draw kidney-bean shapes
    for (let kidney of kidneyShapes) {
      let angle = kidney.baseAngle + p.sin(time + kidney.phase) * 0.3;
      let distance = kidney.distance + p.sin(time * 0.5 + kidney.phase) * 15;
      let x = bloomBody.x + p.cos(angle) * distance;
      let y = bloomBody.y + p.sin(angle) * distance * 0.8;

      let pulse = p.sin(time * kidney.pulseSpeed + kidney.phase) * 0.2 + 1;
      let currentSize = kidney.size * pulse * kidney.satisfaction;

      p.push();
      p.translate(x, y);
      p.rotate(angle + p.PI / 4);

      // Color based on type and satisfaction
      if (kidney.type === 'meal') {
        p.fill(220, 120, 80, 200); // Warm orange for substantial meals
      } else if (kidney.type === 'snack') {
        p.fill(255, 180, 100, 180); // Lighter yellow for snacks
      } else {
        p.fill(180, 140, 200, 150); // Soft purple for rest
      }

      p.noStroke();

      // Draw kidney bean shape
      p.beginShape();
      for (let a = 0; a < p.TWO_PI; a += 0.1) {
        let r1 = currentSize * (0.8 + 0.3 * p.sin(2 * a));
        let r2 = currentSize * (0.6 + 0.2 * p.cos(3 * a));
        let r = (r1 + r2) / 2;
        let indent = a > p.PI * 0.3 && a < p.PI * 0.7 ? 0.7 : 1;
        r *= indent;
        p.vertex(p.cos(a) * r, p.sin(a) * r);
      }
      p.endShape(p.CLOSE);

      // Add subtle glow for satisfaction
      p.fill(255, 255, 255, 50 * kidney.satisfaction);
      p.ellipse(0, 0, currentSize * 0.5, currentSize * 0.3);

      p.pop();
    }

    // Draw Bloom's body with contentment
    let bodyPulse = p.sin(time * 0.3) * 5 + 95;
    p.fill(255, 200, 150, 180);
    p.noStroke();
    p.ellipse(bloomBody.x, bloomBody.y, bodyPulse, bodyPulse * 1.2);

    // Bloom's serene face
    p.fill(240, 180, 140);
    p.ellipse(bloomBody.x, bloomBody.y - 15, 50, 60);

    // Eyes showing contentment
    p.fill(100, 80, 60);
    let eyeOffset = p.sin(time * 0.1) * 2;
    p.ellipse(bloomBody.x - 8, bloomBody.y - 20 + eyeOffset, 3, 6);
    p.ellipse(bloomBody.x + 8, bloomBody.y - 20 + eyeOffset, 3, 6);

    // Gentle smile
    p.noFill();
    p.stroke(120, 100, 80);
    p.strokeWeight(2);
    p.arc(bloomBody.x, bloomBody.y - 5, 20, 15, 0, p.PI);

    // Subtle mouse interaction - kidney shapes respond to proximity
    for (let kidney of kidneyShapes) {
      let angle = kidney.baseAngle + p.sin(time + kidney.phase) * 0.3;
      let distance = kidney.distance + p.sin(time * 0.5 + kidney.phase) * 15;
      let x = bloomBody.x + p.cos(angle) * distance;
      let y = bloomBody.y + p.sin(angle) * distance * 0.8;

      let mouseDistance = p.dist(p.mouseX, p.mouseY, x, y);
      if (mouseDistance < 50) {
        kidney.satisfaction = p.min(1.0, kidney.satisfaction + 0.01);
      }
    }

    // Floating particles showing the harmony of asymmetric care
    p.fill(255, 200, 100, 100);
    p.noStroke();
    for (let i = 0; i < 12; i++) {
      let particleX = bloomBody.x + p.cos(time * 0.2 + i) * (60 + i * 8);
      let particleY = bloomBody.y + p.sin(time * 0.15 + i) * (40 + i * 5);
      let size = 3 + p.sin(time + i) * 2;
      p.ellipse(particleX, particleY, size, size);
    }
  };
}

