function sketch(p) {
  let kidneyShapes = [];
  let centerX, centerY;
  let spiralRadius = 120;
  let bloomFace;
  let time = 0;

  p.setup = function() {
    p.createCanvas(400, 600);
    centerX = p.width / 2;
    centerY = p.height / 2;

    // Create 10 kidney shapes in spiral formation
    for (let i = 0; i < 10; i++) {
      let angle = (i / 10) * p.TWO_PI * 2; // Double spiral
      let radius = spiralRadius - (i * 8);
      let x = centerX + p.cos(angle) * radius;
      let y = centerY + p.sin(angle) * radius;

      kidneyShapes.push({
        x: x,
        y: y,
        originalX: x,
        originalY: y,
        angle: angle,
        size: 25 + i * 2,
        phase: i * 0.6,
        activity: ['breakfast', 'work', 'lunch', 'rest', 'tea', 'dinner', 'evening', 'bath', 'sleep', 'dream'][i]
      });
    }
  };

  p.draw = function() {
    time += 0.02;

    // Warm gradient background
    for (let y = 0; y < p.height; y++) {
      let inter = p.map(y, 0, p.height, 0, 1);
      let c1 = p.color(45, 25, 15); // Deep brown
      let c2 = p.color(85, 45, 25); // Warm brown
      let c = p.lerpColor(c1, c2, inter);
      p.stroke(c);
      p.line(0, y, p.width, y);
    }

    // Draw flowing connections between kidney shapes
    p.stroke(180, 120, 80, 60);
    p.strokeWeight(3);
    p.noFill();
    p.beginShape();
    for (let i = 0; i < kidneyShapes.length; i++) {
      let kidney = kidneyShapes[i];
      let nextKidney = kidneyShapes[(i + 1) % kidneyShapes.length];

      // Animate the spiral flow
      let flowX = kidney.x + p.sin(time + kidney.phase) * 15;
      let flowY = kidney.y + p.cos(time + kidney.phase) * 10;

      if (i === 0) {
        p.curveVertex(flowX, flowY);
      }
      p.curveVertex(flowX, flowY);
      if (i === kidneyShapes.length - 1) {
        p.curveVertex(flowX, flowY);
      }
    }
    p.endShape();

    // Draw kidney shapes with gentle pulsing
    for (let i = 0; i < kidneyShapes.length; i++) {
      let kidney = kidneyShapes[i];

      // Gentle pulsing animation
      let pulse = 1 + p.sin(time * 2 + kidney.phase) * 0.15;
      let currentSize = kidney.size * pulse;

      // Color cycle through warm tones
      let colorPhase = (time + kidney.phase) * 0.5;
      let r = 150 + p.sin(colorPhase) * 50;
      let g = 80 + p.sin(colorPhase + 1) * 40;
      let b = 40 + p.sin(colorPhase + 2) * 30;

      p.fill(r, g, b, 200);
      p.stroke(200, 150, 100, 150);
      p.strokeWeight(2);

      // Draw kidney bean shape
      p.push();
      p.translate(kidney.x, kidney.y);
      p.rotate(kidney.angle + time * 0.1);

      p.beginShape();
      for (let a = 0; a < p.TWO_PI; a += 0.1) {
        let xoff = p.cos(a);
        let yoff = p.sin(a);

        // Create kidney bean indentation
        let radius = currentSize;
        if (a > p.PI * 0.3 && a < p.PI * 0.7) {
          radius *= 0.6; // Indentation
        }

        let x = xoff * radius;
        let y = yoff * radius * 1.3; // Elongated
        p.vertex(x, y);
      }
      p.endShape(p.CLOSE);
      p.pop();

      // Draw small activity symbols
      p.fill(255, 220, 180, 150);
      p.noStroke();
      p.textAlign(p.CENTER);
      p.textSize(8);

      let symbolX = kidney.x + p.sin(time + kidney.phase) * 8;
      let symbolY = kidney.y + p.cos(time + kidney.phase) * 6;

      // Simple symbols for activities
      let symbols = ['☀', '⚡', '🍽', '💤', '☕', '🍽', '🌙', '🛁', '💤', '✨'];
      p.text(symbols[i], symbolX, symbolY + 3);
    }

    // Draw Bloom's understanding face in center
    p.fill(220, 180, 140, 180);
    p.stroke(150, 120, 90);
    p.strokeWeight(2);
    p.ellipse(centerX, centerY, 60, 70);

    // Gentle breathing animation
    let breathe = 1 + p.sin(time * 3) * 0.05;

    // Eyes - understanding, accepting
    p.fill(80, 60, 40);
    p.noStroke();
    p.ellipse(centerX - 12, centerY - 10, 8 * breathe, 6 * breathe);
    p.ellipse(centerX + 12, centerY - 10, 8 * breathe, 6 * breathe);

    // Gentle smile - acceptance of the cycle
    p.stroke(120, 90, 60);
    p.strokeWeight(2);
    p.noFill();
    p.arc(centerX, centerY + 5, 20, 15, 0, p.PI);

    // Flowing energy lines emanating from center
    p.stroke(255, 200, 150, 80);
    p.strokeWeight(1);
    for (let i = 0; i < 8; i++) {
      let angle = (i / 8) * p.TWO_PI;
      let startR = 40;
      let endR = 80 + p.sin(time * 2 + i) * 20;

      let x1 = centerX + p.cos(angle + time * 0.3) * startR;
      let y1 = centerY + p.sin(angle + time * 0.3) * startR;
      let x2 = centerX + p.cos(angle + time * 0.3) * endR;
      let y2 = centerY + p.sin(angle + time * 0.3) * endR;

      p.line(x1, y1, x2, y2);
    }

    // Mouse interaction - gentle attraction to cursor
    if (p.mouseX > 0 && p.mouseX < p.width && p.mouseY > 0 && p.mouseY < p.height) {
      for (let kidney of kidneyShapes) {
        let attraction = p.createVector(p.mouseX - kidney.x, p.mouseY - kidney.y);
        attraction.mult(0.002);
        kidney.x += attraction.x;
        kidney.y += attraction.y;

        // Gentle return to original position
        kidney.x = p.lerp(kidney.x, kidney.originalX, 0.05);
        kidney.y = p.lerp(kidney.y, kidney.originalY, 0.05);
      }
    }
  };
}

