function sketch(p) {
  let bloom;
  let kidney;
  let steamParticles = [];
  let warmLight;
  let kitchenItems = [];
  let time = 0;

  p.setup = function() {
    p.createCanvas(400, 600);

    // Initialize Bloom's position
    bloom = {
      x: 200,
      y: 350,
      bodyWidth: 80,
      bodyHeight: 120,
      armAngle: 0
    };

    // Initialize kidney
    kidney = {
      x: 180,
      y: 280,
      size: 25,
      sizzle: 0
    };

    // Kitchen items
    kitchenItems = [
      {x: 120, y: 250, type: 'pan'},
      {x: 280, y: 200, type: 'cup'},
      {x: 150, y: 180, type: 'plate'},
      {x: 320, y: 320, type: 'towel'}
    ];

    // Warm light source
    warmLight = {
      x: 300,
      y: 150,
      intensity: 0.8
    };
  };

  p.draw = function() {
    time += 0.02;

    // Warm kitchen background
    drawBackground();

    // Kitchen atmosphere
    drawKitchenItems();

    // Steam from cooking
    updateSteam();
    drawSteam();

    // Bloom's figure
    drawBloom();

    // The kidney being prepared
    drawKidney();

    // Warm lighting effects
    drawWarmLight();

    // Subtle hand gesture offering care
    drawCaringGesture();
  };

  function drawBackground() {
    // Warm gradient background
    for(let y = 0; y < p.height; y++) {
      let inter = p.map(y, 0, p.height, 0, 1);
      let c = p.lerpColor(p.color(245, 230, 210), p.color(220, 180, 140), inter);
      p.stroke(c);
      p.line(0, y, p.width, y);
    }

    // Kitchen counter
    p.fill(180, 160, 120);
    p.noStroke();
    p.rect(0, 250, p.width, 80);

    // Counter edge highlight
    p.fill(200, 180, 140);
    p.rect(0, 250, p.width, 8);
  };

  function drawKitchenItems() {
    p.fill(120, 100, 80);
    p.noStroke();

    for(let item of kitchenItems) {
      p.push();
      p.translate(item.x, item.y);

      if(item.type === 'pan') {
        p.fill(80, 70, 60);
        p.ellipse(0, 0, 60, 15);
        p.fill(100, 90, 80);
        p.rect(-5, -20, 10, 25);
      } else if(item.type === 'cup') {
        p.fill(200, 180, 160);
        p.rect(-8, -15, 16, 20, 2);
        p.rect(8, -5, 8, 3);
      } else if(item.type === 'plate') {
        p.fill(240, 220, 200);
        p.ellipse(0, 0, 40, 8);
      } else if(item.type === 'towel') {
        p.fill(180, 140, 120);
        p.rect(-15, -8, 30, 16, 3);
      }
      p.pop();
    }
  };

  function drawBloom() {
    p.push();
    p.translate(bloom.x, bloom.y);

    // Body - well-cared for, not perfect but maintained
    p.fill(220, 190, 160);
    p.stroke(180, 150, 120);
    p.strokeWeight(2);

    // Torso
    p.ellipse(0, 0, bloom.bodyWidth, bloom.bodyHeight);

    // Head
    p.ellipse(0, -bloom.bodyHeight/2 - 25, 50, 60);

    // Hair - thinning but dignified
    p.fill(120, 100, 80);
    p.noStroke();
    p.ellipse(-15, -bloom.bodyHeight/2 - 35, 20, 15);
    p.ellipse(0, -bloom.bodyHeight/2 - 40, 25, 12);
    p.ellipse(15, -bloom.bodyHeight/2 - 35, 18, 15);

    // Eyes - wise, caring
    p.fill(80, 60, 40);
    p.ellipse(-8, -bloom.bodyHeight/2 - 25, 6, 8);
    p.ellipse(8, -bloom.bodyHeight/2 - 25, 6, 8);

    // Gentle smile
    p.noFill();
    p.stroke(120, 90, 70);
    p.strokeWeight(1.5);
    p.arc(0, -bloom.bodyHeight/2 - 15, 20, 12, 0, p.PI);

    // Arms - gentle, experienced movements
    bloom.armAngle = p.sin(time * 1.5) * 0.3;

    p.stroke(180, 150, 120);
    p.strokeWeight(8);
    // Left arm reaching toward pan
    p.line(-bloom.bodyWidth/2, -10, -80 + p.cos(bloom.armAngle) * 10, -40 + p.sin(bloom.armAngle) * 5);
    // Right arm at waist
    p.line(bloom.bodyWidth/2, 10, 60, 20);

    // Clothing - simple, comfortable
    p.fill(100, 120, 140, 150);
    p.noStroke();
    p.rect(-bloom.bodyWidth/2 + 10, -30, bloom.bodyWidth - 20, 80, 5);

    p.pop();
  };

  function drawKidney() {
    p.push();
    p.translate(kidney.x, kidney.y);

    kidney.sizzle = p.sin(time * 8) * 2;

    // Pan
    p.fill(60, 50, 40);
    p.stroke(40, 30, 20);
    p.strokeWeight(2);
    p.ellipse(0, 0, 80, 20);

    // Kidney - organic, nourishing
    p.fill(140 + kidney.sizzle, 80 + kidney.sizzle/2, 60);
    p.noStroke();
    p.push();
    p.rotate(p.sin(time) * 0.1);
    p.beginShape();
    p.vertex(-15, -8);
    p.bezierVertex(-20, -12, -18, -4, -8, -2);
    p.bezierVertex(0, -6, 8, -4, 15, -8);
    p.bezierVertex(18, -2, 12, 6, 8, 8);
    p.bezierVertex(0, 12, -8, 10, -15, 8);
    p.bezierVertex(-22, 4, -20, -4, -15, -8);
    p.endShape();
    p.pop();

    // Gentle cooking sounds visualization
    if(p.frameCount % 30 < 15) {
      p.fill(255, 200, 100, 100);
      p.ellipse(p.random(-10, 10), p.random(-5, 5), 3, 3);
    }

    p.pop();
  };

  function updateSteam() {
    // Add new steam particles
    if(p.frameCount % 8 === 0) {
      steamParticles.push({
        x: kidney.x + p.random(-15, 15),
        y: kidney.y,
        vel: p.random(-0.5, 0.5),
        life: 255,
        size: p.random(3, 8)
      });
    }

    // Update existing particles
    for(let i = steamParticles.length - 1; i >= 0; i--) {
      let particle = steamParticles[i];
      particle.y -= 2;
      particle.x += particle.vel;
      particle.life -= 3;
      particle.size *= 1.01;

      if(particle.life <= 0) {
        steamParticles.splice(i, 1);
      }
    }
  };

  function drawSteam() {
    p.noStroke();
    for(let particle of steamParticles) {
      p.fill(255, 255, 255, particle.life);
      p.ellipse(particle.x, particle.y, particle.size, particle.size);
    }
  };

  function drawWarmLight() {
    // Warm ambient lighting
    p.push();
    p.blendMode(p.SOFT_LIGHT);
    p.fill(255, 220, 180, 30);
    p.noStroke();

    // Main warm light from window
    let lightPulse = p.sin(time * 0.5) * 10 + 100;
    p.ellipse(warmLight.x, warmLight.y, lightPulse, lightPulse * 0.7);

    // Reflected warmth on surfaces
    p.ellipse(200, 280, 150, 80);
    p.ellipse(bloom.x, bloom.y - 50, 120, 100);

    p.pop();
  };

  function drawCaringGesture() {
    // Subtle gesture of offering - perhaps a plate or gesture toward viewer
    let mouseInfluence = p.map(p.mouseX, 0, p.width, -0.2, 0.2);

    p.push();
    p.translate(bloom.x + 40, bloom.y + 30);
    p.rotate(mouseInfluence);

    // Gentle hand offering care
    p.fill(220, 190, 160);
    p.stroke(180, 150, 120);
    p.strokeWeight(1);
    p.ellipse(0, 0, 15, 20);

    // Fingers
    for(let i = 0; i < 4; i++) {
      let angle = p.map(i, 0, 3, -0.3, 0.3);
      p.push();
      p.rotate(angle);
      p.ellipse(0, -10, 3, 8);
      p.pop();
    }

    // Thumb
    p.push();
    p.rotate(0.7);
    p.ellipse(0, -8, 3, 6);
    p.pop();

    p.pop();

    // Caring energy - subtle golden particles around the gesture
    if(p.mouseX > bloom.x - 50 && p.mouseX < bloom.x + 100 && 
       p.mouseY > bloom.y - 100 && p.mouseY < bloom.y + 100) {
      for(let i = 0; i < 3; i++) {
        p.fill(255, 220, 100, p.random(50, 150));
        p.noStroke();
        let sparkleX = bloom.x + 40 + p.random(-20, 20);
        let sparkleY = bloom.y + 30 + p.random(-20, 20);
        p.ellipse(sparkleX, sparkleY, 2, 2);
      }
    }
  };
}

