function sketch(p) {
  let figure;
  let bedWaves = [];
  let breathOffset = 0;
  let skinParticles = [];

  p.setup = function() {
    p.createCanvas(400, 600);

    // Initialize bed waves
    for (let i = 0; i < 8; i++) {
      bedWaves.push({
        y: 400 + i * 15,
        amplitude: 8 - i * 0.8,
        frequency: 0.02 + i * 0.003,
        phase: i * 0.5
      });
    }

    // Initialize skin particles for subtle warmth effect
    for (let i = 0; i < 30; i++) {
      skinParticles.push({
        x: p.random(120, 280),
        y: p.random(200, 350),
        size: p.random(2, 6),
        alpha: p.random(20, 60),
        speed: p.random(0.1, 0.3)
      });
    }
  };

  p.draw = function() {
    // Deep warm background
    p.background(40, 25, 20);

    breathOffset += 0.02;
    let breathScale = 1 + p.sin(breathOffset) * 0.03;

    // Warm ambient light
    let mouseInfluence = p.map(p.mouseX, 0, 400, 0.8, 1.2);

    // Draw bed layers with flowing fabric
    p.noStroke();
    for (let wave of bedWaves) {
      p.fill(60 + wave.y * 0.1, 40 + wave.y * 0.08, 35 + wave.y * 0.06);
      p.beginShape();
      for (let x = 0; x <= 400; x += 10) {
        let y = wave.y + p.sin(x * wave.frequency + p.frameCount * 0.01 + wave.phase) * wave.amplitude;
        p.vertex(x, y);
      }
      p.vertex(400, 600);
      p.vertex(0, 600);
      p.endShape(p.CLOSE);
    }

    // Draw figure - Molly's substantial presence
    p.push();
    p.translate(200, 280);
    p.scale(breathScale * mouseInfluence);

    // Main body - warm flesh tones
    p.fill(205, 160, 130);
    p.stroke(180, 130, 100);
    p.strokeWeight(2);

    // Torso - substantial, unapologetic
    p.ellipse(0, 0, 140, 100);

    // Arms - relaxed, taking up space
    p.ellipse(-60, -10, 35, 80);
    p.ellipse(60, -10, 35, 80);

    // Head - serene authority
    p.fill(215, 170, 140);
    p.ellipse(0, -70, 60, 70);

    // Hair - dark, flowing
    p.fill(30, 20, 15);
    p.noStroke();
    for (let i = 0; i < 12; i++) {
      let angle = p.map(i, 0, 11, -p.PI/3, p.PI/3);
      let length = 40 + p.sin(p.frameCount * 0.02 + i) * 5;
      p.push();
      p.rotate(angle);
      p.ellipse(0, -90 - length/2, 8, length);
      p.pop();
    }

    // Subtle facial features
    p.fill(180, 120, 90);
    p.ellipse(-12, -75, 4, 6); // eyes
    p.ellipse(12, -75, 4, 6);
    p.ellipse(0, -65, 6, 3); // mouth

    p.pop();

    // Skin warmth particles
    for (let particle of skinParticles) {
      particle.y -= particle.speed;
      particle.alpha += p.sin(p.frameCount * 0.05 + particle.x * 0.1) * 2;

      if (particle.y < 180) {
        particle.y = 350;
        particle.x = p.random(120, 280);
      }

      p.fill(255, 200, 150, p.constrain(particle.alpha, 10, 50));
      p.noStroke();
      p.ellipse(particle.x, particle.y, particle.size);
    }

    // Kidney symbols - subtle, integrated
    p.push();
    p.translate(150, 250);
    p.rotate(p.frameCount * 0.01);
    p.fill(140, 60, 50, 80);
    p.noStroke();

    // Kidney shape
    p.beginShape();
    for (let a = 0; a < p.TWO_PI; a += 0.1) {
      let r = 15 + p.sin(a * 3) * 3;
      let x = r * p.cos(a);
      let y = r * p.sin(a) * 1.3;
      p.vertex(x, y);
    }
    p.endShape(p.CLOSE);
    p.pop();

    p.push();
    p.translate(250, 270);
    p.rotate(-p.frameCount * 0.008);
    p.fill(140, 60, 50, 60);
    p.noStroke();

    p.beginShape();
    for (let a = 0; a < p.TWO_PI; a += 0.1) {
      let r = 12 + p.sin(a * 3) * 2;
      let x = r * p.cos(a);
      let y = r * p.sin(a) * 1.3;
      p.vertex(x, y);
    }
    p.endShape(p.CLOSE);
    p.pop();

    // Warm glow around figure
    for (let r = 100; r > 0; r -= 10) {
      p.fill(255, 180, 120, 3);
      p.noStroke();
      p.ellipse(200, 280, r * 2, r * 1.5);
    }

    // Interactive warmth from mouse proximity
    let dist = p.dist(p.mouseX, p.mouseY, 200, 280);
    if (dist < 100) {
      let warmth = p.map(dist, 0, 100, 100, 0);
      p.fill(255, 200, 150, warmth);
      p.noStroke();
      p.ellipse(200, 280, 200, 150);
    }
  };
}

