function sketch(p) {
  let kidneyShapes = [];
  let yesParticles = [];
  let time = 0;
  let figure = {};
  let warmColors = [];

  p.setup = function() {
    p.createCanvas(400, 600);

    warmColors = [
      p.color(255, 215, 120), // butter yellow
      p.color(245, 190, 160), // warm peach
      p.color(255, 180, 150), // soft pink
      p.color(210, 140, 110), // warm brown
      p.color(255, 200, 140)  // cream
    ];

    // Initialize kidney shapes that form YES
    for (let i = 0; i < 50; i++) {
      kidneyShapes.push({
        x: p.random(50, 350),
        y: p.random(150, 350),
        size: p.random(8, 25),
        rotation: p.random(p.TWO_PI),
        rotSpeed: p.random(-0.02, 0.02),
        pulse: p.random(p.TWO_PI),
        color: p.random(warmColors),
        targetX: 0,
        targetY: 0
      });
    }

    // Initialize affirmation particles
    for (let i = 0; i < 30; i++) {
      yesParticles.push({
        x: p.random(p.width),
        y: p.random(p.height),
        vx: p.random(-0.5, 0.5),
        vy: p.random(-1, -0.2),
        life: p.random(255),
        size: p.random(3, 8),
        color: p.random(warmColors)
      });
    }

    // Initialize figure
    figure = {
      x: 200,
      y: 450,
      breathe: 0,
      armPulse: 0
    };
  };

  p.draw = function() {
    time += 0.02;

    // Warm gradient background
    for (let y = 0; y < p.height; y++) {
      let inter = p.map(y, 0, p.height, 0, 1);
      let c = p.lerpColor(p.color(255, 230, 180, 100), p.color(245, 190, 160, 200), inter);
      p.stroke(c);
      p.line(0, y, p.width, y);
    }

    // Update and draw YES formed by kidney shapes
    drawYESFromKidneys();

    // Draw floating affirmation particles
    drawAffirmationParticles();

    // Draw embodied figure
    drawEmbodiedFigure();

    // Add warm glow overlay
    p.push();
    p.blendMode(p.OVERLAY);
    p.fill(255, 215, 120, 30);
    p.ellipse(200, 250, 300 + p.sin(time) * 20, 400 + p.cos(time * 0.7) * 15);
    p.pop();
  };

  function drawYESFromKidneys() {
    // Define YES letter positions
    let yPos = [
      // Y
      {x: 80, y: 180}, {x: 90, y: 200}, {x: 100, y: 220}, {x: 110, y: 240},
      {x: 120, y: 180}, {x: 110, y: 200}, {x: 100, y: 220}, {x: 100, y: 260},
      // E
      {x: 160, y: 180}, {x: 160, y: 200}, {x: 160, y: 220}, {x: 160, y: 240}, {x: 160, y: 260},
      {x: 180, y: 180}, {x: 200, y: 180}, {x: 180, y: 220}, {x: 190, y: 220}, {x: 180, y: 260}, {x: 200, y: 260},
      // S
      {x: 240, y: 180}, {x: 260, y: 180}, {x: 240, y: 200}, {x: 250, y: 220}, {x: 260, y: 240}, {x: 240, y: 260}, {x: 260, y: 260}
    ];

    // Move kidney shapes toward YES positions
    for (let i = 0; i < kidneyShapes.length && i < yPos.length; i++) {
      let target = yPos[i];
      kidneyShapes[i].targetX = target.x + p.sin(time + i) * 5;
      kidneyShapes[i].targetY = target.y + p.cos(time + i * 0.5) * 3;

      kidneyShapes[i].x = p.lerp(kidneyShapes[i].x, kidneyShapes[i].targetX, 0.03);
      kidneyShapes[i].y = p.lerp(kidneyShapes[i].y, kidneyShapes[i].targetY, 0.03);
    }

    // Draw kidney shapes
    for (let kidney of kidneyShapes) {
      p.push();
      p.translate(kidney.x, kidney.y);
      p.rotate(kidney.rotation);
      kidney.rotation += kidney.rotSpeed;

      let pulseSize = kidney.size * (1 + p.sin(time + kidney.pulse) * 0.2);

      p.fill(kidney.color);
      p.noStroke();

      // Draw kidney bean shape
      p.beginShape();
      for (let a = 0; a < p.TWO_PI; a += 0.1) {
        let r = pulseSize * (0.8 + 0.2 * p.sin(a * 2));
        if (a > p.PI * 0.3 && a < p.PI * 0.7) r *= 0.7; // indent for kidney shape
        let x = r * p.cos(a);
        let y = r * p.sin(a);
        p.vertex(x, y);
      }
      p.endShape(p.CLOSE);

      // Add warm glow
      p.fill(255, 255, 200, 50);
      p.ellipse(0, 0, pulseSize * 1.5);

      p.pop();
    }
  }

  function drawAffirmationParticles() {
    for (let particle of yesParticles) {
      particle.x += particle.vx;
      particle.y += particle.vy;
      particle.life -= 1;

      if (particle.life <= 0 || particle.y < 0) {
        particle.x = p.random(p.width);
        particle.y = p.height + 10;
        particle.life = 255;
        particle.vx = p.random(-0.5, 0.5);
        particle.vy = p.random(-1, -0.2);
      }

      p.push();
      let alpha = p.map(particle.life, 0, 255, 0, 150);
      particle.color.setAlpha(alpha);
      p.fill(particle.color);
      p.noStroke();

      let size = particle.size * (1 + p.sin(time * 2 + particle.x * 0.01) * 0.3);
      p.ellipse(particle.x, particle.y, size);
      p.pop();
    }
  }

  function drawEmbodiedFigure() {
    figure.breathe += 0.05;
    figure.armPulse += 0.03;

    p.push();
    p.translate(figure.x, figure.y);

    let breatheScale = 1 + p.sin(figure.breathe) * 0.05;
    p.scale(breatheScale);

    // Body (organic, kidney-like shape)
    p.fill(245, 190, 160, 200);
    p.noStroke();
    p.ellipse(0, 0, 60, 100);

    // Head
    p.fill(255, 180, 150, 220);
    p.ellipse(0, -60, 45, 50);

    // Arms in affirmation gesture
    let armAngle = p.sin(figure.armPulse) * 0.2;
    p.stroke(245, 190, 160);
    p.strokeWeight(8);
    p.line(-15, -20, -30 + p.cos(armAngle) * 10, -40 + p.sin(armAngle) * 5);
    p.line(15, -20, 30 - p.cos(armAngle) * 10, -40 + p.sin(armAngle) * 5);

    // Warm aura
    p.noFill();
    p.stroke(255, 215, 120, 50);
    p.strokeWeight(2);
    let auraSize = 150 + p.sin(time) * 20;
    p.ellipse(0, -10, auraSize, auraSize * 1.2);

    p.pop();

    // Interactive response to mouse
    let mouseInfluence = p.dist(p.mouseX, p.mouseY, figure.x, figure.y);
    if (mouseInfluence < 100) {
      p.push();
      p.fill(255, 215, 120, 100 - mouseInfluence);
      p.noStroke();
      p.ellipse(figure.x, figure.y, 200 - mouseInfluence, 200 - mouseInfluence);
      p.pop();
    }
  }
}
